insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Skye  Bemiddeling via eigenaar', 'Bemiddeling via eigenaresse.
Deze knapperd heet Skye. Zijn eigenaresse moet, vanwege omstandigheden, met pijn in het hart de keuze maken een nieuw thuis voor hem te vinden. Hij verblijft thuis totdat een goede match gevonden is.
Skye is een fitte Duitse herder reu van 7 jaar. Hij is gezond, ingeënt en vertoont geen tekenen van HD.
In huis is hij relatief rustig, maar is wel graag overal bij. Hij komt ook om aandacht en knuffels vragen. En hij is heel nieuwsgierig en enigszins waaks. Skye blijft, als hij eenmaal vertrouwd en opgebouwd is, prima een halve dag alleen en gaat dan gewoon slapen (niet op de bank). Al heeft zo weinig mogelijk alleen zijn natuurlijk de voorkeur.Apporteren doet hij niet, dat principe begrijpt hij niet. Hij gaat liever zijn neus achterna! Hij loopt, speelt en ligt ook graag in de tuin. Het is dan ook geen hond voor op een appartement. 
Hij kent veel commando''/woorden en luistert vrij goed. Een daarvan is ''op de plaats''. Waarna hij in de bench gaat (zijn bench kan mee). Want deze is hij gewend en hij ligt er ook graag in met de deur open. Aangezien hij in sommige situaties stress ervaart, kan dat zijn rustplek zijn op momenten (niet met alleen zijn, dan zit hij in woonkamer). Soms wel met bezoek. Hij kan dan onrustig zijn. Een aparte ruimte (keuken, bijkeuken) zou nog beter werken. Een bot biedt overigens ook al afleiding. 
Hij vertoont geen agressie. Wordt hij met rust gelaten, dan is het meestal snel over. Hij zou het best op zijn plek zijn in een rustig huishouden, grotere kinderen vanaf een jaar of 12 zijn geen probleem. Maar zonder al te veel drukte en zonder andere huisdieren. 
Want dat is een volgend aandachtspunt. Skye loopt buiten goed aan een lange lijn, om lekker te kunnen snuffelen. En is gewend om, naast zijn riem, een halti erbij te dragen. Want andere honden die hij moet passeren zijn spannend. Dan kan hij fixeren, soms blaffen of proberen uit te vallen. Met wat afleiding (koekjes werken o.a.), geruststellende begrenzing, en door de halti, levert het echter zelden problemen op. Gewoon kort nemen en een boogje eromheen maken. Honden die niet te dichtbij komen, zelfs als ze naar hem blaffen, zijn geen probleem. Sommige kalme teefjes vindt hij wel leuk, en er kan aan de riem samen gewandeld worden, maar hij is te gestresst om er vrij mee te kunnen spelen. Met de juiste kennis en begeleiding is hier vast nog winst te behalen. 
Verkeer, joggers, kinderen, vuurwerk, onweer, autorijden (dat vindt hij heerlijk)... zijn voor Skye totaal geen probleem. Vooral mee in de auto is iets wat hij heel graag doet en kan dan ook langere tijd rustig blijven liggen.
Skye is te gevoelig voor een harde aanpak, maar heeft iemand nodig die hem kalm en liefdevol begrenst. Ervaring met grotere honden/herders heeft de voorkeur. Dan krijg je een prachtige herder die jou wil vertrouwen en graag bij je is!
Bij interesse graag een mail sturen naar limburg@dierenbescherming.nl en wij zullen de mail dan doorsturen naar de eigenaresse van Skye. De dierenbescherming heeft geen verdere bemoeienis met de herplaatsing en mogelijke vervolg stappen.
Kennismaking mogelijk na uitwisselen informatie en het vermoeden van een mogelijk goede match.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Skye_2026-05-08-082459_tpqg.jpg?stamp=2605081024&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Skye_2026-05-08-082459_tpqg.jpg?stamp=2605081024&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Skye_2026-05-08-082459_tpqg.jpg?stamp=2605081024&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Skye_2026-05-08-082459_tpqg.jpg?stamp=2605081024&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/skye-1.jpg?stamp=2605081025&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/skye2_2026-05-08-082532_pzmw.jpg?stamp=2605081025&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Skye3_2026-05-08-082545_jvlp.jpg?stamp=2605081025&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Skye4.jpg?stamp=2605081025&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Skye_2026-05-08-082459_tpqg.jpg?stamp=2605081024&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Skye_2026-05-08-082459_tpqg.jpg?stamp=2605081024&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Skye_2026-05-08-082459_tpqg.jpg?stamp=2605081024&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/skye-1.jpg?stamp=2605081025&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/skye2_2026-05-08-082532_pzmw.jpg?stamp=2605081025&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Skye3_2026-05-08-082545_jvlp.jpg?stamp=2605081025&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Skye4.jpg?stamp=2605081025&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4604040-skye-bemiddeling-via-eigenaar'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4604040-skye-bemiddeling-via-eigenaar')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Koekie', 'Koekie zoekt haar veilige thuis...

Soms komt er een hond binnen waarvan je hart een beetje breekt. Koekie, onze Anatolische herder dame van pas 8 maanden jong, is daar één van.Koekie werd gedumpt en nooit meer opgehaald. Alsof niemand meer naar haar omkeek. Maar al snel zagen we dar er achter die lieve oogjes een verhaal zat dat niet eerlijk was voor zo''n jonge hond. Een pup hoort onbevangen en vrolijk te zijn... Koekie kende vooral angst.Ze schrok van voerbakken, van drinkbakken en eigenlijk van alles wat nieuw voor haar was. Alsof ze had geleerd dat de wereld geen fijne plek is. Toch.. ondanks alles wat ze heeft meegemaakt, zit er geen greintje kwaad in dit meisje. Met geduld, rust en heel veel liefde zien we haar iedere dag een beetje meer opbloeien. Inmiddels huppelt ze vrolijk over de speelweide en zoekt ze voorzichtig contact. Kleine stapjes voor ons misschien, maar gigantische stappen voor Koekie. ❤️Ook lichamelijk heeft Koekie het zwaar gehad. Ze is inmiddels geholpen aan haar entropion oogjes. Door deze aandoening had ze zo veel pijn dat ze haar ogen nauwelijks open kon houden. Volgende week mogen gelukkig haar hechtingen eruit en kan ze eindelijk zonder die constante pijn verder leven.Koekie is lief voor mensen en andere honden. Ze zoekt een warm thuis met grote tuin. Een plek waar ze de tijd krijgt om te ontdekken dat het leven ook zacht kan zijn. Iemand die haar met liefde wil begeleiden, har vertrouwen wil winnen en haar wil laten voelen dat mensen het soms echt goed bedoelen.Voor Koekie zoeken we geen snelle beslissing, maar een gouden mandje vol geduld, begrip en liefde. Want dit meisje verdiend eindelijk het leven dat ze nooit heeft gehad. Wil jij op pad met Koekie? Stuur een mail na limburg@dierenbescherming.nl en kom kennismaken met onze lieve dame', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Koekie-3.jpg?stamp=2605081313&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Koekie-3.jpg?stamp=2605081313&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Koekie-3.jpg?stamp=2605081313&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-3.jpg?stamp=2605081313&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-5.jpg?stamp=2605081314&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-1.jpg?stamp=2605081313&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-4.jpg?stamp=2605081314&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-6.jpg?stamp=2605081314&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-2.jpg?stamp=2605081313&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-7.jpg?stamp=2605081314&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Koekie-3.jpg?stamp=2605081313&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Koekie-3.jpg?stamp=2605081313&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-3.jpg?stamp=2605081313&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-5.jpg?stamp=2605081314&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Koekie-1.jpg?stamp=2605081313&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4604295-koekie'
from public.shelters s
