insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Denzel', 'Joehoe zie je mij? Dat was een serieuze vraag want ik zie het niet altijd even goed..Maar misschien zie ik het wel zitten met jou, ik ben Denzel een kruising Windhond reu van 5 jaar oud en 22kg. Ik ben weggehaald met meerdere honden omdat wij niet goed werden verzorgd.Ik ben een vrolijke, enthousiaste, zachtaardige, vriendelijke en lieve heer en gek op aandacht. Het liefste kruip ik helemaal in je of tegen je aan en geef ik je een omhelzing! Ik heb het helaas niet zo goed gehad en ik zoek nu een baas waar ik wel alles krijg wat ik zo verdien! Kinderen ben ik niet gewend, maar reageer wel vriendelijk naar ze, zijn de kinderen aan honden gewend, dan wil ik ze best ontmoeten.Ik vind andere honden een beetje spannend, dit komt natuurlijk ook omdat ik het niet zo goed kan inschatten. Ik zoek dan ook een huis zonder dieren. Ik loop netjes mee aan de riem, soms wel iets dichter tegen je been aan als steun. Mijn ogen zijn beschadigd en hierdoor zie ik niet meer alles goed, ik zie nog wel voldoende hoor maar soms moet ik even wat beter focussen. Loslopen kan ik dus helaas niet, er bestaat een kans dat mijn zicht in de toekomst nog meer achteruit gaat. Mijn nieuwe baas moet hier dus wel rekening mee houden.Het alleen thuis blijven zal rustig opgebouwd en aangeleerd moeten worden. Ik ben namelijk gered uit een kennelsituatie, een huis heb ik dus nog nooit gezien. Mijn nieuwe baas zal veel tijd moeten hebben zodat ik eerst kan wennen en mij veilig voel. Samen heerlijk wandelen, nieuwe dingen leren en de wereld ontdekken. Dat klinkt toch als een droom die hopelijk snel uitkomt?!Heb jij een plekje vrij in je huis en hart?', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/IMG_0688.jpeg?stamp=2605051635&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0688.jpeg?stamp=2605051635&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0688.jpeg?stamp=2605051635&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0688.jpeg?stamp=2605051635&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0706.jpeg?stamp=2605051635&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0342.jpeg?stamp=2604221702&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0688.jpeg?stamp=2605051635&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0688.jpeg?stamp=2605051635&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0688.jpeg?stamp=2605051635&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0706.jpeg?stamp=2605051635&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0342.jpeg?stamp=2604221702&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4581902-denzel'
