insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Molly', 'Hoi, ik ben Molly, een middelgrote kruising van bijna 6 jaar. Wegens omstandigheden kon ik niet meer bij mijn vorige baas blijven.Naar mensen toe ben ik vriendelijk, als ik je goed ken ben ik erg enthousiast en blij om je te zien! Ben je onbekend heb ik soms even de tijd nodig. Kinderen ben ik niet gewend en, als ik eerlijk ben, vind ik ze ook spannend. Ik wil graag afstand houden van ze en kan ze dan prima negeren. Mijn huis delen met kinderen zie ik dus niet zo zitten.Op andere honden reageer ik wisselend. Ik heb wat negatieve ervaringen gehad en raak daardoor snel gespannen. Soms vind ik andere honden wel leuk hoor, maar dan heb ik ze al wat vaker gezien en zijn ze niet zo druk. Het liefst negeer ik ze buiten, en mijn nieuwe baas moet het niet erg vinden om mij aangelijnd uit te laten. Aan de riem loop ik netjes mee, ik luister goed naar mijn baas en wil graag iets voor je doen. Geef mij een opdracht en ik doe het, en dit doe ik met volle overtuiging!Ik zoek mensen die voldoende tijd voor mij hebben en die, net als ik, van een actief leven houden. Ik ben netjes zindelijk en ken veel commando’s. Alleen thuis zijn vond ik in mijn vorige huis erg spannend. Daarom is dit een belangrijk aandachtspunt voor mijn nieuwe baasjes. Ik zoek een rustige woonomgeving, met mensen die in het begin veel thuis zijn zodat ik rustig kan wennen. Dit moet geleidelijk worden opgebouwd. Ik ben namelijk een gevoelig typje en heb duidelijkheid, rust, regelmaat en structuur nodig.Verder ben ik gek op aandacht, zachtaardig, sportief en – al zeg ik het zelf – een leuk maatje.Heb jij een thuis voor mij?', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/1e984965-b6d4-476d-ba59-c6189fcecb87.jpeg?stamp=2604291508&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/1e984965-b6d4-476d-ba59-c6189fcecb87.jpeg?stamp=2604291508&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/1e984965-b6d4-476d-ba59-c6189fcecb87.jpeg?stamp=2604291508&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/1e984965-b6d4-476d-ba59-c6189fcecb87.jpeg?stamp=2604291508&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/d1fdb92b-38f5-435a-810b-be9884e9212a.jpeg?stamp=2604281329&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/b4670d5e-4990-48a0-8e0f-58055a00c465.jpeg?stamp=2604291508&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/d67dffca-506a-47cc-83f9-556c6a23df0d.jpeg?stamp=2604291508&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/1e984965-b6d4-476d-ba59-c6189fcecb87.jpeg?stamp=2604291508&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/1e984965-b6d4-476d-ba59-c6189fcecb87.jpeg?stamp=2604291508&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/1e984965-b6d4-476d-ba59-c6189fcecb87.jpeg?stamp=2604291508&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/d1fdb92b-38f5-435a-810b-be9884e9212a.jpeg?stamp=2604281329&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/b4670d5e-4990-48a0-8e0f-58055a00c465.jpeg?stamp=2604291508&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/d67dffca-506a-47cc-83f9-556c6a23df0d.jpeg?stamp=2604291508&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4593978-molly'
from public.shelters s
where s.name = 'Dierentehuis Kennemerland'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4593978-molly')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zwolle', 'Nova', 'Nova is een gesteriliseerde teef, geboren op 30 augustus 2024, en een echte Duitse herder in hart en nieren.Wegens omstandigheden is zij naar ons overgebracht en mogen wij nu op zoek naar een passende, ervaren baas die haar de juiste begeleiding kan bieden.In het begin is Nova waaks en laat ze dit merken door te blaffen, dus ongezien het erf of de tuin inkomen gaat niet met Nova. Heel fijn wanneer je iets vrijer woont.Maar zodra ze je leert kennen, verandert ze in een vriendelijke en baasgerichte hond. Ze bouwt graag een band op met haar eigenaar en geniet zichtbaar van aandacht en contact. Nova is actief, speels en leergierig, en vindt het heerlijk om samen bezig te zijn. Ook een knuffelmoment op z’n tijd slaat ze zeker niet af 😉.

Nova is een hond voor een baas die herder-ervaring heeft. Ze is niet sociaal naar andere honden en ook niet geschikt om samen te wonen met katten. Voor haar zoeken we daarom een plek waar zij de enige hond in huis is. Ze kan geplaatst worden bij kinderen vanaf 16 jaar, mits zij stevig in hun schoenen staan en weten hoe zij met een herder moeten omgaan.
Aan de riem vraagt Nova nog de nodige begeleiding. Ze kan uitvallen naar fietsers, reageren op hardlopers en op andere honden. Dit gedrag vraagt training, geduld en een consequente aanpak. Ook heeft ze de neiging om af en toe in een jas of mouw te happen, iets waar ook actief mee geoefend moet worden. Nova weet precies bij wie ze dit wel en bij wie ze dit niet kan doen. Dus consequentheid, regels en een (positieve) training zijn erg van belang.
Alleen thuis blijven lijkt over het algemeen goed te gaan, in de kennel is zij rustig en over het algemeen laat ze haar spulletjes heel. Een enkele uitzondering daargelaten.
De Duitse herder staat bekend als een intelligente, werklustige en loyale hond die graag samenwerkt met zijn baas. Het is een ras dat veel beweging en mentale uitdaging nodig heeft om in balans te blijven. Duitse herders zijn vaak waaks en beschermend, wat hen uitstekende gezinshonden maakt in de juiste handen. Ze leren snel en vinden het leuk om te trainen, maar hebben wel een consequente en duidelijke opvoeding nodig. Door hun energieke karakter passen ze het beste bij een actieve eigenaar die graag met hen aan de slag gaat. Voldoende structuur en duidelijke regels zijn belangrijk.
Een Duitse herder is een hond die zich sterk hecht aan zijn eigenaar en graag onderdeel is van het gezin. Ze hebben zowel fysieke als mentale stimulatie nodig om gelukkig te zijn. Mits goed begeleid, zijn het trouwe en veelzijdige honden die veel voor hun baas willen doen.Voor Nova zoeken wij dan ook een actieve, ervaren eigenaar die haar de juiste begeleiding, structuur en uitdaging kan bieden.Ben jij bereid om met haar te trainen en samen te werken aan een stabiele toekomst?-> Er zijn foto’s gemaakt van Nova’s heupen en gehele rug. Uit onderzoek is gebleken dat er op dit moment geen sprake is van artrose. Wel zijn de heupen iets ondiep, wat past bij een lichte vorm van HD. Op dit moment is hiervoor geen behandeling nodig. Het advies is om wel goed op de beweging te letten: liever rechtlijnig bewegen en draaien beperken, en bijvoorbeeld niet te veel met ballen of stokken gooien.

Kennismakingen: wij vragen geïnteresseerden altijd om 3x te komen kennismaken', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_330x285_crop_center-center_none/7512-nova-50.jpg?stamp=2605041540&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/7512-nova-50.jpg?stamp=2605041540&tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/7512-nova-50.jpg?stamp=2605041540&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7512-nova-50.jpg?stamp=2605041540&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7512-nova-60.jpg?stamp=2605041540&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7512-nova-62.jpg?stamp=2605041540&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7512-nova-49.jpg?stamp=2605041540&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/7512-nova-50.jpg?stamp=2605041540&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/7512-nova-50.jpg?stamp=2605041540&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7512-nova-50.jpg?stamp=2605041540&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7512-nova-60.jpg?stamp=2605041540&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7512-nova-62.jpg?stamp=2605041540&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7512-nova-49.jpg?stamp=2605041540&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4600504-nova'
