insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zwolle', 'Jade', 'Jade is een gesteriliseerde Rhodesian Ridgebackteef, geboren op 1 december 2017.
Door omstandigheden is Jade in de opvang terechtgekomen, haar exacte verleden is onbekend. Maar duidelijk is wel dat zij een zacht en gevoelig karakter heeft. In het begin kan zij angstig reageren op nieuwe mensen en situaties, maar wanneer je haar de tijd en rust geeft, zie je dat zij langzaam ontdooit en graag contact met je zoekt. Kent Jade je, dan is zij een actieve en speelse hond die ook enorm kan genieten van knuffelmomenten, al kan zij daarbij soms wat onbenullig overkomen.
Jade vindt het dagelijks leven nog spannend en heeft begeleiding nodig bij basisvaardigheden zoals zindelijkheid, alleen thuis blijven en het lopen aan de riem. Aan de lijn kan zij angstig en onrustig zijn, al trekt zij niet constant, en met geduld en training zal hier zeker vooruitgang in te boeken zijn. Wij wandelen met haar met een veiligheidstuig.
In de kennel is zij over het algemeen rustig. Met andere honden is haar gedrag wisselend; zij is sociaal met Ridgebackreu Basalt, een stabiele, rustige hond zou haar mogelijk kunnen helpen, terwijl een plek als enige hond ook goed bij haar zou kunnen passen.Over omgang met katten is niets bekend.
Gezien haar onzekerheid plaatsen wij Jade bij voorkeur in een huishouden zonder jonge kinderen; wij denken dat zij het beste tot haar recht komt bij kinderen vanaf ongeveer 15 jaar of ouder. Medisch gezien heeft Jade lichte spondylose in de laatste rugwervels, waar momenteel rekening mee gehouden moet worden, maar zij heeft geen dieetvoeding nodig en haar gebit is recent nog volledig gereinigd. Eerder had zij wat last van seizoensgebonden kaalheid, maar dit is momenteel niet meer zichtbaar.
De Rhodesian Ridgeback staat bekend als een zelfstandige, intelligente en waakzame hond met een sterk karakter en een groot uithoudingsvermogen. Het ras is van nature loyaal aan zijn eigenaar, maar kan gereserveerd zijn naar vreemden en heeft daarom een consequente, rustige begeleiding nodig. Ridgebacks zijn energiek en hebben voldoende beweging en mentale uitdaging nodig om in balans te blijven. Daarnaast zijn zij gevoelig voor de sfeer in huis en reageren zij het beste op een stabiele, duidelijke en geduldige opvoeding. Door hun zelfstandigheid kunnen zij soms eigenwijs zijn, waardoor ervaring met honden of bereidheid om begeleiding te zoeken belangrijk is.
Voor Jade zoeken wij een rustige, stabiele omgeving met een eigenaar die haar de tijd geeft om te groeien en haar stap voor stap begeleidt in het leven dat voor veel honden vanzelfsprekend is. In de juiste handen zal zij zich ontwikkelen tot een trouwe en aanhankelijke metgezel die intens geniet van de aandacht en nabijheid. Denk jij dat jij Jade die kans kunt bieden?Kennismakingen; wij vragen geïnteresseerden altijd om 3x te komen kennismaken en wandelen.
rhodesian ridgeback', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_330x285_crop_center-center_none/Jade-55.png?stamp=2605011209&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/Jade-55.png?stamp=2605011209&tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/Jade-55.png?stamp=2605011209&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/Jade-55.png?stamp=2605011209&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/Jade-2.png?stamp=2605011211&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/Jade-55.png?stamp=2605011209&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/Jade-55.png?stamp=2605011209&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/Jade-55.png?stamp=2605011209&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/Jade-2.png?stamp=2605011211&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4597881-jade'
from public.shelters s
where s.name = 'Zwols Dierenasiel'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4597881-jade')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Lilly', 'Pup alarm! Lilly zoekt haar forever home!Dit kleine, zachte wolkje heet Lilly en is een Maltezer pup van 14 weken jong. Momenteel verblijft ze in een gastgezin, nadat ze helaas moest vertrekken bij haar vorige thuis vanwege allergieën. Een verdrietige start, maar Lilly laat zien dat ze klaar is voor en nieuw hoofdstuk.Lilly is een lief en zachtaardig meisje dat eerst even de kat uit de boom kijkt. Geef haar een beetje geduld, en je ziet haar langzaam ontdooien en naar je toe groeien. In haar gastgezin geniet ze zichtbaar van de aanwezigheid van andere honden. Een vrolijk maatje van ongeveer haar formaat en energielevel zou ze dan ook fantastisch vinden!Zoal het een pup betaamt, moet Lilly nog veel leren. Wandelen aan de riem is nog nieuw voor haar en hoewel ze al netjes aangeeft wanneer ze naar buiten moet, kunnen er natuurlijk nog wel eens ongelukjes gebeuren. Een huis met een tuin zou daarom echt een grote pre zijn, zodat ze makkelijk en snel haar plasje buiten kan doen en verder kan oefenen met zindelijk worden. Het opvoeden van zo''n klein hummeltje vraagt tijd, liefde en geduld - maar je krijgt er een ontzettend lief vriendinnetje voor terug.Ben jij degene die Lilly de rust, begeleiding en liefde kan geven om verder op te groeien tot een zelfverzekerde en gelukkige hond? Stuur dan een mail na limburg@dierenbescherming.nl', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Lilly-1.jpg?stamp=2605021119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Lilly-1.jpg?stamp=2605021119&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Lilly-1.jpg?stamp=2605021119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-1.jpg?stamp=2605021119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-8.jpg?stamp=2605021120&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-2.jpg?stamp=2605021119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-3.jpg?stamp=2605021119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-5.jpg?stamp=2605021119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-6.jpg?stamp=2605021120&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-7.jpg?stamp=2605021120&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Lilly-1.jpg?stamp=2605021119&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Lilly-1.jpg?stamp=2605021119&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-1.jpg?stamp=2605021119&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-8.jpg?stamp=2605021120&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Lilly-2.jpg?stamp=2605021119&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4598730-lilly'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
