insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Kelsey', 'Kennis maken met dit dier? Het asiel werkt op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens via het vragenformulier (zie onder) doorgeven aan ons.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1193319-Kelsey-4.jpeg?stamp=2604291356&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1193319-Kelsey-4.jpeg?stamp=2604291356&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1193319-Kelsey-4.jpeg?stamp=2604291356&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193319-Kelsey-4.jpeg?stamp=2604291356&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193318-Kelsey-3.jpeg?stamp=2604291356&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193319-Kelsey-2.jpeg?stamp=2604291356&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193319-Kelsey.jpeg?stamp=2604291356&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1193319-Kelsey-4.jpeg?stamp=2604291356&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1193319-Kelsey-4.jpeg?stamp=2604291356&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193319-Kelsey-4.jpeg?stamp=2604291356&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193318-Kelsey-3.jpeg?stamp=2604291356&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193319-Kelsey-2.jpeg?stamp=2604291356&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193319-Kelsey.jpeg?stamp=2604291356&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4596482-kelsey'
