insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Enschede', 'Souf', 'Maak kennis met Souf! 🐾
Deze vrolijke, energieke jonge hond is op zoek naar zijn nieuwe avontuur (en natuurlijk een fijn thuis). Souf zit nog volop in de leerfase en ontdekt de wereld elke dag een beetje meer. Daarom zoekt hij een baasje dat duidelijk en consequent is, maar ook vooral geduldig en gezellig met hem aan de slag wil.
Souf barst van de energie en houdt van actie! Lange wandelingen, spelen en samen bezig zijn? Daar zegt hij geen nee tegen. 
Voor hem zoeken we dus een actief baasje dat hem niet alleen liefde geeft, maar ook uitdaging en structuur.
Ben jij klaar voor een maatje dat je leven een stuk levendiger maakt? Dan is Souf misschien wel jouw perfecte match! 
---------------------------------------------------------------------------------------------------
Klik hier voor het interessefomulier!
Heeft u interesse vul dan het onderstaande interesseformulier in. Vanwege de vele reacties benaderen we alleen diegene die uitgenodigd wordt voor een kennismaking. Indien u binnen 3 dagen niets van ons hebt vernomen, dan is de keuze gevallen op een andere geïnteresseerde. Is de keuze op u gevallen, dan bellen wij u met een 088 nummer. Houdt uw telefoon in de gaten!
Let op, het kan voorkomen dat wij meerdere interesse mails krijgen voor hetzelfde dier. Het dier is pas voor u gereserveerd op het moment dat er een kennismakingsafspraak is ingepland. Wij kunnen onze dieren maximaal 3 dagen voor u reserveren, we vinden het namelijk erg belangrijk dat een dier niet langer dan noodzakelijk in onze opvang verblijft. Graag uw begrip hiervoor.
Het is goed om te weten dat wij altijd werken met minimaal twee kennismakingen. De hond gaat niet bij de eerste kennismaking mee. Wij adviseren u om u goed in te lezen op de website van de LICG over het ras waarop u reageert.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_330x285_crop_center-center_none/e89c47e6-36c1-4143-bf6c-d017d49ab0b6.jpg?stamp=2605041129&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_384x330_crop_center-center_none/e89c47e6-36c1-4143-bf6c-d017d49ab0b6.jpg?stamp=2605041129&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_519x453_crop_center-center_none/e89c47e6-36c1-4143-bf6c-d017d49ab0b6.jpg?stamp=2605041129&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/e89c47e6-36c1-4143-bf6c-d017d49ab0b6.jpg?stamp=2605041129&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/Souf.jpg?stamp=2604291136&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_384x330_crop_center-center_none/e89c47e6-36c1-4143-bf6c-d017d49ab0b6.jpg?stamp=2605041129&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_519x453_crop_center-center_none/e89c47e6-36c1-4143-bf6c-d017d49ab0b6.jpg?stamp=2605041129&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/e89c47e6-36c1-4143-bf6c-d017d49ab0b6.jpg?stamp=2605041129&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/Souf.jpg?stamp=2604291136&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301218&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4596164-souf'
from public.shelters s
where s.name = 'Dierenopvangcentrum Enschede'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4596164-souf')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Enschede', 'Kees', 'Kees is geen gewone hond. Nee, Kees is een wervelwind van energie, op vier poten die elke kamer binnenkomt alsof het een feestje is. En eerlijk gezegd maakt hij er ook eentje van. Vanaf het moment dat je hem ontmoet, is het alsof hij je al jaren kent. 
Kees hecht zich snel aan mensen, alsof hij precies weet wie hem leuk vindt en dat geeft hij dubbel en dwars terug. Buiten wandelen is één van zijn favoriete bezigheden. Keurig loopt hij mee aan de riem. soms valt hij soms uit naar fietsers maar een duidelijke nee is vaak voldoende en dan loopt hij keurig mee. 
Volgens zijn vorige eigenaar kan Kees goed overweg met andere honden. Misschien een speelse snuffel hier, een vrolijke begroeting daar hij staat open voor vriendschap, net als bij mensen. Thuis houdt Kees ook alles goed in de gaten. Gaat de bel? Dan laat hij zich horen. Niet omdat hij boos is, maar omdat hij wil laten weten: ik ben er, ik pas op dit huis en op mijn mensen.
Zijn zindelijkheid heeft nog wat aandacht nodig, maar we verwachten dat dit met de juiste begeleiding en tijd. Met een duidelijke routine en positieve begeleiding gaat hij hier zeker stappen in maken hij wil het namelijk heel graag goed doen. Kees is een hond met een groot hart, vol enthousiasme en liefde. Hij zoekt iemand die dat ziet, die met hem wil lachen, wandelen. Want één ding is zeker: met Kees in huis is het nooit saai alleen maar een stukje vrolijker. 
klik hier voor het interesse formulier !
Heeft u interesse vul dan het onderstaande interesseformulier in. Vanwege de vele reacties benaderen we alleen diegene die uitgenodigd wordt voor een kennismaking. Indien u binnen 3 dagen niets van ons hebt vernomen, dan is de keuze gevallen op een andere geïnteresseerde. Is de keuze op u gevallen, dan bellen wij u met een 088 nummer. Houdt uw telefoon in de gaten! 
Het is goed om te weten dat wij altijd werken met minimaal twee kennismakingen. De hond gaat niet bij de eerste kennismaking mee. Wij adviseren u om u goed in te lezen op de website van de LICG over het ras waarop u reageert.
Wij zijn geopend van ma t/m vr van 10:30u tot 12:00u en van 13:00 tot 16:00u, op zaterdag van 10:00u tot 12:00u. Tijdens openingstijden zijn wij telefonisch te bereiken op telefoonnummer 088 – 8 11 36 70 voor eventuele vragen. 
Let op, het kan voorkomen dat wij meerdere interesse mails krijgen voor hetzelfde dier. Het dier is pas voor u gereserveerd op het moment dat er een kennismakingsafspraak is ingepland. Wij kunnen onze dieren maximaal 3 dagen voor u reserveren, we vinden het namelijk erg belangrijk dat een dier niet langer dan noodzakelijk in onze opvang verblijft. Graag uw begrip hiervoor.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_330x285_crop_center-center_none/4581350/3S7A1143.jpg?stamp=2604110724&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_384x330_crop_center-center_none/4581350/3S7A1143.jpg?stamp=2604110724&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_519x453_crop_center-center_none/4581350/3S7A1143.jpg?stamp=2604110724&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/4581350/3S7A1143.jpg?stamp=2604110724&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/4581352/3S7A1075.jpg?stamp=2604121341&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_384x330_crop_center-center_none/4581350/3S7A1143.jpg?stamp=2604110724&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_519x453_crop_center-center_none/4581350/3S7A1143.jpg?stamp=2604110724&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/4581350/3S7A1143.jpg?stamp=2604110724&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/4581352/3S7A1075.jpg?stamp=2604121341&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301218&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4580114-kees'
from public.shelters s
where s.name = 'Dierenopvangcentrum Enschede'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4580114-kees')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Mo en Laska', 'Maak kennis met Mo & Laska — een gouden duo in labradorverpakking dat bewijst dat leeftijd echt maar een getal is (een licht elastisch getal, in hun geval).
Mo (dame, 2014, gesteriliseerd) en Laska (heer, 2016, intact) zijn misschien officieel senioren, maar mentaal zitten ze nog ergens tussen “puber met suiker” en “feestcommissie zonder rem”. Haal je deze twee in huis, dan krijg je geen honden… maar een welkomstcomité op standje festival.
Iedereen is welkom. Echt iedereen. Familie, vrienden, buren, pakketbezorgers — zelfs de melkboer krijgt een ontvangst alsof hij een wereldster is. Laska doet daar graag nog een schepje bovenop met zijn kenmerkende L.E.O.-gedrag (Lomp En Onbenullig™). Niet om lastig te zijn, maar puur om te zeggen:“HALLO! WIJ ZIJN HIER! EN JIJ OOK! WAT GEZELLIG!”
Gelukkig weten ze ook wanneer het tijd is om even serieus te kijken. Een subtiel waaks randje zit er zeker op.
Hobby’s en talenten:
Laska: professioneel balfanaticus (Olympische ambities niet uitgesloten)Mo: fulltime genietexpert, gespecialiseerd in knuffels en kriebelsSamen: eten… denken aan eten… dromen over eten…
Over dat laatste gesproken: ze zijn momenteel bezig met hun “summer body 2030”-programma. Geen ingewikkeld dieetvoer, gewoon iets minder brokken in de bak (een uitdaging van olympisch niveau voor een labrador). Daarbij horen ook wandelingen — liever meerdere korte rondjes dan één marathon, mede omdat ze nog wat… eh… “statig gebouwd” zijn. Bonus: je hoeft voorlopig geen sportschoolabonnement meer want voor beide geldt: trekkracht aan de riem verzekerd.
Sociaal leven:
Andere honden: wisselend succes, vooral Laska kan wat enthousiast (lees: reactief) reagerenKatten: doe maar niet!Kinderen: ja, mits ze stevig in hun schoenen staan en begrijpen dat “lomp enthousiasme” een ding is
Woonsituatie:
Alleen thuis zijn? Kunnen ze, maar rustig opbouwen is belangrijkTuin? Ja graag! Zon, regen, modder — ze nemen het allemaal serieus
Waarom juist zij?Omdat je niet alleen twee honden adopteert, maar ook twee persoonlijkheden, twee schaduwen, twee harten vol liefde. Ja, ze zijn wat ouder — maar geloof ons: hun enthousiasme, loyaliteit en knuffelcapaciteit doen niet onder voor die van een pup.
Dus denk je nu:“Wat een cadeau om deze twee nog een prachtige tijd te geven”
Dan hopen Mo & Laska dat jij degene bent met wie ze hun laatste (en misschien wel leukste) avonturen mogen beleven!
Wij vragen je uitsluitend te reageren via de mail, met een uitgebreide persoonlijke toelichting en motivatie. Als je via de “bezoek plannen” knop reageert, kunt je de gewenste informatie vermelden bij de toelichting. Op reacties zonder toelichting wordt niet gereageerd.
Een hond kies je niet zomaar, wij hebben dan ook een strenge selectie voor onze asielhonden. Houd er daarom rekening mee dat een hond tijdens de eerste kennismaking nog niet geplaatst wordt. Per dier kijken we hoe vaak het noodzakelijk is om terug te komen. De afspraken worden in overleg en in kort tijdsbestek ingepland. Ook willen wij kennismaken met het gehele gezin, inclusief de eventuele al aanwezige hond(-en). Op het asiel krijgen jullie alle tijd om kennis te maken, te gaan wandelen en vragen te stellen.
Na een positieve kennismaking worden er vervolgafspraken gemaakt.
Geïnteresseerd in Mo en Laska?
Neem contact met ons op via de "een bezoek plannen" knop (vergeet niet de gevraagde gegevens erbij te vermelden - zie tekst), of bel ons op (0314) 32 48 54
Let wel: het kan zijn dat er al andere gegadigden zijn, die een afspraak hebben gemaakt om kennis te komen maken. Dit wordt hier niet altijd zichtbaar.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/lab7.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/lab7.jpg?stamp=2605012035&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/lab7.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab7.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab5.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab1.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab9.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab8.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab6.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab4.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab2.jpg?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/lab7.jpg?stamp=2605012035&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/lab7.jpg?stamp=2605012035&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab7.jpg?stamp=2605012035&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/lab5.jpg?stamp=2605012035&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4593272-mo-en-laska'
from public.shelters s
where s.name = 'Dierencentrum Achterhoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4593272-mo-en-laska')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Dushi', 'Maak kennis met Dushi! Dushi is een enthousiaste Herder x Teckel kruising van 1,5 jaar die een beetje afwachtend is maar bomvol energie zit. Hij is een actieve en energieke hond die graag bezig is en het heerlijk vindt om eropuit te gaan. Hij geniet zichtbaar van lange wandelingen en spelen met een balletje. Voldoende beweging en trainen is dus wel belangrijk voor deze jongen.
Dushi is in het begin angstig voor nieuwe mensen en komt dan een beetje intimiderend over, maar onder dat geblaf schuilt een klein en lief karakter die met de tijd al snel tevoorschijn komt. Als je hem rustig benadert, met wat lekkers, is hij al snel je vriend en wilt hij dolgraag knuffelen en op schoot. Dushi is bij bekende mensen reuze enthousiast en springt dan vrolijk tegen je aan en wilt heel graag aandacht. Vanwege zijn afwachtende, maar ook wat drukke karakter denken wij dat hij beter op zijn plek is in een huis zonder kinderen en andere huisdieren.
Dushi is waaks in huis en kan blaffen als de deurbel gaat of als er mensen of honden langs lopen. Verder slaapt hij in huis rustig in een mand en is goed zindelijk.
Ook kent Dushi al wat basis commando’s zoals zit, af, blijf en pootje. Buiten loopt hij netjes mee aan de riem zonder te trekken. Hij snuffelt veel en kijkt niet om naar voorbijkomend verkeer. Wel reageert hij tijdens een wandeling fel op andere honden en (mannelijke) hardlopers. Dat is dus een aandachtspuntje voor deze jongen. Wij plaatsen hem om die reden niet met andere honden.
Kortom, Dushi is een jonge, energieke hond die wat tijd nodig heeft om aan nieuwe mensen te wennen, maar met tijd en vertrouwen een lief en aanhankelijk maatje is.
Wat wij zoeken voor Dushi is een rustig huishouden zonder kinderen en andere huisdieren. Hij heeft een baasje nodig die hem zowel fysiek als mentaal uitdaagt en hem de tijd geeft om rustig te wennen aan zijn nieuwe omgeving. Een tuin is voor Dushi wel een must om zijn energie kwijt te kunnen.
Ben jij net als Dushi zo enthousiast van actief zijn? Neem dan contact op, Dushi kan niet wachten om samen te trainen! 🐾
Heeft u interesse na het lezen van de beschrijving? Vul onderstaande vragenlijst in en mail deze naar info@dierenasielutrecht.nl, wij nemen dan contact met u op.
Let op, op mail zonder vragenlijst kunnen wij niet reageren! - Heeft u eerder een hond gehad, wat voor ras?- Waarom kiest u voor deze hond/dit ras?- Hoe woont u (flat/vrijstaand/boerderij) hoeveel m2?- Heeft u momenteel een hond? (ras/geslacht/leeftijd)?- Wat is de gezinssamenstelling (kinderen of kinderwens/dieren)?- Hoelang en hoe vaak moet de hond wekelijks alleen zijn?- Wat bent u van plan om, buiten wandelen om, met de hond te doen?- Adres en contactgegevens:', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Dushi4.png?stamp=2605011439&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Dushi4.png?stamp=2605011439&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Dushi4.png?stamp=2605011439&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dushi4.png?stamp=2605011439&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dushi2.jpg?stamp=2604241222&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dushi1.jpg?stamp=2604241222&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dushi3.jpg?stamp=2604241222&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Dushi4.png?stamp=2605011439&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Dushi4.png?stamp=2605011439&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dushi4.png?stamp=2605011439&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dushi2.jpg?stamp=2604241222&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dushi1.jpg?stamp=2604241222&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dushi3.jpg?stamp=2604241222&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4593013-dushi'
