insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', 'Mowgli', 'Hoi! Ik ben Mowgli 🐾 
Ik ben een Franse bulldog van 5 jaar en, al zeg ik het zelf, een vrolijke, enthousiaste dame. Ik heb nog een heel leven voor me en ik ben er helemaal klaar voor om dat samen met iemand te delen. 
Knuffelen? Ja, graag! Daar ben ik echt dol op. Ik kruip het liefst lekker dicht tegen je aan. Maar vergis je niet, ik kan ook heerlijk spelen hoor. Achter speeltjes aanrennen is één van mijn favoriete bezigheden. Gooi iets weg en ik ben al onderweg! 
Katten heb ik nog nooit ontmoet, dus dat is voor mij nog een groot vraagteken. Kinderen? Geen probleem! Die vind ik juist leuk. Andere honden? Tja daar heb ik wel een duidelijke mening over. In 1 huis wonen met een andere hond is dus eigenlijk niet helemaal handig. 
Wandelen heb ik een tijdje minder gedaan, dus dat zijn we rustig weer aan het opbouwen. Maar een fijn rondje lopen kan ik nu al van genieten. Lekker samen naar buiten, nieuwe geurtjes ontdekken, heerlijk! 
Wat ik zoek? Iemand die net zo blij wordt van knuffelen als ik. Iemand die met mij wil spelen, samen op pad wil gaan en mij de kans geeft om verder te groeien. Wellicht zelfs wel gezellig met Beau! 
Ik ben er klaar voor om opnieuw te beginnen. Jij ook?', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_330x285_crop_center-center_none/IMG_6597.jpg?stamp=2604221134&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_384x330_crop_center-center_none/IMG_6597.jpg?stamp=2604221134&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_519x453_crop_center-center_none/IMG_6597.jpg?stamp=2604221134&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/IMG_6597.jpg?stamp=2604221134&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/IMG_6625.jpg?stamp=2604221134&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_384x330_crop_center-center_none/IMG_6597.jpg?stamp=2604221134&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_519x453_crop_center-center_none/IMG_6597.jpg?stamp=2604221134&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/IMG_6597.jpg?stamp=2604221134&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/IMG_6625.jpg?stamp=2604221134&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_882x1004_crop_center-center_none/banner-beeld-hond-close-885.png?stamp=2504161034&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4591171-mowgli'
