select s.id, 'Rotterdam', 'Noach & Bracha', 'Noach & Bracha zoeken samen hun gouden mandje 🐾💛', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_330x285_crop_center-center_none/noach-en-bracha.jpg?stamp=2604221319&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_384x330_crop_center-center_none/noach-en-bracha.jpg?stamp=2604221319&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_519x453_crop_center-center_none/noach-en-bracha.jpg?stamp=2604221319&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/noach-en-bracha.jpg?stamp=2604221319&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/bracha.jpg?stamp=2604221106&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/Noach-1.jpg?stamp=2604221320&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_384x330_crop_center-center_none/noach-en-bracha.jpg?stamp=2604221319&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_519x453_crop_center-center_none/noach-en-bracha.jpg?stamp=2604221319&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/noach-en-bracha.jpg?stamp=2604221319&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/bracha.jpg?stamp=2604221106&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/Noach-1.jpg?stamp=2604221320&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301131&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4591102-noach-b