insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Mia en Pip', 'Graag stellen we jullie voor aan Mia en Pip! Deze twee vrolijke vriendinnen zijn onafscheidelijk en worden dan ook samen geplaatst. Mia is een jonge labrador retriever van 1 jaar oud en Pip is een kruising Friese Stabij x Berner Sennen van 1,5 jaar oud. Samen vormen ze een gezellig, speels en liefdevol duo.
Mia is een enthousiaste en aanhankelijke dame die gek is op aandacht, knuffelen en spelen. Of het nu gaat om een bal, een flostouw of samen ravotten met Pip: Mia is altijd in voor actie. ’s Ochtends begroet ze iedereen vrolijk met een kwispelende staart en een speeltje in haar bek. Zoals een echte labrador betaamt, is ze ook dol op water en neemt ze het liefst meteen een duik zodra ze de kans krijgt.
Pip is net zo speels, maar heeft een iets ander karakter. Ze is slim, zelfstandig en een tikje onzeker. Ze vindt het heerlijk om met Mia te spelen of samen met haar baas met een bal bezig te zijn. Nieuwe mensen vindt Pip in het begin spannend, maar met wat geduld (en een bal) sluit ze je al snel in haar hart. Met steun van Mia durft ze steeds meer en laat ze zien wat een stoere, maar gevoelige hond ze eigenlijk is.
Beide dames zijn dol op koekjes en leren graag nieuwe dingen. Ze kennen al een aantal basiscommando’s zoals zit, poot en af, maar hebben nog verdere training nodig. Mia kan buiten soms wat lomp en enthousiast zijn en vergeet dan dat ze aan de riem loopt. Pip is buiten juist wat gevoeliger voor prikkels en kan reageren op bijvoorbeeld fietsers of auto’s door te blaffen of te trekken. Met positieve training, duidelijkheid en beloning zullen ze hier samen nog grote stappen in kunnen maken.
Tijdens wandelingen geniet Mia volop en snuffelt ze er vrolijk op los, terwijl Pip soms wat extra steun nodig heeft als ze iets spannend vindt. Binnen kan Pip wat waaks zijn en reageren op harde geluiden, terwijl Mia juist graag de gezellige knuffelkont uithangt.
Mia is daarnaast een tikje lui en gek op eten, waardoor ze wat overgewicht heeft. Het is belangrijk dat ze samen met Pip voldoende beweging krijgt om fitter te worden en gezond te blijven. Pip heeft juist veel behoefte aan zowel fysieke als mentale uitdaging en zou het geweldig vinden om actief te trainen met haar toekomstige baas.
Voor dit duo zoeken we een betrokken en actief baasje dat met beide honden aan de slag wil gaan. Iemand die Pip de tijd geeft om vertrouwen op te bouwen en Mia helpt om fitter en meer gefocust te worden. Vanwege Pip haar onzekere karakter plaatsen we hen niet bij kinderen of andere huisdieren.
Kortom, Mia en Pip zijn twee lieve, jonge honden met ieder hun eigen karakter, maar samen vormen ze een prachtig duo. Met geduld, consequente en positieve training krijg je er twee trouwe, vrolijke en liefdevolle vriendinnen voor het leven bij. 🐾
Heeft u interesse na het lezen van de beschrijving? Vul onderstaande vragenlijst in en mail deze naar info@dierenasielutrecht.nl, wij nemen dan contact met u op.
Let op, op mail zonder vragenlijst kunnen wij niet reageren! - Heeft u eerder een hond gehad, wat voor ras?- Waarom kiest u voor deze hond/dit ras?- Hoe woont u (flat/vrijstaand/boerderij) hoeveel m2?- Heeft u momenteel een hond? (ras/geslacht/leeftijd)?- Wat is de gezinssamenstelling (kinderen of kinderwens/dieren)?- Hoelang en hoe vaak moet de hond wekelijks alleen zijn?- Wat bent u van plan om, buiten wandelen om, met de hond te doen?- Adres en contactgegevens:', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Mia-Pip-1.jpg?stamp=2604211036&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Mia-Pip-1.jpg?stamp=2604211036&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Mia-Pip-1.jpg?stamp=2604211036&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Mia-Pip-1.jpg?stamp=2604211036&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Mia-Pip-2.jpg?stamp=2604211036&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Mia-Pip_2026-04-21-083900_nxig.jpg?stamp=2604211039&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Mia-Pip-1.jpg?stamp=2604211036&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Mia-Pip-1.jpg?stamp=2604211036&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Mia-Pip-1.jpg?stamp=2604211036&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Mia-Pip-2.jpg?stamp=2604211036&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Mia-Pip_2026-04-21-083900_nxig.jpg?stamp=2604211039&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4589867-mia-en-pip'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4589867-mia-en-pip')
