insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zwolle', 'Willem', 'Willem is een enthousiaste reu, geboren op 24 februari 2023.Denk je Spaniel te herkennen? Dan heb je gelijk, want Willem is een knappe Duitse Wachtelhond, ook wel Duitse spaniel genoemd. 

Willem is een lieve, sociale en mensgerichte hond die graag bij je in de buurt is en goed overweg kan met andere honden. Hij heeft een energiek en speels karakter en staat bekend als een echte druktemaker die volop beweging en uitdaging nodig heeft.
Willem is actief en gebruikt buiten graag zijn neus; speuren en ontdekken zitten echt in zijn natuur. Hij vindt het fantastisch om bezig te zijn. Lange wandelingen en denkspelletjes vindt hij fantastisch en hiermee raakt hij ook hij zijn energie kwijt.Aan de riem kan hij nog trekken, wat vraagt om begeleiding en training. In de kennel is hij netjes en zindelijk en blijft hij rustig alleen, maar buiten in zijn eentje op de speelweide vindt hij alleen zijn minder prettig en kan hij gaan joelen.


Willem kan geplaatst worden bij oudere kinderen vanaf ongeveer 8 jaar, mits zij weten hoe zij met een hond om moeten gaan. En mits zij hem niet bij zijn voerbak storen. Want Willem is érg gesteld op zijn eten en wil dit niet delen.Andere honden vindt Willem erg leuk, maar katten zijn voor Willem echt geen goede match.

Bij de dierenartscontrole werd een lichte patella luxatie (graad 1 à 2) aan zijn linkerknie vastgesteld. Na een aantal weken observatie lijkt Willem er gelukkig geen last van te hebben en is nu geen behandeling nodig. Wel is het belangrijk om dit in de gaten te houden. 
De Duitse Wachtelhond is van oorsprong een jachthond met een sterk ontwikkelde neus en een grote werklust. Het ras staat bekend om zijn intelligentie, doorzettingsvermogen en behoefte aan voldoende beweging en mentale uitdaging. Deze honden zijn trouw aan hun eigenaar en werken graag samen, maar kunnen ook zelfstandig en eigenwijs zijn.Ze hebben een consequente, maar vriendelijke opvoeding nodig en gedijen het beste bij een actieve baas die veel tijd met hen doorbrengt. Door hun jachtinstinct zijn ze vaak minder geschikt in combinatie met kleine huisdieren. Daarnaast hebben ze behoefte aan structuur, duidelijkheid en voldoende uitlaatmogelijkheden om zowel fysiek als mentaal in balans te blijven. 

Voor Willem zoeken wij een actieve baas die hem voldoende beweging, uitdaging en begeleiding kan bieden. Met de juiste aanpak groeit hij uit tot een trouwe, enthousiaste en liefdevolle metgezel. Ben jij klaar voor een energieke hond die graag met je samenwerkt en de wereld wil ontdekken? Denk dan eens aan Willem!', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_330x285_crop_center-center_none/7558-willem-28.jpg?stamp=2604101323&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/7558-willem-28.jpg?stamp=2604101323&tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/7558-willem-28.jpg?stamp=2604101323&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7558-willem-28.jpg?stamp=2604101323&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7558-willem-30.jpg?stamp=2604101323&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7558-willem-27.jpg?stamp=2604101323&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7558-willem-23.jpg?stamp=2604101323&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/7558-willem-28.jpg?stamp=2604101323&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/7558-willem-28.jpg?stamp=2604101323&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7558-willem-28.jpg?stamp=2604101323&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7558-willem-30.jpg?stamp=2604101323&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7558-willem-27.jpg?stamp=2604101323&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7558-willem-23.jpg?stamp=2604101323&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4580945-willem'
from public.shelters s
where s.name = 'Zwols Dierenasiel'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4580945-willem')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Enschede', 'Tonic', 'Maak kennis met Tonic, een energieke en pittige Australian Shepherd met een sterke persoonlijkheid en een grote dosis werklust. Hij is een slimme hond die graag bezig is en veel potentie heeft, maar die ook duidelijke sturing nodig heeft om tot zijn recht te komen.
Buiten ervaart Tonic veel prikkels die hij nog moeilijk kan verwerken. Vooral andere honden vindt hij erg lastig. In zulke situaties kan hij fel en uitvallend reageren. Het is daarom belangrijk dat zijn toekomstige eigenaar dit begrijpt en bereid is om hier actief en geduldig mee aan de slag te gaan.
Naar mensen toe is Tonic juist heel sociaal en vriendelijk. Hij geniet van contact en kan echt een maatje zijn voor zijn eigenaar.
Tonic heeft baat bij een rustige en stabiele omgeving, waarin hij stap voor stap kan leren omgaan met prikkels en kan werken aan zijn zelfvertrouwen. Met de juiste begeleiding, training en een consequente aanpak kan hij hierin mooie vooruitgang boeken. Het is een hond die tijd, geduld en inzet vraagt, maar die zeker de moeite waard is.
Voor Tonic zoeken we een ervaren en betrokken thuis, zonder andere honden. We zoeken een eigenaar die stevig in de schoenen staat, duidelijke maar eerlijke grenzen kan stellen en hem de structuur en begeleiding biedt die hij nodig heeft. Ervaring met reactief gedrag is hierbij een groot pluspunt.
Ben jij degene die Tonic de rust, duidelijkheid en begeleiding kan bieden waar hij zo naar op zoek is? 
---------------------------------------------------------------------------------------------------
Heeft u interesse vul dan het onderstaande interesseformulier in. Vanwege de vele reacties benaderen we alleen diegene die uitgenodigd wordt voor een kennismaking. Indien u binnen 3 dagen niets van ons hebt vernomen, dan is de keuze gevallen op een andere geïnteresseerde. Is de keuze op u gevallen, dan bellen wij u met een 088 nummer. Houdt uw telefoon in de gaten!
Let op, het kan voorkomen dat wij meerdere interesse mails krijgen voor hetzelfde dier. Het dier is pas voor u gereserveerd op het moment dat er een kennismakingsafspraak is ingepland. Wij kunnen onze dieren maximaal 3 dagen voor u reserveren, we vinden het namelijk erg belangrijk dat een dier niet langer dan noodzakelijk in onze opvang verblijft. Graag uw begrip hiervoor.
Het is goed om te weten dat wij altijd werken met minimaal twee kennismakingen. De hond gaat niet bij de eerste kennismaking mee. Wij adviseren u om u goed in te lezen op de website van de LICG over het ras waarop u reageert.
KLIK HIER VOOR HET INTERESSEFORMULIER!', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_330x285_crop_center-center_none/84286505-2962-4eaa-9b5c-1ab667cb18cd.jpg?stamp=2603301542&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_384x330_crop_center-center_none/84286505-2962-4eaa-9b5c-1ab667cb18cd.jpg?stamp=2603301542&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_519x453_crop_center-center_none/84286505-2962-4eaa-9b5c-1ab667cb18cd.jpg?stamp=2603301542&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/84286505-2962-4eaa-9b5c-1ab667cb18cd.jpg?stamp=2603301542&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/c3feacc2-33a5-4678-911c-b2cb14bacbd7.jpg?stamp=2603301548&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_384x330_crop_center-center_none/84286505-2962-4eaa-9b5c-1ab667cb18cd.jpg?stamp=2603301542&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_519x453_crop_center-center_none/84286505-2962-4eaa-9b5c-1ab667cb18cd.jpg?stamp=2603301542&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/84286505-2962-4eaa-9b5c-1ab667cb18cd.jpg?stamp=2603301542&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/_800x550_crop_center-center_none/c3feacc2-33a5-4678-911c-b2cb14bacbd7.jpg?stamp=2603301548&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumEnschede/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301218&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4580384-tonic'
