insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Gucci *Asiel Genk*', 'Let op Gucci verblijft in het asiel van Genk België.
Gucci zat reeds eerder in ons asiel. Nadat haar match gevonden werd mocht ze proeven van de gezellige warmte van een thuis, een eigen familie, de aandacht van een eigen baasje,… Maar als de gezondheid van het baasje het samen zijn onmogelijk maakt, moet er opnieuw een oplossing gezocht worden. Dus mocht Gucci bij de dochter gaan wonen. Gucci was te opgewonden in huis, te hevig met de hond van de dochter en bij het wandelen viel ze uit naar honden en mensen. Daarnaast is Gucci gevoelig voor allergieën. De moeilijke beslissing om haar af te staan aan het asiel werd genomen.
Bij ons laat Gucci aan de lijn hetzelfde gedrag zien, maar binnenshuis in vrijheid is Gucci een vrolijke dame. Ze maakt graag contact met mensen al gaat dit soms gepaard met een beetje te veel opwinding. Dikke kussen zijn dan niet uitgesloten, al kan ze zich steeds beter beheersen. Ze is gek op mensen en kan ook haar rust vinden in huis. Haar grootste hobby: snuffelen! Als een echte pro snuffelt Gucci hier alle weiden af, waarna ze voldaan in haar mandje ploft.
Als je meteen na een heerlijke knuffelsessie afscheid neemt zal je merken dat Gucci het moeilijk heeft. Rustig opbouwen is hier aangewezen. Maar deze slimme meid kan ook verrassend uit de hoek komen. Zit, poot en los wordt netjes beheerst uitgevoerd, steeds voorafgegaan door een sierlijke pirouette. Plié! Ook puzzelen doet Gucci als een dame: aandachtig en nauwkeurig. Kleurrijke speeltjes halen dan weer het kleine meisje in haar naar boven. Pluchen beertjes mogen gezellig mee in de mand of in de bench, de favoriete slaapplek van prinses Gucci. Ontbijt op bed steeds welkom!
Voor Gucci zoeken we een plekje met een tuin ze wordt niet op een appartement geplaatst.
Kinderen vanaf 14 jaar.
Staat Gucci’s gouden mandje bij jou thuis?Heb je een huis met een tuin? Stuur dan een mail naar info@dierenasielgenk.be.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-23042025-120300-1.jpg?stamp=2604031651&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-23042025-120300-1.jpg?stamp=2604031651&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-23042025-120300-1.jpg?stamp=2604031651&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-23042025-120300-1.jpg?stamp=2604031651&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/DIERENASIELGENK_EVIOCLICK_WEB-112-scaled-1-2.jpg?stamp=2604031651&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-27112024-110550-4.jpg?stamp=2604031651&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/gucci-3.jpg?stamp=2604031651&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-23042025-120300-1.jpg?stamp=2604031651&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-23042025-120300-1.jpg?stamp=2604031651&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-23042025-120300-1.jpg?stamp=2604031651&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/DIERENASIELGENK_EVIOCLICK_WEB-112-scaled-1-2.jpg?stamp=2604031651&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/dierenasiel-genk-vzw-gucci-197954-extra-27112024-110550-4.jpg?stamp=2604031651&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/gucci-3.jpg?stamp=2604031651&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4576384-gucci-asiel-genk'
