insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zwolle', 'Frummel', 'Frummel is een reu, geboren rond 24 september 2022, die als vondeling is binnengebracht. Een eigenaar heeft zich nooit meer gemeld, wat ons vermoeden bevestigd dat Frummel niet uit vrije wil daar heen is gelopen..Hij werd aangetroffen in het buitengebied en was zo bang dat hij zich niet zomaar liet pakken. Pas na vijf dagen lukte het bezorgde dierenliefhebbers om hem veilig te stellen. In het begin was Frummel erg van slag en in paniek hapte hij van zich af, wat heel begrijpelijk is na zo’n start. Maar al snel kreeg hij vertrouwen in de dierverzorgers en laat hij een heel andere kant van zichzelf zien.Zodra hij je kent (en dat gaat best snel!), is hij een vrolijke en aanhankelijke hond die graag bij je in de buurt is en geniet van aandacht en knuffels.Frummel is een actieve en speelse hond die netjes zindelijk is in zijn kennel. Aan de riem is hij in het begin enthousiast en blaft hij. Buiten is hij nieuwsgierig, al vindt hij sommige situaties nog spannend.Omdat Frummel een moeilijke start heeft gehad, zoeken wij voor hem een rustige en stabiele omgeving. Hij kan in eerste instantie wat afwachtend zijn en heeft dus tijd nodig om mensen te leren vertrouwen. Wanneer hij zich veilig voelt, laat hij zien hoe lief en gezellig hij is. Alleen thuis zijn vindt hij nog lastig; hij laat dan horen dat hij je mist. Over zijn omgang met andere honden en katten is nog weinig bekend, maar met de juiste begeleiding zou samenleven met een andere hond tot zijn formaat mogelijk kunnen zijn. Hij heeft de speelplaats gedeeld met 2 kleine hondjes en dat ging prima. Honden tot zijn eigen formaat gaat zonder problemen. Samenwonen met kinderen onder de 15 jaar past niet bij Frummel. Voor Frummel zoeken wij een thuis waar de baas veel thuis is en die ook alle tijd neemt om Frummel te laten wennen.Op die manier kan hij verder groeien in zelfvertrouwen en kan hij zich ontwikkelen tot de stabiele en blije hond die hij is. In het geval van een tuin moet deze goed afgezet zijn.
Kennismakingen: wij vragen geïnteresseerden altijd om 3x kennis te komen maken.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_330x285_crop_center-center_none/7553-frummel-8.jpg?stamp=2604031256&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/7553-frummel-8.jpg?stamp=2604031256&tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/7553-frummel-8.jpg?stamp=2604031256&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7553-frummel-8.jpg?stamp=2604031256&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7553-frummel-15.jpg?stamp=2604031257&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7553-frummel-14.jpg?stamp=2604031256&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/7553-frummel-8.jpg?stamp=2604031256&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/7553-frummel-8.jpg?stamp=2604031256&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7553-frummel-8.jpg?stamp=2604031256&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7553-frummel-15.jpg?stamp=2604031257&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7553-frummel-14.jpg?stamp=2604031256&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4575972-frummel'
