  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4575972-frummel')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Diva', 'Gezocht: persoonlijke knuffel assistent (fulltime functie)Maak kennis met Diva - onze professionele knuffelkont met jaren ervaring in het uitdelen (en vooral opeisen) van aandacht. Diva is ervan overtuigd dat jouw handen maar een doel hebben in het leven: haar kriebelen. En eerlijk? Daar heeft ze eigenlijk gewoon gelijk in. Ze is ontzettend aanhankelijk en plakt het liefst gezellig tegen je aan alsof ze vastgelijmd zit. Alleen zijn? Dat vindt deze dame zwaar overrated. Samen zijn is veel leuker!Tijdens het wandelen laat Diva haar goede manieren zien: andere honden? Prima, maar liever op gepaste afstand. Thuis deelt ze haar troon dan ook het liefst niet - ze is graag jouw enige prinses.Diva heeft een rugzakje: ze heeft spondylose en artrose. Daarom krijgt ze levenslang pijnstilling en speciale voeding. Gelukkig laat ze zich daar totaal niet door tegenhouden en geniet ze volop van haar dagjes knuffelen, wandelen en bij je zijn❤️ Diva zoekt: een huisje zonder andere dieren. Mensen die veel thuis zijn (of haar gewoon overal mee naartoe nemen😉 ). Wat krijg je ervoor terug? Onvoorwaardelijke liefde en de beste knuffels van Nederland.Denk jij dat jij geschikt bent als Diva''s persoonlijke knuffel assistent? Solliciteer via limburg@dierenbescherming.nl en wie weet mag jij binnenkort in dienst!', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Diva_2026-03-28-130656_gmzh.jpg?stamp=2603281409&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Diva_2026-03-28-130656_gmzh.jpg?stamp=2603281409&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Diva_2026-03-28-130656_gmzh.jpg?stamp=2603281409&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva_2026-03-28-130656_gmzh.jpg?stamp=2603281409&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva-28-3.jpg?stamp=2603281407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva-28-3-7.jpg?stamp=2603281407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva-28-3-3.jpg?stamp=2603281407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva-28-3-2.jpg?stamp=2603281407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva-28-3-1.jpg?stamp=2603281407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva-28-3-4.jpg?stamp=2603281407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva-28-3-5.jpg?stamp=2603281407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva-28-3-6.jpg?stamp=2603281407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Diva_2026-03-28-130656_gmzh.jpg?stamp=2603281409&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Diva_2026-03-28-130656_gmzh.jpg?stamp=2603281409&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Diva_2026-03-28-130656_gmzh.jpg?stamp=2603281409&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4570145-diva'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4570145-diva')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Gouda', 'Nala', 'Nala (8 jaar) een Golden retriever uit België opzoek naar haar nieuwe thuis! Nala is bij ons afgestaan omdat haar vuurwerkangst steeds erger werd en dat niet meer te doen was in de stad. Nala durfde niet meer buiten te wandelen en dus hebben de eigenaren besloten dat het voor Nala beter is om te verhuizen. Nala is dan ook op zoek naar een rustige omgeving en een rustig huishouden. Naast haar vuurwerkangst heeft Nala ook bezitsagressie. Dit uit zich bij haar op verschillende momenten. Het kan haar hierbij gaan om een botje, maar ook een speeltje of iets waar ze op dat moment mee bezig is. Nala is een bench gewend en ook gewend dat zij hierin haar eten/ botje krijgt. Zij is geen tuin gewend, maar wilt wel graag graven en ook dit is iets wat Nala gaat verdedigen. 
Naast haar puntjes van aandacht loopt Nala wel netjes mee aan de lijn, ze vindt het soms nog wel spannend om buiten te lopen en soms is een kort rondje voor haar voldoende. Mogelijk dat hoe meer vertrouwen zij in de omgeving en jou krijgt hoe liever zij wil gaan wandelen. Rollen in de modder of zwemmen in het water (liefst modder) is iets wat zij echt supertof vindt!! De mooie blonde kleur raakt zij dan ook geregeld kwijt... 
Nala heeft meerdere gedragsissues daarom hebben wij besloten om bij haar gedragsmedicatie in te zetten om te zien of zij op deze manier beter om zou kunnen gaan met de veranderingen en ze hierdoor een beter leervermogen zou krijgen. Gelukkig zien wij bij haar zeker een verbetering in en zien we een steeds enthousiastere hond die meer en meer contact met ons begint te maken. Ze heeft bij ons nog niets laten zien van bezitsagressie en ook niet van de baknijd. Wij vragen wat dat betreft ook niet veel van haar en wij verwachten dat als haar nieuwe eigenaar er ook zo in staat en er ook open voor staat om Nala haar een eigen ruimte te geven waarin zij haar eten of ander lekkers rustig kan opeten of haar rust kan vinden, dan verwachten wij dat dit ook geen issue hoeft te zijn. 
Wij zijn uiteraard nog steeds met Nala in training, haar nieuwe eigenaar moet dan ook zeker bereid zijn om hierin verder met haar aan de slag te gaan. Het belangrijkste voor Nala is dat je haar leert begrijpen waardoor zij geen agressie hoeft in te zetten, want zij vertelt je namelijk precies wat zij wel en niet fijn vindt! 
Het is niet mogelijk om zonder afspraak naar onze honden te komen kijken. Om er zeker van te zijn dat u en de hond een goede match zijn, verzoeken we u vriendelijk de algemene vragenlijst zo uitgebreid mogelijk te beantwoorden en te mailen naar gouda@dierenbescherming.nl . Wij zullen dan contact met u opnemen. U kunt UITSLUITEND mailen, bellen heeft geen zin.
Wat zijn uw naam, adres, woonplaats en telefoonnummer?
Vertel iets over uw gezinssituatie. Wat zijn de leeftijden van alle gezinsleden?
Vertel iets over uw werksituatie (aantal dagen, hoeveel uren bent u van huis, etc.)
Hoeveel uur moet de hond alleen thuis kunnen zijn? Hoe vaak per week komt dit voor?
Vertel iets over uw woonsituatie (appartement, rijtjes woning, afgesloten tuin of open tuin, etc.)
Wat is uw ervaring met honden (ras, karakter, leeftijd etc.)?
Welke huisdieren heeft u?
Welke tijd en dagen bent u beschikbaar voor kennismaking?', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_330x285_crop_center-center_none/4582832/DSC_0042_2026-04-13-133131_czfg.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_384x330_crop_center-center_none/4582832/DSC_0042_2026-04-13-133131_czfg.jpg?stamp=2604131532&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_519x453_crop_center-center_none/4582832/DSC_0042_2026-04-13-133131_czfg.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4582832/DSC_0042_2026-04-13-133131_czfg.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4582831/DSC_0041_2026-04-13-133129_vlnl.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4582830/DSC_0034_2026-04-13-133126_rbqf.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4582829/DSC_0031_2026-04-13-133124_phrf.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4582828/DSC_0030_2026-04-13-133120_dmos.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4582827/DSC_0028_2026-04-13-133117_zyba.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4582826/DSC_0021-1.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/IMG-20260412-WA0002.jpg?stamp=2604121849&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/IMG-20260412-WA0000_2026-04-12-165210_dson.jpg?stamp=2604121852&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/Screenshot_20260412_185106_Edge.jpg?stamp=2604131532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/Screenshot_20260412_185043_Edge.jpg?stamp=2604121852&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/NALA_CANVAS_40_X_60_cm.jpg?stamp=2604141415&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4564361-nala'
from public.shelters s
where s.name = 'Dierenopvangcentrum Gouda'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4564361-nala')
limit 1;

