insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zwolle', 'Tirza', 'Tirza is een Old English Bulldog, een gesteriliseerde teef geboren op 16 oktober 2021.Haar vorige bazen konden Tirza ‘niet goed meer lezen’. Zij hebben haar destijds uit een nare situatie gehaald en helemaal opgeknapt met goede verzorging en operaties. Maar nu lijkt het beter om een andere geschikte plek voor haar te zoeken.Tirza blijkt namelijk een hond die erg op haar rust en regelmaat is gesteld en erg gevoelig is. Drukte van mensen en dieren vindt zij dan ook maar niets. Bij teveel prikkels kan haar emmertje overlopen en haar vorige bazen vonden haar dan onvoorspelbaar. Tirza heeft nog nooit gebeten, maar je moet aan haar zien wanneer Tirza overprikkeld is en het even genoeg voor haar is. Tirza is tegen de asielmedewerkers vriendelijk en maakt goed contact. Zij wandelt rustig (trekt eerst even, maar daarna goed) met je mee en reageert goed op trainen met beloningen.Met andere honden heeft Tirza niets. Grotere honden zijn nog redelijk ok, maar kleinere honden moeten uit haar buurt blijven.In huis is zij waaks naar vreemde mensen en samenwonen met kinderen is voor Tirza nu, en in de toekomst, niet verstandig. Eventjes alleen blijven kon Tirza prima. Zij is rustig in huis en maakt niets kapot. Ook is zij goed zindelijk, gaat ze graag mee met de auto en vindt zij zwemmen en met stokken spelen helemaal geweldig. Wij zoeken voor Tirza een redelijk prikkelarme woonplek. Een drukke woonwijk met kinderen en honden is niets voor haar, een rustig dorp zonder teveel mensen langs haar huis zou wellicht kunnen. Een huis met een tuin die goed afgezet is.Maar ook een eigenaar waar iedereen maar in- en uitloopt past niet bij Tirza. Bovenal zoeken wij dus een passende baas die Bulldog-ervaring heeft en verstand heeft van de hondentaal.
Kennismakingen: wij vragen geïnteresseerden altijd om 3x te komen kennismaken en te wandelen.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_330x285_crop_center-center_none/Tirza-02.png?stamp=2605051217&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/Tirza-02.png?stamp=2605051217&tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/Tirza-02.png?stamp=2605051217&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/Tirza-02.png?stamp=2605051217&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/Tirza-en-Bram-01.png?stamp=2605051216&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7509-tirza-81.jpg?stamp=2603011849&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7509-tirza-77.jpg?stamp=2603011849&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7509-tirza-72.jpg?stamp=2603011849&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7509-tirza-78.jpg?stamp=2603011849&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7509-tirza-82.jpg?stamp=2603011849&tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_384x330_crop_center-center_none/Tirza-02.png?stamp=2605051217&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_519x453_crop_center-center_none/Tirza-02.png?stamp=2605051217&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/Tirza-02.png?stamp=2605051217&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/Tirza-en-Bram-01.png?stamp=2605051216&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/zwolsDierenasiel/_800x550_crop_center-center_none/7509-tirza-81.jpg?stamp=2603011849&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4544536-tirza'
from public.shelters s
where s.name = 'Zwols Dierenasiel'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4544536-tirza')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Ede', 'Franciscus', 'Frans de Fransman', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_330x285_crop_center-center_none/2L3A0145.jpg?stamp=2602070942&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_384x330_crop_center-center_none/2L3A0145.jpg?stamp=2602070942&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_519x453_crop_center-center_none/2L3A0145.jpg?stamp=2602070942&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_800x550_crop_center-center_none/2L3A0145.jpg?stamp=2602070942&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_800x550_crop_center-center_none/2L3A0130.jpg?stamp=2602070942&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_800x550_crop_center-center_none/2L3A0137.jpg?stamp=2602070942&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_800x550_crop_center-center_none/2L3A0191.jpg?stamp=2602070942&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_800x550_crop_center-center_none/2L3A0135.jpg?stamp=2602070942&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/Algemeen/_800x550_crop_center-center_none/19cd9050-2dbb-47e4-95cb-70e83bca598f.jpg?stamp=2601301241&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/Algemeen/_800x550_crop_center-center_none/57e484c1-ec6b-4029-af35-aa7a83572c53.jpg?stamp=2601301236&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_384x330_crop_center-center_none/2L3A0145.jpg?stamp=2602070942&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_519x453_crop_center-center_none/2L3A0145.jpg?stamp=2602070942&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_800x550_crop_center-center_none/2L3A0145.jpg?stamp=2602070942&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_800x550_crop_center-center_none/2L3A0130.jpg?stamp=2602070942&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisDeHofVanEde/IZB-dieren/_800x550_crop_center-center_none/2L3A0137.jpg?stamp=2602070942&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4523044-franciscus'
