insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Harrie', 'Maak kennis met Harrie – een gezellige Husky van 6 jaar met energie voor tien en een neus die standaard op standje ontdekkingstocht staat. Harrie volgt in het leven vooral zijn neus… en zijn ogen doen dapper hun best om bij te blijven. Tijdens het wandelen zigzagt hij vrolijk door de wereld, want ja: er is zóveel te ruiken. Net zo eerlijk: Harrie loopt graag met overtuiging aan de riem. Trekken hoort daar voorlopig nog bij — hij ziet wandelen als een teamsport waarbij hij de leiding neemt.
Ondanks zijn 6 lentes is Harrie nog lang niet toe aan een rollator en zijn de geraniums veilig achtergelaten bij het tuincentrum. Stilzitten is niet zijn hobby. Deze jongen wil bewegen! Hardlopen? Top. Fietsen? Ook goed — Harry rent er met liefde naast. Ben jij een fervent skeeler? Dan zit je met Harrie helemaal snor en ga je sneller dan een snorfiets. Hij tilt je met gemak naar een hoger niveau. En heb je een tuin? Dan heeft Harrie nog een extra hobby: graven. Verwacht geen strak gazon, maar wel een hond die met volle overgave aan zijn “archeologische projecten” werkt.
In het begin zal je even je beste beentje voor moeten zetten om contact met hem te maken. Maar eerlijk is eerlijk: dat maakt het juist leuk. Zie hoe jullie band groeit terwijl jullie samen trainen, oefenen en successen vieren. Met een buideltje trainer snacks, wat tijd en geduld kom je een heel eind (oké… vooral met die snacks).
Kleine kanttekening: botjes zijn écht van Harrie. Kauwstaven ziet hij als zijn persoonlijke prooi en die deelt hij niet graag. Voerbaknijd? Nee hoor. Alleen bij botjes geldt: handen thuis, dit is van mij.
Kleine kinderen en Harrie zijn geen ideale match. Kinderen vanaf 12 jaar passen beter bij zijn energie en grenzen.
Met teven gaat Harrie doorgaans prima. Met reuen heeft hij nog wat huiswerk te doen — daar valt voor hem nog het nodige te leren.
Voor Harrie zoeken we een actief huishouden waar tijd, aandacht en beweging geen probleem zijn. Zijn energie moet eruit: lekker fysiek bezig zijn is een must. Hersenwerk is een mooie bonus, maar pas als zijn lijf tevreden is, is Harrie dat ook. En geloof ons: een tevreden Harrie is een tevreden baas.
Zin om deze spring-in-’t-veld te ontmoeten? Dan zien we je graag! En wie weet verovert hij al snel een speciaal plekje bij je… met de bijnaam “hartje”. Kijk goed — dat hartje vind je zelfs terug in zijn vacht. 💛
Wij vragen je alleen te reageren via de mail, met een uitgebreide persoonlijke toelichting en motivatie. Als je via de “bezoek plannen” knop reageert, kunt je de gewenste informatie vermelden bij de toelichting. Op reacties zonder toelichting wordt niet gereageerd.
Een hond kies je niet zomaar, wij hebben dan ook een strenge selectie voor onze asielhonden. Houd er daarom rekening mee dat een hond tijdens de eerste kennismaking nog niet geplaatst wordt. Per dier kijken we hoe vaak het noodzakelijk is om terug te komen. De afspraken worden in overleg en in kort tijdsbestek ingepland. Ook willen wij kennismaken met het gehele gezin, inclusief de eventuele al aanwezige hond(-en). Op het asiel krijgen jullie alle tijd om kennis te maken, te gaan wandelen en vragen te stellen.
Na een positieve kennismaking worden er vervolgafspraken gemaakt.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/4533127/Harrie18.jpg?stamp=2602102008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4533127/Harrie18.jpg?stamp=2602102008&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4533127/Harrie18.jpg?stamp=2602102008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4533127/Harrie18.jpg?stamp=2602102008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4533128/Harrie19.jpg?stamp=2602102008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520176/harrie1.jpg?stamp=2601262102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4533126/Harrie17.jpg?stamp=2602102008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520189/harrie14.jpg?stamp=2601262103&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520184/harrie9.jpg?stamp=2601262102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520183/harrie8.jpg?stamp=2601262102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520182/harrie7.jpg?stamp=2601262102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520180/harrie5.jpg?stamp=2601262102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520179/harrie4.jpg?stamp=2601262102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520177/harrie2.jpg?stamp=2601262102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4520185/harrie10.jpg?stamp=2601262102&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4520171-harrie'
from public.shelters s
where s.name = 'Dierencentrum Achterhoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4520171-harrie')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Kaya', 'Dit is Kaya een heerlijke Duitse herder meid van 5 jaar oud. Ze is bij ons in het asiel terecht gekomen omdat haar baasje helaas door medische redenen niet meer voor haar kon zorgen. Helaas door deze situatie heeft Kaya een sexy mollig figuur gekregen. Uiteraard gaan we in de opvang hier al een start in maken maar de nieuwe eigenaar zal hier mee verder moeten. 
Kaya heeft in haar leven niet altijd de juiste socialisatie gehad en heeft een lange periode vooral achter in een tuin gewoond. Hierdoor vindt ze de wereld buiten soms nog best spannend. Als haar emmertje vol raakt, kan ze daarop reageren door uit te vallen. Gelukkig zien we hier in de opvang al enorme vooruitgang: Kaya is leergierig, pakt training goed op en het wandelen gaat steeds beter. Ze maakt al fijn contact en trekt een stuk minder aan de lijn. Toch is ze er nog niet helemaal en heeft ze iemand nodig die haar hierin verder wil begeleiden.
Voor Kaya zoeken we een rustige woonplek, bij voorkeur aan de rand van een wijk of vrijstaand, zodat ze minder snel overprikkeld raakt. Haar ideale baasje heeft ervaring met honden zoals zij en is bereid om tijd, geduld en liefde in haar te investeren.Ben jij de herder fanaat die wij zoeken voor onze sexy mollige Kaya, en geeft je haar een kans om verder te groeien ? Mail dan snel naar het asiel.
KENNISMAKEN MET DEZE HOND?
Leuk! We zien je reactie graag tegemoet. Stuur ons een zo uitgebreid mogelijke mail met:
je naam, adres, woonplaats en telefoonnummerinformatie over de gezinssamenstelling (indien kinderen, de leeftijden)woonsituatie (beneden of boven, tuin/balkon, trap/lift)de werksituatie/werktijdende ervaring met hondende eventuele andere aanwezige huisdieren.Eventuele vakantieplannen op korte termijn: We hebben geen mogelijkheid om een dier tot na de vakantie vast te houden en adviseren om pas na de vakantie op zoek te gaan naar een nieuwe huisgenoot.
Mailen kan naar info.vlaardingen@dierenbescherming.nl. We verzoeken om alle hierboven gevraagde gegevens in 1 mail te sturen. We krijgen vaak meerdere mailtjes voor een dier en we maken een eerste selectie op basis van de informatie die in de mail is gegeven. We nodigen mensen telefonisch uit voor een kennismaking. Het is niet mogelijk om zonder uitnodiging langs te komen om bij de honden te kijken.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_330x285_crop_center-center_none/Kaya.jpg?stamp=2605041445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/Kaya.jpg?stamp=2605041445&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/Kaya.jpg?stamp=2605041445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Kaya.jpg?stamp=2605041445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/20260504_102237_resized.jpg?stamp=2605041445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1199.jpeg?stamp=2603160956&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1168.jpeg?stamp=2603160957&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1155.jpeg?stamp=2603160959&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1188.jpeg?stamp=2603160957&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1226.jpeg?stamp=2603161002&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/Kaya.jpg?stamp=2605041445&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/Kaya.jpg?stamp=2605041445&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Kaya.jpg?stamp=2605041445&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/20260504_102237_resized.jpg?stamp=2605041445&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1199.jpeg?stamp=2603160956&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4504530-kaya'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4504530-kaya')
limit 1;

