select s.id, 'Spijkenisse', 'Connor (met filmpje)', 'Lieve angsthaas zoekt eigen terrein', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_330x285_crop_center-center_none/IMG-20260420-WA0005_2026-04-20-120450_wtxo.jpg?stamp=2604201404&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260420-WA0005_2026-04-20-120450_wtxo.jpg?stamp=2604201404&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260420-WA0005_2026-04-20-120450_wtxo.jpg?stamp=2604201404&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0005_2026-04-20-120450_wtxo.jpg?stamp=2604201404&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20250922-WA0072.jpg?stamp=2509241229&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0014_2026-04-20-120453_dhyf.jpg?stamp=2604201406&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0010_2026-04-20-120452_zcng.jpg?stamp=2604201404&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20251001-WA0040.jpg?stamp=2510011521&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20250728-WA0008.jpg?stamp=2507281455&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0008_2026-04-20-120451_ddea.jpg?stamp=2604201407&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20250724-WA0012.jpg?stamp=2507241456&tag=xs', 'https://cm