insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Bella (muizenvanger)', 'Dit is Bella! Onze pittige dame van 12 jaar jong die heel goed weet wat ze wel en vooral niet wil. Knuffelhond? Nee hoor, daar doet Bella niet aan. Ze is meer van kijk maar, maar raak me niet aan mentaliteit. En eerlijk gezegd, dat maakt haar stiekem gewoon een baas.Bella is terug in de opvang omdat haar grenzen niet werden gerespecteerd en geloof ons, deze dame kan dat heel duidelijk maken. Dus heb jij respect voor persoonlijke ruimte en vind je het prima als een hond zelf het tempo bepaalt? Dan zou Bella zomaar jouw nieuwe huisgenoot kunnen zijn!Bella zoekt een rustig huisje met een tuin waar ze haar ronde kan doen. Mensen die niet constant willen knuffelen, maar haar accepteren zoals ze is. Iemand die haar nog wat mooie, rustige jaren wil geven.Ze staat op dieetvoer - er mag een kilootje vanaf. Ze krijgt ook gedragsmedicatie, want zelfs de grootste diva kan wel eens wat ondersteuning gebruiken. Bella is dus geen hond voor iedereen. Maar voor de juiste persoon wordt ze jouw meest eigenzinnige, grappige en onafhankelijke huisgenoot.Durf jij samen te wonen met een pittige tante die de boel graag op haar eigen manier regelt? Stuur een mail naar limburg@dierenbescherming.nl en kom kennis maken met Bella!', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Bella-6-3.jpg?stamp=2603061659&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Bella-6-3.jpg?stamp=2603061659&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Bella-6-3.jpg?stamp=2603061659&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Bella-6-3.jpg?stamp=2603061659&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Bella-Valentijn.png?stamp=2602091059&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/PSX_20250715_215816.jpg?stamp=2509261251&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/PSX_20250715_220100.jpg?stamp=2509261251&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/20250715_152426.jpg?stamp=2509261251&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/PSX_20250715_215608.jpg?stamp=2509261251&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/20250715_152141.jpg?stamp=2509261252&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Bella-kerst.jpg?stamp=2512221006&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Bella-6-3.jpg?stamp=2603061659&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Bella-6-3.jpg?stamp=2603061659&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Bella-6-3.jpg?stamp=2603061659&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Bella-Valentijn.png?stamp=2602091059&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4399273-bella'
