insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Jeff', 'Jeff zoekt zijn eigen plek!
Deze actieve jongen houdt van rennen, spelen en vooral van een potje ballen gooien op de speelweide.Hij is gehoorzaam en luistert goed. Hij loopt netjes aan de riem. Jeff is alert en reageert op zijn omgeving. Wanneer een andere hond uitvalt, kan Jeff hierop reageren. Met de juiste begeleiding en rust blijft dit goed hanteerbaar.Jeff is geen hond die zich zomaar de kaas van het brood laat eten. Hij weet wat hij wil en laat zich niet zomaar iets vertellen. Deze knappe jongen heeft een sterk karakter en zoekt iemand die hem begrijpt en grenzen op een rustige manier kan aangeven.Ben jij klaar voor deze trouwe en sportieve viervoeter? Stuur dan een mail naar limburg@dierenbescherming.nl en wie weet tot snel!', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Jeff-1.jpg?stamp=2507181306&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Jeff-1.jpg?stamp=2507181306&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Jeff-1.jpg?stamp=2507181306&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-1.jpg?stamp=2507181306&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-Valentijn.png?stamp=2602091103&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-kerst.jpg?stamp=2512221008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-2.jpg?stamp=2507181307&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-3.jpg?stamp=2507181306&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-4.jpg?stamp=2507181307&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-5.jpg?stamp=2507181307&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Jeff-1.jpg?stamp=2507181306&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Jeff-1.jpg?stamp=2507181306&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-1.jpg?stamp=2507181306&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-Valentijn.png?stamp=2602091103&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jeff-kerst.jpg?stamp=2512221008&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4315730-jeff'
