insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Snoop', 'Let op! Snoop verblijft sinds kort in het asiel van Hart van Brabant! 
Bij interesse kunt u de vragenlijst invullen en deze naar ons mailen. Of bel direct met Hart van Brabant op: 0135435209
Maak kennis met de knappe en imposante Snoop!
Snoop is een prachtige reu van 5 jaar oud die door privé omstandigheden van de eigenaar bij ons terecht is gekomen. Hij is een bijzondere hond met een groot hart, die op zoek is naar een liefdevol thuis waar hij helemaal zichzelf mag zijn.
Van origine komt Snoop uit Griekenland, als jonge pup is hij naar Nederland gekomen. De berghond-roots zijn nog wel duidelijk in zijn gedrag en karakter te herkennen: hij is enorm trouw aan zijn baas, en beschermt zijn territorium met alles wat hij in zich heeft. Een drukke woonwijk of een huis met regelmatig visite is dan ook niet aan hem besteed. Is hij eenmaal van zijn eigen terrein af, dan is hij veel toegankelijker en warmt hij vrij snel op bij nieuwe mensen. Kent hij je eenmaal goed en heeft hij de tijd gehad je te leren kennen, dan heb je er een hele loyale en aanhankelijke vriend bij. Zijn hart winnen is goud waard, hij is dan een echte knuffelkont!
Wandelen doet hij ontzettend graag. Hij loopt rustig mee en luistert goed. Rennen in de buitenlucht vindt hij fantastisch, en lekker ravotten in de tuin is ook echt zijn ding. Een tuin is voor Snoop dan ook een echte must – hij geniet met volle teugen van het buitenleven. Rollen in het gras, spelen met zijn favoriete touwspeeltje of samen touwtrekken met zijn baasje: het maakt hem dolgelukkig. Ook kan hij met de meeste andere honden goed overweg en speelt hij enthousiast samen. Hij is niet echt gediend van een enorme druktemaker, maar een redelijk rustige soortgenoot om af en toe een sprintje mee te trekken kan hij erg waarderen.
Vanwege zijn waakse aard plaatsen we Snoop niet bij jonge kinderen. Hij heeft een sterk beschermend instinct en bewaakt graag zijn huis en zijn mensen. Dit is niet passend in een jong gezin met eventuele vriendjes die over de vloer komen e.d. Snoop heeft een voorkeur voor mensen van het vrouwelijk geslacht, maar kan na rustig wennen ook prima bij een man worden geplaatst. Met name is het belangrijk dat er rekening wordt gehouden met zijn waaksheid en dat dit veilig kan doen in de omgeving waar hij terecht komt.
Ben jij op zoek naar een trouwe kameraad met karakter, die van beweging, gezelligheid en heel veel knuffelen houdt? Dan zou Snoop zomaar jouw perfecte match kunnen zijn!
 interesse na het lezen van de beschrijving? Vul onderstaande vragenlijst in en mail deze naar info@dierenasielutrecht.nl, wij nemen dan contact met u op.
Let op, op mail zonder vragenlijst kunnen wij niet reageren! - Heeft u eerder een hond gehad, wat voor ras?- Waarom kiest u voor deze hond/dit ras?- Hoe woont u (flat/vrijstaand/boerderij)?- Heeft u momenteel een hond? (ras/geslacht/leeftijd)?- Wat is de gezinssamenstelling (kinderen of kinderwens/dieren)?- Hoelang en hoe vaak moet de hond wekelijks alleen zijn?- Wat bent u van plan om, buiten wandelen om, met de hond te doen?- Adres en contactgegevens:', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Snoop-sneeuw.jpg?stamp=2601081007&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Snoop-sneeuw.jpg?stamp=2601081007&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Snoop-sneeuw.jpg?stamp=2601081007&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Snoop-sneeuw.jpg?stamp=2601081007&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Snoop-2_2025-05-01-100145_ishb.jpg?stamp=2505011201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Snoop-6.jpeg?stamp=2604181531&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/snoop-2_2026-04-18-133215_dddn.jpg?stamp=2604181532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/snoop-5.jpg?stamp=2604181531&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Snoop-3.jpg?stamp=2511171426&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Snoop-sneeuw.jpg?stamp=2601081007&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Snoop-sneeuw.jpg?stamp=2601081007&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Snoop-sneeuw.jpg?stamp=2601081007&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Snoop-2_2025-05-01-100145_ishb.jpg?stamp=2505011201&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Snoop-6.jpeg?stamp=2604181531&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/snoop-2_2026-04-18-133215_dddn.jpg?stamp=2604181532&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4237597-snoop'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4237597-snoop')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Zec', 'Helaas is Zec bij ons teruggekomen, omdat de plaatsing niet de juiste match bleek te zijn.
Meet Zec, onze vriendelijke reus van 8 jaar jong! Deze grote jongen heeft een hart van goud en een ego dat denkt dat hij een schoothond is (tip: probeer het niet, tenzij je een sterke bank hebt). Knuffels incasseren? Geen enkel probleem—hij is een professionele knuffelmagnaat in opleiding.
Zijn skills:
Vangt ballen alsof het zijn lust en leven is en plukt deze nog met gemak uit de lucht.Kent zijn commando’s op zijn duimpje en voert de meeste ook netjes uit (voor een koekje misschien allemaal 😉).Kan prima even alleen thuis blijven, al mist hij je dan stiekem wel.Zijn oren staan altijd in standje luister, dus je voelt je heerlijk gehoord... tenminste, dat hoop je!
De fijne kneepjes:Zec is een krachtpatser, dus wandelen aan de lijn is... laten we zeggen, een team effort. Het ligt eraan wie de leiding neemt. 
Zec kan niet overweg met soortgenoten.
🏡 Een groot huis waar hij de ruimte heeft.🌳 Een tuin zou een verrijking zijn voor deze actieve beer.🚫 Geen trappen, want Zec is een grote jongen van middelbare leeftijd.🐱 Hij heeft met katten samengeleefd, maar om het soepel te laten verlopen zoeken we in eerste instantie een thuis zonder katten.
Let op, heren!Zec heeft wat tijd nodig om aan mannen te wennen. Maar heb je eenmaal zijn vertrouwen, dan kun je op hem rekenen—voor altijd.
Wat zoekt Zec?Een warm thuis waar hij zijn energie kwijt kan en hij af en toe zijn waakse talenten mag inzetten. Als je ballen kunt gooien, een beetje spieren hebt voor de riem, en zijn liefde én lompe knuffels aankunt, ben jij misschien wel de match voor Zec!
Interesse? Kom kennismaken met Zec en laat hem jouw hart stelen (of je bal, net wat je in je hand hebt).
Wij vragen je alleen te reageren via de mail, met een uitgebreide persoonlijke toelichting en motivatie. Als je via de “bezoek plannen” knop reageert, kunt je de gewenste informatie vermelden bij de toelichting. Op reacties zonder toelichting wordt niet gereageerd. 
Een hond kies je niet zomaar, wij hebben dan ook een strenge selectie voor onze asielhonden. Houd er daarom rekening mee dat een hond tijdens de eerste kennismaking nog niet geplaatst wordt. Per dier kijken we hoe vaak het noodzakelijk is om terug te komen. De afspraken worden in overleg en in kort tijdsbestek ingepland. Ook willen wij kennismaken met het gehele gezin, inclusief de eventuele al aanwezige hond(-en). Op het asiel krijgen jullie alle tijd om kennis te maken, te gaan wandelen en vragen te stellen. 
Na een positieve kennismaking worden er vervolgafspraken gemaakt.', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/4168788/Zec7.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4168788/Zec7.jpg?stamp=2502022052&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4168788/Zec7.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168788/Zec7.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168783/Zec2.jpg?stamp=2502051410&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168787/Zec6.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168789/Zec8.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168790/Zec9.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168791/Zec10.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168786/Zec5.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168785/Zec4.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168784/Zec3.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4168782/Zec1.jpg?stamp=2502022052&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4168788/Zec7.jpg?stamp=2502022052&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4168788/Zec7.jpg?stamp=2502022052&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4168781-zec'
from public.shelters s
where s.name = 'Dierencentrum Achterhoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/4168781-zec')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Boelie *Asiel Genk*', 'Deze knappe man is een kruising Akita met Amerikaanse Stafford. Hij is geboren in januari 2020. Zijn vorige eigenaar wilde hem na 6 dagen niet meer bij zich houden.
Boelie is een actieve hond die graag dingen onderneemt. Toen hij hier binnenkwam, wist Boelie absoluut niet wat hij moest doen, hoe zich te gedragen en wat te verwachten. Er is in het asiel hard gewerkt aan zijn etiquette en tijdens het project Belgian Cell Dogs bleek Boelie een voorbeeldstudent te zijn. Zodra hij een band heeft met mensen heeft Boelie zin om te werken! Boelie heeft ook al geleerd om na te denken op momenten dat hij gefrustreerd wordt, daar waar hij voorheen kon happen. Hij heeft hier enorme vooruitgang in geboekt. We zijn dan ook heel enthousiast over zijn leervermogen!
Favoriete bezigheden van deze vent zijn spelen en voerspelletjes. Momenten van aaien vindt hij ook fijn, maar Boelie is liever bezig met snuffelen, apporteren of snoepen. Oh, en als hobby is er ook nog zwemmen, of pootje baden. Zijn lijstje van favoriete bezigheden wordt afgesloten met een rustige wandeling.Boelie is een hele leergierige en voedselgerichte hond. Hij kent inmiddels de commando’s ‘zit’, ‘poot’ en ‘kom hier’.
We zoeken voor Boelie een huis met een tuin. Zijn toekomstige baasje is het best in het begin meer thuis om hem te begeleiden. Oudere kinderen kunnen een optie voor hem zijn. Hij wordt helaas niet bij andere dieren geplaatst.Heeft u interesse in Boelie? Neem dan contact met ons op.
Deze hond heeft meegedaan aan het programma van Belgian Cell Dogs, waarbij gedetineerden trainen met asielhonden om zodoende de adoptiekansen van de honden te verhogen. De honden leren gedurende 8 weken commando’s en gewenst gedrag te vertonen.
LET OP! Deze hond verblijft bij onze collega''s van dierenasiel Genk. Heb je interesse en wil je graag kennismaken met Boelie? neem dan contact op met dierenasiel Genk.
Telefoon : 0032-89 35 70 09
Email: info@dierenasielgenk.be

Adres: Europalaan 13, 3600 Genk', 'dog', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Boelie_2024-09-04-081334_lnyk.png?stamp=2409041013&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Boelie_2024-09-04-081334_lnyk.png?stamp=2409041013&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Boelie_2024-09-04-081334_lnyk.png?stamp=2409041013&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Boelie_2024-09-04-081334_lnyk.png?stamp=2409041013&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/boelie.jpg?stamp=2306301432&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/boelie2.jpg?stamp=2306301432&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/boelie1.jpg?stamp=2306301432&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Boelie_2024-09-04-081334_lnyk.png?stamp=2409041013&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Boelie_2024-09-04-081334_lnyk.png?stamp=2409041013&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Boelie_2024-09-04-081334_lnyk.png?stamp=2409041013&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/boelie.jpg?stamp=2306301432&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/boelie2.jpg?stamp=2306301432&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/boelie1.jpg?stamp=2306301432&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/3338615-boelie'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/honden/3338615-boelie')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Hecate', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1192707-Hecate-8.jpg?stamp=2605081509&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1192707-Hecate-8.jpg?stamp=2605081509&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1192707-Hecate-8.jpg?stamp=2605081509&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192707-Hecate-8.jpg?stamp=2605081509&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192707-Hecate-5.jpg?stamp=2605081459&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192707-Hecate-6.jpg?stamp=2605081459&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192707-Hecate-7.jpg?stamp=2605081459&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1192707-Hecate-8.jpg?stamp=2605081509&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1192707-Hecate-8.jpg?stamp=2605081509&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192707-Hecate-8.jpg?stamp=2605081509&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192707-Hecate-5.jpg?stamp=2605081459&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192707-Hecate-6.jpg?stamp=2605081459&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192707-Hecate-7.jpg?stamp=2605081459&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4593198-hecate'
