insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', 'Pim en Pom', 'We stellen heel graag Pim en Pom aan u voor
Helaas kon het baasje van deze twee lieve katten, broer en zus, er niet meer voor zorgen. Zodoende zijn ze bij ons in het asiel terecht gekomen. Beide katten gaan heel leuk met elkaar om. Ze wassen elkaar zelfs. Pim is de cyperse kater, hij vindt iedereen leuk. Pom is in eerste instantie wat terughoudender. Maar als zij je eenmaal kent dan komt ze ook naar je toe. Omdat ze een rustig huishouden gewend zijn zoeken wij dit ook weer voor hun. Ze zijn nog nooit buiten geweest en zoeken dan ook weer een plek waar ze niet naar buiten hoeven.
Wie geeft Pim en Pom een nieuwe start?', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_330x285_crop_center-center_none/pp.jpg?stamp=2605081431&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_384x330_crop_center-center_none/pp.jpg?stamp=2605081431&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_519x453_crop_center-center_none/pp.jpg?stamp=2605081431&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/pp.jpg?stamp=2605081431&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/ppim.jpg?stamp=2605081428&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Pim1.jpg?stamp=2605081428&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/pimm.jpg?stamp=2605081429&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_384x330_crop_center-center_none/pp.jpg?stamp=2605081431&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_519x453_crop_center-center_none/pp.jpg?stamp=2605081431&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/pp.jpg?stamp=2605081431&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/ppim.jpg?stamp=2605081428&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Pim1.jpg?stamp=2605081428&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/pimm.jpg?stamp=2605081429&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_882x1004_crop_center-center_none/banner-beeld-hond-close-885.png?stamp=2504161034&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4604365-pim-en-pom'
from public.shelters s
