insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Zephyros', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.
Zephyros is een gezellige en aanwezige huisgenoot die graag in de buurt van zijn mensen is. Een echte persoonlijkheid dus: sociaal, nieuwsgierig en altijd betrokken bij wat er in huis gebeurt.
Zoals het een echte kater betaamt, heeft hij ook een duidelijke eigen wil. Wanneer zijn grenzen niet gerespecteerd worden, kan hij dat laten merken door zijn pootjes te laten wapperen. Geef je hem de ruimte en begrijp je zijn signalen, dan krijg je daar een ontzettend lieve en gezellige kat voor terug die graag onderdeel is van het gezin.
Deze energieke jongen heeft wel de mogelijkheid nodig om naar buiten te kunnen. Daar kan hij zijn energie kwijt, op ontdekkingstocht gaan en lekker zijn eigen ding doen.
Vanwege zijn soms wat onvoorspelbare gedrag plaatsen we hem alleen bij kinderen boven de 12 jaar. De verwachting is dat Zephyros het beste uit de verf komt als hij het rijk voor zich alleen heeft. We plaatsen hem dus niet bij andere katten. 
Bent u iemand die katten begrijpt en op zoek is naar een gezellige kameraad met karakter? Dan zou deze bijzondere kater zomaar de perfecte match kunnen zijn. 
Pas als uw (compleet) ingevulde formulier binnen is wordt uw aanvraag in behandeling genomen. We zullen dan kijken of u een geschikte match bent voor het dier en dan zullen we u hopelijk telefonisch uitnodigen voor een ontmoeting. Ontmoetingen vinden alleen op afspraak plaats. We kunnen dieren maximaal 1 week "reserveren". (datum van inplannen afspraak tot datum kennismaking).', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_330x285_crop_center-center_none/1193223-Zephyros.jpg?stamp=2604301051&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_384x330_crop_center-center_none/1193223-Zephyros.jpg?stamp=2604301051&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_519x453_crop_center-center_none/1193223-Zephyros.jpg?stamp=2604301051&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_800x550_crop_center-center_none/1193223-Zephyros.jpg?stamp=2604301051&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_384x330_crop_center-center_none/1193223-Zephyros.jpg?stamp=2604301051&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_519x453_crop_center-center_none/1193223-Zephyros.jpg?stamp=2604301051&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_800x550_crop_center-center_none/1193223-Zephyros.jpg?stamp=2604301051&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4597062-zephyros'
from public.shelters s
where s.name = 'De Kuipershoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4597062-zephyros')
