insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Arcas', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1193040-Arcas.jpg?stamp=2605051620&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1193040-Arcas.jpg?stamp=2605051620&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1193040-Arcas.jpg?stamp=2605051620&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193040-Arcas.jpg?stamp=2605051620&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1193040-Arcas.jpg?stamp=2605051620&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1193040-Arcas.jpg?stamp=2605051620&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193040-Arcas.jpg?stamp=2605051620&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592086-arcas'
from public.shelters s
where s.name = 'De Kuipershoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592086-arcas')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Dido', 'Dido is een poezendametje van 2 jaar oud. Ze is als zwervertje gevonden. Dido is angstig en heeft tijd nodig om te wennen. Ze vind alles ontzettend spannend!
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Dido.png?stamp=2605061118&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Dido.png?stamp=2605061118&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Dido.png?stamp=2605061118&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Dido.png?stamp=2605061118&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Dido.png?stamp=2605061118&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Dido.png?stamp=2605061118&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Dido.png?stamp=2605061118&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601361-dido'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601361-dido')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Boaz (FIV +, binnenkat)', 'Boaz is een kater van 3 jaar oud die als zwervertje is gevonden. Een lieve kerel, maar bang. Hij vindt het allemaal maar spannend.
Helaas is hij aidspositief, geen doodvonnis. Maar hij moet wel goed verzorgd worden en mag niet meer vrij buiten rondlopen.
Wat is kattenaids?Kattenaids is een 
virusziekte die het afweersysteem van een kat aantast. Het is niet 
besmettelijk voor mensen of andere dieren, alleen voor katten onderling.
 Er is geen geneesmiddel of medicijn voor kattenaids. Belangrijk is dat 
de katten een zo stressvrij mogelijk leven lijden en niet meer vrij 
buiten mogen rondlopen. Indien ze dus goed verzorgd worden hebben ze een
 goede levensverwachting. De meeste aidskatten overlijden eerder door 
ouderdom of andere problemen dan door de aids.

Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Boaz.png?stamp=2605061119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Boaz.png?stamp=2605061119&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Boaz.png?stamp=2605061119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Boaz.png?stamp=2605061119&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Boaz.png?stamp=2605061119&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Boaz.png?stamp=2605061119&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Boaz.png?stamp=2605061119&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601359-boaz-fiv-binnenkat'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601359-boaz-fiv-binnenkat')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Gouda', 'Cheddar', 'Cheddar, een zacht kaasje met een knapperig randje. Ja, net als de kaas. En net als een goede cheddar geldt ook hier: even laten rijpen… en dan wordt het alleen maar beter. Cheddar kwam wat schuw binnen en dacht eerst: “Mensen? Nee bedankt.” 
Maar… terwijl hij dat dacht, liet hij zich stiekem toch gewoon aaien. En nog een keer. En nog een keer. ‘Oeh, toch wel lekker dat gekriebel onder m''n kinnetje. Ow ik ga nu spontaan kneden en he m''n bips schiet opeens omhoog’. Kortom: hij is niet zo stoer als hij zelf denkt. Onder dat voorzichtige laagje zit namelijk gewoon een onzeker mannetje dat eigenlijk best graag wil… maar het nog niet helemaal durft toe te geven. Een beetje zoals kaas die eerst nog hard lijkt, maar uiteindelijk gewoon zacht wordt als je hem de tijd geeft. Wat hij nodig heeft? Een heel rustig huis met tuin, zonder kinderen, waar hij in zijn eigen tempo mag ontdooien (of eh… ontsmelten). Want als je Cheddar die ruimte geeft, dan komt hij vanzelf. Misschien eerst een beetje aarzelend. Misschien met kleine stapjes. Maar wel oprecht. En geloof ons, als hij eenmaal vertrouwen heeft, dan heb je geen blok kaas meer… maar een zacht, smeltend knuffelkaasje in huis. Tijdens zijn verblijf bij ons is hij behandeld aan zijn gebit. Vrijdag volgt nog een controle, maar daarna is hij klaar om te vertrekken naar zijn nieuwe huisje.  
Het is niet mogelijk om zonder afspraak naar onze katten te komen kijken. Om er zeker van te zijn dat u en de kat een goede match zijn, verzoeken we u vriendelijk de algemene vragenlijst zo uitgebreid mogelijk te beantwoorden en te mailen naar gouda@dierenbescherming.nl .
Wat zijn uw naam en telefoonnummer?Vertel iets over uw gezinssituatie. Wat zijn de leeftijden van alle gezinsleden?Zijn er andere dieren in huis en zijn deze katten gewend? En wat zijn de leeftijden?Vertel iets over uw woonsituatie, Wat voor soort woning heeft u en heeft deze een balkon of een tuin?Wat zijn uw verwachtingen van de kat?Welke tijd en dagen bent u beschikbaar voor kennismaking?Gaat u binnenkort met vakantie?', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_330x285_crop_center-center_none/3_2026-05-05-120111_ztrr.jpg?stamp=2605051442&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_384x330_crop_center-center_none/3_2026-05-05-120111_ztrr.jpg?stamp=2605051442&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_519x453_crop_center-center_none/3_2026-05-05-120111_ztrr.jpg?stamp=2605051442&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/3_2026-05-05-120111_ztrr.jpg?stamp=2605051442&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/1_2026-05-05-120110_howo.jpg?stamp=2605051442&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/2_2026-05-05-120110_ekam.jpg?stamp=2605051401&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_384x330_crop_center-center_none/3_2026-05-05-120111_ztrr.jpg?stamp=2605051442&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_519x453_crop_center-center_none/3_2026-05-05-120111_ztrr.jpg?stamp=2605051442&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/3_2026-05-05-120111_ztrr.jpg?stamp=2605051442&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/1_2026-05-05-120110_howo.jpg?stamp=2605051442&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/2_2026-05-05-120110_ekam.jpg?stamp=2605051401&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301136&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601192-cheddar'
from public.shelters s
where s.name = 'Dierenopvangcentrum Gouda'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601192-cheddar')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Noor', 'Noor is een bang dametje van 2 jaar oud. Ze is als zwervertje gevonden en helaas niet opgehaald door de baas. Noor vind het asiel maar spannend. Ze weet niet wat haar is overkomen.
We zoeken voor Noor een baasje met liefde, geduld en kattenervaring.
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Noor_2026-05-06-092030_yuwj.png?stamp=2605061120&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Noor_2026-05-06-092030_yuwj.png?stamp=2605061120&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Noor_2026-05-06-092030_yuwj.png?stamp=2605061120&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Noor_2026-05-06-092030_yuwj.png?stamp=2605061120&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Noor_2026-05-06-092030_yuwj.png?stamp=2605061120&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Noor_2026-05-06-092030_yuwj.png?stamp=2605061120&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Noor_2026-05-06-092030_yuwj.png?stamp=2605061120&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601200-noor'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601200-noor')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Gouda', 'Forest', 'Forest betekent letterlijk bos, en dat klopt ook wel een beetje. Deze knappe langharige kater van 5 jaar heeft namelijk een tijd rondgelopen bij een recreatiepark, alsof hij zijn eigen natuurdocumentaire aan het opnemen was. Na een jaar “Into the Wild” (maar dan zonder camera) is het eindelijk gelukt om hem te vangen. En wat blijkt? Helemaal geen ruige bosbaas… maar een onzeker, lief mannetje dat eigenlijk gewoon dacht: “Ik doe wel stoer, maar iemand mag me best aaien hoor.” Forest is een beetje zoals een echt bos: 
In het begin stil en mysterieus… maar als je er rustig doorheen wandelt, ontdek je hoe mooi en zacht het eigenlijk is. Hij houdt van aandacht en zachte aaitjes, maar wel op een rustige manier. Geen drukte, geen hectiek, Forest is meer van het type zen-wandeling dan festival in het park.  
Wat hij zoekt: Een rustig huis met tuin (een klein privé-bosje zou hij top vinden), geen kleine kinderen en iemand die begrijpt dat hij even moet wennen. 
Andere dieren in huis? Dat is nog een mysterie, net als een onbekend pad in het bos. 
En dan zijn vacht… Ja, meneer heeft een prachtige lange jas. Maar zoals bij elk bos geldt: 
Af en toe onderhoud is nodig. Denk: klitten voorkomen voordat het een compleet natuurgebied wordt. Kortom: Forest is geen wilde tijger, maar een zachte bosbewoner die op zoek is naar rust, liefde en iemand die hem helpt om zijn leven weer een beetje… gecultiveerd te maken. 
Geef je hem de tijd, dan groeit hij uit tot jouw eigen rustige, spinnende stukje natuur in huis.In de opvang heeft Forest een gebitsbehandeling gekregen, na controle zou hij vanaf vrijdag naar zijn nieuwe huisje mogen vertrekken. Uiteraard kan hij eventueel wel al eerder bezoek ontvangen.Ook zat zijn mooie lange vacht wat ''in de war'' door zijn avonturen. De klitten zijn voorzichtig weggeschoren. 
Het is niet mogelijk om zonder afspraak naar onze katten te komen kijken. Om er zeker van te zijn dat u en de kat een goede match zijn, verzoeken we u vriendelijk de algemene vragenlijst zo uitgebreid mogelijk te beantwoorden en te mailen naar gouda@dierenbescherming.nl .
