assets/dierenopvangcentrumGouda/_384x330_crop_center-center_none/2_2026-05-05-122327_ghqh.jpg?stamp=2605051447&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_519x453_crop_center-center_none/2_2026-05-05-122327_ghqh.jpg?stamp=2605051447&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/2_2026-05-05-122327_ghqh.jpg?stamp=2605051447&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/5_2026-05-05-122329_kzhi.jpg?stamp=2605061323&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/3_2026-05-05-122328_tmug.jpg?stamp=2605051423&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601159-forest'
from public.shelters s
where s.name = 'Dierenopvangcentrum Gouda'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4601159-forest')
