insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Damian', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1193127-Damian-3.jpg?stamp=2605051605&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1193127-Damian-3.jpg?stamp=2605051605&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1193127-Damian-3.jpg?stamp=2605051605&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193127-Damian-3.jpg?stamp=2605051605&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193127-Damian-2.jpg?stamp=2605051605&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193127-Damian-4.jpg?stamp=2605051605&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1193127-Damian-3.jpg?stamp=2605051605&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1193127-Damian-3.jpg?stamp=2605051605&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193127-Damian-3.jpg?stamp=2605051605&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193127-Damian-2.jpg?stamp=2605051605&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193127-Damian-4.jpg?stamp=2605051605&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592104-damian'
from public.shelters s
where s.name = 'De Kuipershoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592104-damian')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Spijkenisse', 'Joep & Joris', 'Joep en Joris ( wit melk snorretje) zijn twee prachtige rood-witte gecastreerde katers van 9 jaar oud . Deze heren hebben hun leven samen doorgebracht en zijn dan ook echt onafscheidelijk. Helaas is hun eigenaar overleden, waardoor ze samen in het asiel zijn terechtgekomen. Een grote verandering, die ze duidelijk nog aan het verwerken zijn.
 Beide katers hebben op zijn zachtst gezegd een maatje meer, dus het is belangrijk dat ze in hun nieuwe thuis rustig en geleidelijk wat kilo’s kwijt kunnen raken. Dit vraagt om een beetje toewijding, aangepast voer en vooral geduld.
Joris is bekend met blaasgruis en krijgt hiervoor speciaal voer. Hij is de meest terughoudende van de twee en blijft het liefst dicht bij zijn broer. Nieuwe situaties laat hij een beetje langs zich heen gaan, veilig van een afstandje, zolang Joep maar in de buurt is.

Joep is iets dapperder, maar ook onzeker. Hij wil graag een aai en zoekt contact, maar vindt het tegelijkertijd spannend. Met een rustige benadering en wat tijd zal hij zeker steeds meer vertrouwen krijgen. Wij hebben bij Joep een hart echo laten maken omdat er een klein ruisje te horen was. Hieruit is gebleken dat er sprake is van milde HCM waarvoor hij nu geen verdere behandeling nodig heeft maar wél is het belangrijk dat er 1 x per jaar een controle echo wordt gemaakt.

Wat deze twee knappe koppies vooral nodig hebben, is een kalm en stabiel thuis waar ze samen mogen blijven. Geen drukte, maar een plekje waar ze op hun eigen tempo kunnen wennen, zich veilig voelen en elkaar kunnen blijven steunen zoals ze altijd hebben gedaan. Beide katers zijn ontzettend lief maar hebben even tijd nodig om te wennen aan nieuwe mensen en nieuw situaties. Wij weten zeker dat deze broers na gewenning zich ontpoppen in hele gezellige en vrolijke katten.

Denk jij dat je Joep & Joris een gouden mandje kunt bieden en ben je geduldig en begripvol? Vul dan snel het interesse formulier in en wie weet kunnen wij een afspraak maken voor een kennismaking met dit duo.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_330x285_crop_center-center_none/IMG-20260426-WA0014.jpg?stamp=2605071735&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260426-WA0014.jpg?stamp=2605071735&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260426-WA0014.jpg?stamp=2605071735&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260426-WA0014.jpg?stamp=2605071735&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260508-WA0009.jpg?stamp=2605081750&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260426-WA0014.jpg?stamp=2605071735&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260426-WA0014.jpg?stamp=2605071735&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260426-WA0014.jpg?stamp=2605071735&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260508-WA0009.jpg?stamp=2605081750&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301101&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4600802-joep-joris'
from public.shelters s
where s.name = 'Dierenopvangcentrum Spijkenisse'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4600802-joep-joris')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Mandy', 'Mandy is een poezendame van 2 jaar oud. Ze is als zwervertje gevonden met haar kittens en heeft een tijdje in een gastgezin gezeten. Daar had ze zoveel stress van de aanwezige katten dat ze allerlei medische problemen kreeg. Er is voor de zekerheid nog een hartecho gemaakt, maar hier kwamen geen problemen uit naar voren.
In het asiel echter heeft ze geen enkel probleem en doet ze het super goed!
Ze is heel aanhankelijk, knuffelig en leuk. Ze miauwt een beetje schor, als een kikker.
Ze wordt vrijdag 8 mei nog gesteriliseerd en mag dan verhuizen. Ze zoekt dan een thuis zonder andere katten of honden, ergens waar ook geen kleine kindjes wonen. Dit is te druk voor haar.
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Mandy.png?stamp=2605061126&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Mandy.png?stamp=2605061126&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Mandy.png?stamp=2605061126&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Mandy.png?stamp=2605061126&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Maya_2026-05-06-092658_xjqr.png?stamp=2605061126&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Mandy.png?stamp=2605061126&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Mandy.png?stamp=2605061126&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Mandy.png?stamp=2605061126&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Maya_2026-05-06-092658_xjqr.png?stamp=2605061126&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 