insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Victor', 'Victor is een knappe zwart-witte kater van 6 jaar. Hij maakt een stoere indruk, maar daaronder zit een gevoelig en zachtaardig karakter verstopt, een combinatie die hem juist zo bijzonder maakt.
Nieuwe situaties bekijkt Victor het liefst eerst even van een afstandje. Hij is geen kat die zich halsoverkop ergens in stort, hij neemt de tijd om alles rustig te observeren. Met wat geduld en begrip zie je hem stap voor stap openbloeien. Zodra hij zich op zijn gemak voelt, laat hij zijn aanhankelijke kant zien en geniet hij zichtbaar van gezelschap en aandacht.
Victor is als zwerfkat bij ons binnengekomen en helaas nooit meer opgehaald. Wat hij precies heeft meegemaakt weten we niet, maar het is duidelijk dat hij nu toe is aan rust, stabiliteit en een veilige plek die hij echt zijn thuis kan noemen. Een plek waar hij zich kan ontspannen, zonder zich ergens druk om te hoeven maken. 
Op zijn eigen tempo verkent Victor graag zijn omgeving. Hij snuffelt nieuwsgierig rond, inspecteert alles zorgvuldig en kan intens genieten van een warm plekje in de zon. Een tuin waar hij lekker kan rondstruinen is voor hem dan ook belangrijk. 
Voor Victor zoeken we een rustig huishouden zonder kinderen of andere huisdieren. Hij heeft baat bij een stabiele en voorspelbare omgeving, bij iemand die begrijpt dat vertrouwen tijd nodig heeft. Maar wie hem die kans geeft, krijgt er een bijzondere kater voor terug, een kat die misschien niet meteen op schoot springt, maar wel langzaam je hart verovert.
Gun jij Victor het warme en liefdevolle thuis waar hij naar op zoek is? Neem dan snel contact met ons op!', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Victor.jpg?stamp=2605041418&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Victor.jpg?stamp=2605041418&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Victor.jpg?stamp=2605041418&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Victor.jpg?stamp=2605041418&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Victor-1.jpg?stamp=2605041418&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Victor.jpg?stamp=2605041418&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Victor.jpg?stamp=2605041418&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Victor.jpg?stamp=2605041418&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Victor-1.jpg?stamp=2605041418&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4600382-victor'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4600382-victor')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Kitty', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1191692-Kitty-6.jpg?stamp=2605041359&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1191692-Kitty-6.jpg?stamp=2605041359&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1191692-Kitty-6.jpg?stamp=2605041359&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty-6.jpg?stamp=2605041359&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty-3.jpg?stamp=2604031144&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty-4.jpg?stamp=2604031144&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty.jpg?stamp=2603141643&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty2.jpg?stamp=2603141643&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1191692-Kitty-6.jpg?stamp=2605041359&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1191692-Kitty-6.jpg?stamp=2605041359&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty-6.jpg?stamp=2605041359&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty-3.jpg?stamp=2604031144&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty-4.jpg?stamp=2604031144&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty.jpg?stamp=2603141643&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191692-Kitty2.jpg?stamp=2603141643&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4558982-kitty'
