where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4599405-mare')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Mea', 'Mea is een verlegen vondelingetje van een jaar of 5. Een tijd lang hebben we haar helemaal niet gezien. Maar nu na een paar weken in de ruimte is ze eindelijk wat meer gewend en komt ze los. Echt aaien kunnen we haar nog niet, maar zodra we gaan spelen met de andere katten in de ruimte, komt ze nieuwsgierig tevoorschijn en wil graag meedoen. En dan heeft ze zoveel plezier dat ze zomaar haar angst vergeet. En zoals het een zwerfkatje betaamt, komt ze er altijd uit voor beschuit. 
Voor haar zoeken we dan ook een rustig huishouden, zonder kinderen of kinderen op komst, met een ervaren eigenaar. Iemand die veel met haar gaat oefenen en er lol in heeft om haar verder te socialiseren. Spelen en eten zijn uitstekende manieren gebleken om haar hart te veroveren. Verwacht u niet dat ze binnen een paar weken op schoot zit. Het zal wat meer tijd en geduld gaan kosten dan dat. Maar als u geniet van ieder stapje in de goede richting, geeft dit al snel veel voldoening. Kijkt u op onze website onder “schuwe katten en kittens” voor meer tips en informatie. 
Mea is op haar gemak bij andere katten maar we zien haar eigenlijk nooit met ze slapen of spelen. We denken dan ook dat ze prima in haar eentje geplaatst kan worden, belangrijkst is dat haar nieuwe eigenaar met veel geduld en inzet haar helpt te ontwikkelen. 
Denkt u nu “die Mea is wel wat voor mij?”. Kom dan eens bij ons langs, we stellen haar graag aan u voor!', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/mea-3.jpg?stamp=2605031148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/mea-3.jpg?stamp=2605031148&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/mea-3.jpg?stamp=2605031148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/mea-3.jpg?stamp=2605031148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/mea-2.jpg?stamp=2605031148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/mea-3.jpg?stamp=2605031148&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/mea-3.jpg?stamp=2605031148&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/mea-3.jpg?stamp=2605031148&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/mea-2.jpg?stamp=2605031148&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4599393-mare'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4599393-mare')
