insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Dexter', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_330x285_crop_center-center_none/1191875-Dexter-3.jpg?stamp=2605021413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_384x330_crop_center-center_none/1191875-Dexter-3.jpg?stamp=2605021413&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_519x453_crop_center-center_none/1191875-Dexter-3.jpg?stamp=2605021413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_800x550_crop_center-center_none/1191875-Dexter-3.jpg?stamp=2605021413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_800x550_crop_center-center_none/1191875-Dexter-4.jpg?stamp=2605021413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_800x550_crop_center-center_none/1191875-Dexter-5.jpg?stamp=2605021413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_384x330_crop_center-center_none/1191875-Dexter-3.jpg?stamp=2605021413&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_519x453_crop_center-center_none/1191875-Dexter-3.jpg?stamp=2605021413&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_800x550_crop_center-center_none/1191875-Dexter-3.jpg?stamp=2605021413&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_800x550_crop_center-center_none/1191875-Dexter-4.jpg?stamp=2605021413&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Algemeen/_800x550_crop_center-center_none/1191875-Dexter-5.jpg?stamp=2605021413&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4567238-dexter'
from public.shelters s
where s.name = 'De Kuipershoek'
