insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Sura', 'Sura is een dametje van 5 jaar oud die afgestaan is wegens dat de eigenaren teveel weg waren en Sura ook graag naar buiten wilde.
Ze gaat graag naar buiten in een tuin, helaas kon dit niet omdat ze veel thuis alleen was. Sura is speels, sociaal en lief. Komt graag naar je toe voor aandacht.
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag verzoeken wij je eerst een kennismakingsmail te sturen naar limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Sura.png?stamp=2605061130&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Sura.png?stamp=2605061130&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Sura.png?stamp=2605061130&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Sura.png?stamp=2605061130&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Sura.png?stamp=2605061130&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Sura.png?stamp=2605061130&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Sura.png?stamp=2605061130&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4598002-sura'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4598002-sura')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Koppel Snowy en Cypers (binnenkatten)', 'Dit zijn Snowy en Cypers. Ze zijn afgestaan wegens dat hun baasje naar een verzorgingstehuis is verhuisd. Het zijn zusjes van 7 jaar oud en gewend om binnen te wonen.
Beide dames zijn wel echt te zwaar op het moment en moeten op dieet om problemen in de toekomst te voorkomen.
De dames zijn helaas bang op het moment en vinden alles heel erg spannend.
