insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Ties (FIV +, binnenkat)', 'Ties is een kerel van 4 jaar oud, lief maar bang. Hij heeft tijd nodig om te wennen aan al die nieuwe mensen. Hij is opzoek naar een huisje waar hij alle tijd krijgt om te wennen, waar die binnen kan blijven of een mooie ren / balkon heeft.Wat is kattenaids?Kattenaids is een 
virusziekte die het afweersysteem van een kat aantast. Het is niet 
besmettelijk voor mensen of andere dieren, alleen voor katten onderling.
 Er is geen geneesmiddel of medicijn voor kattenaids. Belangrijk is dat 
de katten een zo stressvrij mogelijk leven lijden en niet meer vrij 
buiten mogen rondlopen. Indien ze dus goed verzorgd worden hebben ze een
 goede levensverwachting. De meeste aidskatten overlijden eerder door 
ouderdom of andere problemen dan door de aids.
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Ties.png?stamp=2605012027&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Ties.png?stamp=2605012027&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Ties.png?stamp=2605012027&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Ties.png?stamp=2605012027&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Ties.png?stamp=2605012027&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Ties.png?stamp=2605012027&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Ties.png?stamp=2605012027&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4597974-ties-fiv-binnenkat'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4597974-ties-fiv-binnenkat')
