insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Cheat', 'Cheat is een grote, imposante kater met een zacht hart. Hij kwam bij ons via afstand, omdat zijn vorige eigenaar hem soms lastig kon peilen. Die onvoorspelbaarheid zorgde voor onzekerheid, waardoor is besloten een nieuw, passend thuis voor hem te zoeken. In zijn vorige huis woonde Cheat samen met een andere kat, maar dat was geen gelukkige combinatie. Het is goed mogelijk dat daar ook de nodige spanning en frustratie uit voortkwam, want bij ons heeft Cheat nog geen moment ongewenst gedrag laten zien.

Hier laat hij zich kennen als een gezellige en aanhankelijke kerel die graag in je buurt is. Zodra hij je ziet, kijkt hij je verwachtingsvol aan, alsof hij hoopt dat je speciaal voor hem komt. En eerlijk is eerlijk: daar is moeilijk aan te weerstaan. Hij staat meteen op, komt naar je toe en begint enthousiast tegen je te kletsen. Cheat is dol op aandacht, geniet zichtbaar van knuffelmomenten en ligt het liefst lekker bij je op schoot of dicht tegen je aan. Ook ’s avonds zoekt hij graag je gezelschap op; als hij mee naar bed mag, kruipt hij tevreden bij je in de buurt. Soms kan dit gedrag verraderlijk zijn, want wanneer Cheat voldoende prikkels heeft gehad, laat hij subtiele signalen zien. Zijn staart begint te zwiepen, zijn blik verandert en zijn oren gaan naar achteren. Dit is het moment om te stoppen met aaien en Cheat lekker zijn ding te laten doen. 
Omdat zijn vorige eigenaar aangaf dat Cheat soms plotseling kon omslaan en dan kon uithalen, zoeken we voor hem een baasje dat kattentaal begrijpt en zijn signalen goed kan lezen. Iemand die hem de rust, duidelijkheid en het vertrouwen kan geven dat hij nodig heeft. Voor Cheat zoeken we een rustig thuis zonder jonge kinderen. Kinderen vanaf ongeveer 12 jaar, die ervaring hebben met katten en zijn grenzen respecteren, zijn welkom om te komen kijken of er een klik is. Cheat is graag binnen, maar vindt het ook fijn om af en toe een rondje door de buurt te maken. Daarom plaatsen we hem niet in een appartement
Denk jij dat jij Cheat het thuis kunt bieden dat hij verdient? Vul dan het aanvraagformulier in bij stap 3 en wie weet ontmoeten jullie elkaar binnenkort.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/4568879/DSC_0124_2026-03-26-150327_hcgc.jpg?stamp=2603261604&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/4568879/DSC_0124_2026-03-26-150327_hcgc.jpg?stamp=2603261604&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/4568879/DSC_0124_2026-03-26-150327_hcgc.jpg?stamp=2603261604&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4568879/DSC_0124_2026-03-26-150327_hcgc.jpg?stamp=2603261604&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4568878/DSC_0114_2026-03-26-150323_iwbs.jpg?stamp=2603261604&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4568876/DSC_0095_2026-03-26-150315_jgcz.jpg?stamp=2603261604&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4568877/DSC_0105_2026-03-26-150319_woqc.jpg?stamp=2603261603&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/4568879/DSC_0124_2026-03-26-150327_hcgc.jpg?stamp=2603261604&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/4568879/DSC_0124_2026-03-26-150327_hcgc.jpg?stamp=2603261604&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4568879/DSC_0124_2026-03-26-150327_hcgc.jpg?stamp=2603261604&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4568878/DSC_0114_2026-03-26-150323_iwbs.jpg?stamp=2603261604&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4568876/DSC_0095_2026-03-26-150315_jgcz.jpg?stamp=2603261604&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4568877/DSC_0105_2026-03-26-150319_woqc.jpg?stamp=2603261603&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4568875-cheat'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4568875-cheat')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Gouda', 'Puk', 'Puk is een prachtige poes van 6 jaar met een heel eigen persoonlijkheid. Ze is geen allemansvriend, maar juist een kat die je moet leren lezen en respecteren. En precies daarin zit haar charme. Bij vertrouwde mensen is ze, na een wat langere wenperiode, gezellig aanwezig en op haar eigen manier aanhankelijk. Ze zoekt veel contact, maar wel volgens haar eigen planning. Puk werkt niet met afspraken, alleen met spontane ingevingen.
Puk voelt zich prettiger als ze zelf de regie heeft. Nieuwe situaties en mensen bekijkt ze het liefst eerst rustig van een afstandje. Geef je haar die ruimte, dan zie je langzaam haar nieuwsgierige kant naar boven komen. Een lekker snackje (Whiskas tempatations) helpt hier goed bij. Als ze voor je kiest, voelt dat extra bijzonder. Ze is geen kat die je zomaar oppakt of ongevraagd aait. Bij Puk geldt: laat haar het initiatief nemen. Als je haar grenzen respecteert, bouw je stap voor stap een mooie band met haar op. En vindt ze het uiteindelijk heerlijk om aaitjes te krijgen en onder haar kinnetje gekriebeld te worden. Ze kan dan echt genieten en spint erop los. Ze ligt dan ook graag bij je op de bank. 
In een rustig huishouden met max 1-2 personen, zal Puk het beste tot haar recht komen. Iemand met geduld en gevoel voor kattentaal is voor haar ideaal. Ervaring met katten die wat meer “gebruiksaanwijzing” hebben is een pré, maar vooral belangrijk is dat je haar neemt zoals ze is. Puk is een kat voor iemand die het juist mooi vindt om vertrouwen op te bouwen. Geen instant knuffelkat, maar een bijzondere huisgenoot die op haar eigen manier laat zien dat ze je waardeert. 
Het is niet mogelijk om zonder afspraak naar onze katten te komen kijken. Om er zeker van te zijn dat u en de kat een goede match zijn, verzoeken we u vriendelijk de algemene vragenlijst zo uitgebreid mogelijk te beantwoorden en te mailen naar gouda@dierenbescherming.nl .
Wat zijn uw naam en telefoonnummer?Vertel iets over uw gezinssituatie. Wat zijn de leeftijden van alle gezinsleden?Zijn er andere dieren in huis en zijn deze katten gewend? En wat zijn de leeftijden?Vertel iets over uw woonsituatie, Wat voor soort woning heeft u en heeft deze een balkon of een tuin?Wat zijn uw verwachtingen van de kat?Welke tijd en dagen bent u beschikbaar voor kennismaking?Gaat u binnenkort met vakantie?', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_330x285_crop_center-center_none/7c12520e-7cfd-46b2-9b5f-bf27408ec215.jpg?stamp=2604301410&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_384x330_crop_center-center_none/7c12520e-7cfd-46b2-9b5f-bf27408ec215.jpg?stamp=2604301410&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_519x453_crop_center-center_none/7c12520e-7cfd-46b2-9b5f-bf27408ec215.jpg?stamp=2604301410&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/7c12520e-7cfd-46b2-9b5f-bf27408ec215.jpg?stamp=2604301410&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/7664ef0c-cd9b-45cd-b9bd-298dd613b13f.jpg?stamp=2604301409&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4daf0335-705c-4b77-9ca0-785b50d9557d.jpg?stamp=2604301410&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/b986bd98-2938-486c-ba30-ca1ba489b683.jpg?stamp=2604301409&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_384x330_crop_center-center_none/7c12520e-7cfd-46b2-9b5f-bf27408ec215.jpg?stamp=2604301410&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_519x453_crop_center-center_none/7c12520e-7cfd-46b2-9b5f-bf27408ec215.jpg?stamp=2604301410&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/7c12520e-7cfd-46b2-9b5f-bf27408ec215.jpg?stamp=2604301410&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/7664ef0c-cd9b-45cd-b9bd-298dd613b13f.jpg?stamp=2604301409&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/4daf0335-705c-4b77-9ca0-785b50d9557d.jpg?stamp=2604301410&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/b986bd98-2938-486c-ba30-ca1ba489b683.jpg?stamp=2604301409&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301136&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4597297-puk'
from public.shelters s
where s.name = 'Dierenopvangcentrum Gouda'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4597297-puk')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Diva', 'Hallo! Mijn naam is Diva. Een knappe schildpad dame van 9 jaar oud. Ik ben op zoek naar liefde en gezelligheid!
Ik hou van aandacht en geef graag kopjes. Passend bij mijn uiterlijk kan ik wel koppig zijn en weet ik duidelijk mijn grenzen aan te geven. Ik kom graag en veel buiten en zoek daarom een huis met een tuin. In de opvang heb ik contact gemaakt met andere katten en ik heb de mensen hier duidelijk laten weten dat dit niets voor mij is. Ik zoek lekker een paleisje waar ik de enige poezendame ben! Ik zou in een gezin kunnen wonen met oudere kinderen. Rust is ook belangrijk voor mij, dus een huis met jonge kinderen lijkt mij niet fijn. Ik ben nog dol op spelen en dan met name met hengeltjes. 
Spreekt mijn verhaal jou aan? Dan hoop ik je snel te mogen ontmoeten.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/Diva4.jpg?stamp=2605051547&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/Diva4.jpg?stamp=2605051547&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/Diva4.jpg?stamp=2605051547&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Diva4.jpg?stamp=2605051547&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Diva_2026-04-29-150852_yfem.jpg?stamp=2604291708&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Diva3.jpg?stamp=2604291708&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Diva1_2026-04-29-150852_vyby.jpg?stamp=2604291708&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/Diva4.jpg?stamp=2605051547&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/Diva4.jpg?stamp=2605051547&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Diva4.jpg?stamp=2605051547&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Diva_2026-04-29-150852_yfem.jpg?stamp=2604291708&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Diva3.jpg?stamp=2604291708&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Diva1_2026-04-29-150852_vyby.jpg?stamp=2604291708&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4596731-diva'
from public.shelters s
where s.name = 'Dierentehuis Kennemerland'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4596731-diva')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Mikky', 'Mikky is een prachtige, gevoelige dame van 10 jaar die na het overlijden van haar baasje bij ons in het asiel is gekomen. Ze heeft haar hele leven in een rustig huis gewoond, waar ze altijd samen was met haar vertrouwde baasje en dat is precies wat ze nu weer zo hard nodig heeft.
Het asielleven vindt Mikky op dit moment nog erg spannend. Ze laat zich niet meteen zien zoals ze echt is, maar we weten dat ze bij haar baasje een ontzettend lieve kat was. Geef haar de tijd om te wennen en je zult zien dat ze langzaam opbloeit.
Voor Mikky zoeken we een rustig huishouden bij iemand die haar de tijd geeft en haar let wennen op haar tempo. Een woning met katveilig balkon zou voor haar perfect zijn, zo kan ze op een veilige manier genieten van de buitenlucht.
Ze mag dan wel al 10 jaar zijn maar ze is nog dol op spelen. Met een hengeltje krijgen we haar zo ver om de angst even te vergeten en lekker te kunnen spelen. Ook is deze dame dol op iets lekkers en hiermee al snel over te halen.
Gun jij deze bijzondere dame een tweede kans en een liefdevol thuis?
KENNISMAKEN EN ADOPTIE:
We verzoeken om de volgende informatie via info.vlaardingen@dierenbescherming.nl te sturen:
naam, adres en telefoonnummerde gezinssamenstelling (indien kinderen, de leeftijden)de woonsituatie (wel/geen tuin/balkon en hoe dat is afgezet, graag foto''s toevoegen)werksituatie/ werktijdende ervaring met katteneventuele andere aanwezige huisdiereneventuele vakantieplannen op korte termijn: We hebben geen mogelijkheid om een dier tot na de vakantie vast te houden en adviseren om pas na de vakantie op zoek te gaan naar een nieuwe huisgenoot.
Het is niet mogelijk om per e-mail of via de telefoon een kat te reserveren. Kennismaken met de asielkatten kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch. Bij meerdere gegadigden maken we een selectie voor de uitnodiging voor het kennismaken op basis van de informatie zoals gegeven in de mail. Let op: katten dienen bij adoptie met een auto opgehaald te worden', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_330x285_crop_center-center_none/Mikky1.jpeg?stamp=2604291355&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/Mikky1.jpeg?stamp=2604291355&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/Mikky1.jpeg?stamp=2604291355&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/Mikky1.jpeg?stamp=2604291355&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/Mikky2.jpeg?stamp=2604291355&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/Mikky1.jpeg?stamp=2604291355&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/Mikky1.jpeg?stamp=2604291355&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/Mikky1.jpeg?stamp=2604291355&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/Mikky2.jpeg?stamp=2604291355&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301030&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4596498-mikky'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4596498-mikky')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Bastet', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1192782-Bastet.jpg?stamp=2604281115&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1192782-Bastet.jpg?stamp=2604281115&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1192782-Bastet.jpg?stamp=2604281115&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192782-Bastet.jpg?stamp=2604281115&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192728-Bastet-3.jpg?stamp=2604281116&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192728-Bastet-2.jpg?stamp=2604281116&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1192782-Bastet.jpg?stamp=2604281115&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1192782-Bastet.jpg?stamp=2604281115&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192782-Bastet.jpg?stamp=2604281115&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192728-Bastet-3.jpg?stamp=2604281116&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192728-Bastet-2.jpg?stamp=2604281116&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592131-bastet'
from public.shelters s
where s.name = 'De Kuipershoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592131-bastet')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Gouda', 'Snoetje', 'Snoetje: drie poten, vier keer zoveel karakter. 
Als hij het naar zijn zin heeft, is hij echt een kroelkip, dit vindt hij heerlijk. Ook ligt hij graag op schoot en spint er op los. Van plezier kringelt hij om je heen en deelt enthousiast kopjes uit. Snoetje runt zijn eigen koninkrijk zonder concurrentie, dus hij is graag de enige kat in huis. Hij is ooit aangereden en heeft hij nu nog maar drie poten. Deze jongen heeft veel gezelligheid en veiligheid in huis nodig, maar ook vrijheid en een tuin om in te struinen. Hij heeft graag een kattenluik op chip zodat hij zelf controle heeft. Wat je ervoor terugkrijgt? Een kat met karakter, doorzettingsvermogen en een duidelijke liefde voor... eten en vooral liquid snacks. (Daar doet hij echt alles voor en dat mag je best een beetje misbruiken bij de kennismaking) Snoetje is in een nieuwe situatie in eerste instantie wat onrustige en onzeker en heeft echt even de tijd nodig. Maar als hij eenmaal heeft ontdekt dat alles ok is, dan is hij helemaal heppiedepeppie, een blij ei. We zoeken voor hem een kat-arme omgeving waar niet al te veel druk verkeer is. Snoetje kan ook aardig verhalen vertellen, dus je moet wel open staan voor wat goede gesprekken. Zoek je een uniek karakter met drie poten en een grote persoonlijkheid? Dan is Snoetje jouw man. 
Het is niet mogelijk om zonder afspraak naar onze katten te komen kijken. Om er zeker van te zijn dat u en de kat een goede match zijn, verzoeken we u vriendelijk de algemene vragenlijst zo uitgebreid mogelijk te beantwoorden en te mailen naar gouda@dierenbescherming.nl .
Wat zijn uw naam en telefoonnummer?Vertel iets over uw gezinssituatie. Wat zijn de leeftijden van alle gezinsleden?Zijn er andere dieren in huis en zijn deze katten gewend? En wat zijn de leeftijden?Vertel iets over uw woonsituatie, Wat voor soort woning heeft u en heeft deze een balkon of een tuin?Wat zijn uw verwachtingen van de kat?Welke tijd en dagen bent u beschikbaar voor kennismaking?Gaat u binnenkort met vakantie?', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_330x285_crop_center-center_none/442afbb4-8a8e-4c6a-9426-ddc37d0f3854_2026-04-22-122730_eogx.jpg?stamp=2604221428&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_384x330_crop_center-center_none/442afbb4-8a8e-4c6a-9426-ddc37d0f3854_2026-04-22-122730_eogx.jpg?stamp=2604221428&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_519x453_crop_center-center_none/442afbb4-8a8e-4c6a-9426-ddc37d0f3854_2026-04-22-122730_eogx.jpg?stamp=2604221428&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/442afbb4-8a8e-4c6a-9426-ddc37d0f3854_2026-04-22-122730_eogx.jpg?stamp=2604221428&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/e940f8e6-ae45-473c-9c07-60777ed2643e.jpg?stamp=2604301030&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/829f4f3e-02d1-4793-800e-9927dee521e2_2026-04-22-122730_idvu.jpg?stamp=2604221428&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/3020d678-604b-4d1a-a16c-3dd20431af07.jpg?stamp=2604221429&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_384x330_crop_center-center_none/442afbb4-8a8e-4c6a-9426-ddc37d0f3854_2026-04-22-122730_eogx.jpg?stamp=2604221428&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_519x453_crop_center-center_none/442afbb4-8a8e-4c6a-9426-ddc37d0f3854_2026-04-22-122730_eogx.jpg?stamp=2604221428&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/442afbb4-8a8e-4c6a-9426-ddc37d0f3854_2026-04-22-122730_eogx.jpg?stamp=2604221428&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/e940f8e6-ae45-473c-9c07-60777ed2643e.jpg?stamp=2604301030&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/829f4f3e-02d1-4793-800e-9927dee521e2_2026-04-22-122730_idvu.jpg?stamp=2604221428&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/_800x550_crop_center-center_none/3020d678-604b-4d1a-a16c-3dd20431af07.jpg?stamp=2604221429&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301136&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4591457-snoetje'
from public.shelters s
where s.name = 'Dierenopvangcentrum Gouda'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4591457-snoetje')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Bruno', 'Ontmoet Bruno, een prachtige kater van ongeveer 3 jaar oud met een rugzakje vol mysterie. Bruno is waarschijnlijk opgegroeid zonder de nabijheid van mensen; hij zwierf maandenlang door tuinen op zoek naar een veilig plekje, totdat hij bij ons werd binnengebracht. Of hij ooit een echt huis heeft gehad, weten we niet, maar voor Bruno is de mensenwereld nog even een groot en spannend avontuur waar hij liever van een veilige afstand naar kijkt.
In het asiel heeft Bruno zijn eigen vertrouwde eilandje gecreëerd waar hij eigenlijk altijd te vinden is. Contact maken vindt hij nog erg spannend en uit zijn schulp kruipen doet hij niet zomaar. Voor Bruno is een aai over zijn bol op dit moment nog tien stappen te ver; hij heeft tijd nodig, heel veel geduld en een baasje dat begrijpt dat vertrouwen niet te dwingen is. Toch is er één ding waarvoor hij zijn angst opzijzet, en dat is de liquid stick. Zodra hij dat lekkers ruikt, komt hij voorzichtig van zijn plekje tevoorschijn. Het is hét moment waarop hij laat zien dat er, ergens diep van binnen, een dapper katje schuilt dat stapje voor stapje dichterbij durft te komen.
Omdat Bruno zo gesteld is op zijn rust, zoeken we voor hem een heel specifiek nieuw thuis. Hij woont het liefst in een kalm huishouden zonder andere huisdieren of kinderen (denk hierbij ook aan een kinderwens), bij mensen die er vrede mee hebben dat hij de eerste tijd vooral onzichtbaar zal zijn. Daarnaast is Bruno een echte buitenjongen in hart en nieren. Na een goede wenperiode wil hij dolgraag weer een tuin hebben om te verkennen, waardoor een appartement voor hem geen optie is. 
Heb jij een rustig huis, een flinke voorraad liquid sticks en alle tijd van de wereld om deze bijzondere kater te laten ontdooien? Vul dan het aanvraagformulier in onder stap 3.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Bruno.jpg?stamp=2605011426&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Bruno.jpg?stamp=2605011426&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Bruno.jpg?stamp=2605011426&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Bruno.jpg?stamp=2605011426&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4595906/Bruno-3_2026-04-28-142248_qrlw.jpg?stamp=2604281622&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4595907/Bruno-4.jpg?stamp=2604281622&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4595905/Bruno-2_2026-04-28-142245_gcos.jpg?stamp=2604281622&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4595904/Bruno-1_2026-04-28-142242_aaid.jpg?stamp=2604281622&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Bruno.jpg?stamp=2605011426&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Bruno.jpg?stamp=2605011426&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Bruno.jpg?stamp=2605011426&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4595906/Bruno-3_2026-04-28-142248_qrlw.jpg?stamp=2604281622&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4595907/Bruno-4.jpg?stamp=2604281622&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4595905/Bruno-2_2026-04-28-142245_gcos.jpg?stamp=2604281622&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4595904/Bruno-1_2026-04-28-142242_aaid.jpg?stamp=2604281622&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4595896-bruno'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4595896-bruno')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Willem-Dries (boerderijkat)', 'Maak kennis met Willem-Dries, een stoere kater van twee jaar oud met een heel duidelijk levensmotto: kijken mag, maar liever niet te dichtbij. Willem-Dries is bij ons binnengekomen via een vangactie en waarschijnlijk heeft hij zijn hele leven buiten gewoond zonder ooit aan mensen te wennen. In de weken dat hij nu bij ons in de opvang verblijft, heeft hij ons één ding heel duidelijk gemaakt: het leven als gezellige huiskat is simpelweg niets voor hem.
Willem-Dries is een standvastige kater die mensen doodeng vindt. Zodra er iemand in de buurt komt, verandert hij in een standbeeld op zijn verstopplek en vermijdt hij elk oogcontact, in de hoop dat hij niet opgemerkt wordt. Hij is een kat die liever onzichtbaar blijft en zijn eigen plan trekt. Omdat hij in de opvang geen enkele vooruitgang heeft geboekt in het contact met mensen, gunnen we hem een plek waar hij die druk ook helemaal niet meer voelt.
We zoeken voor Willem-Dries een mooie boerderij, een manege of een andere buiten plek waar hij de vrijheid krijgt om lekker buiten te struinen. Hij zoekt een plek waar hij dagelijks zijn verzorging krijgt in de vorm van een bakje voer en een warm, droog plekje om te slapen. Het belangrijkste is dat zijn nieuwe baasje begrijpt dat Willem-Dries liever de andere kant op rent als er iemand aan komt en dat er verder helemaal niets van hem verwacht wordt.
De deal is eigenlijk heel simpel: jij zorgt voor de catering en een veilige basis, en Willem-Dries zorgt er als dank voor dat de muizenpopulatie op jouw terrein onder controle blijft. Een eerlijke ruil voor een onafhankelijke heer die gewoon ''kat'' wil zijn.
Het is wel belangrijk dat Willem-Dries op zijn nieuwe plek eerst een paar weken in een afgesloten ruimte kan wennen. Zo leert hij waar zijn eten staat en wat zijn vaste honk is, zodat hij niet direct wegloopt zodra hij de vrijheid krijgt. Daarna mag hij met een gerust hart zijn nieuwe koninkrijk gaan verkennen.
Heb jij de perfecte werkplek voor Willem-Dries waar hij in alle rust zijn eigen gang mag gaan? Vul dan het aanvraagformulier in onder stap 3.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/WhatsApp-Image-2026-04-28-at-09.54.29.jpeg?stamp=2604281511&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/WhatsApp-Image-2026-04-28-at-09.54.29.jpeg?stamp=2604281511&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/WhatsApp-Image-2026-04-28-at-09.54.29.jpeg?stamp=2604281511&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/WhatsApp-Image-2026-04-28-at-09.54.29.jpeg?stamp=2604281511&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/WhatsApp-Image-2026-04-28-at-09.54.29.jpeg?stamp=2604281511&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/WhatsApp-Image-2026-04-28-at-09.54.29.jpeg?stamp=2604281511&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/WhatsApp-Image-2026-04-28-at-09.54.29.jpeg?stamp=2604281511&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4595827-willem-dries-boerderijkat'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4595827-willem-dries-boerderijkat')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Purmerend', 'Smartie', 'Voorzichtige kater.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_330x285_crop_center-center_none/smartie1.jpg?stamp=2604291122&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_384x330_crop_center-center_none/smartie1.jpg?stamp=2604291122&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_519x453_crop_center-center_none/smartie1.jpg?stamp=2604291122&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_800x550_crop_center-center_none/smartie1.jpg?stamp=2604291122&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_800x550_crop_center-center_none/4595711/4be00e10-8473-4b15-8846-392b2ec9c180.jpg?stamp=2604281355&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/Dieren/_800x550_crop_center-center_none/Smartie.jpeg?stamp=2605041145&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_384x330_crop_center-center_none/smartie1.jpg?stamp=2604291122&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_519x453_crop_center-center_none/smartie1.jpg?stamp=2604291122&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_800x550_crop_center-center_none/smartie1.jpg?stamp=2604291122&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/_800x550_crop_center-center_none/4595711/4be00e10-8473-4b15-8846-392b2ec9c180.jpg?stamp=2604281355&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/Dieren/_800x550_crop_center-center_none/Smartie.jpeg?stamp=2605041145&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisAlkmaar/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301011&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4595702-smartie'
