insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', 'Loekie', 'Loekie is een poes met een duidelijk karakter. Ze weet precies wat ze wil en geeft haar grenzen helder aan. Drukke omgevingen zijn niets voor haar, daarom zoeken we voor Loekie een rustig huishouden zonder kinderen.
Andere katten zijn helaas geen goede match voor haar; Loekie komt het beste tot haar recht als enige kat in huis. Ze heeft af en toe buiten gelopen, maar heeft hier geen sterke behoefte aan. Een afgeschermde tuin zou wél een fijne extra zijn, zodat ze veilig een frisse neus kan halen wanneer ze daar zin in heeft.
Hoewel ze in het begin wat afstandelijk kan zijn, laat Loekie haar zachtere kant zien zodra ze je vertrouwt. Dan komt ze graag naar je toe voor aandacht en gezelschap, op haar eigen voorwaarden.
Ben jij iemand die haar de rust, duidelijkheid en het begrip kan geven dat ze nodig heeft? Dan zou Loekie zomaar jouw perfecte huisgenoot kunnen zijn.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_330x285_crop_center-center_none/Loekie.jpg?stamp=2604271157&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_384x330_crop_center-center_none/Loekie.jpg?stamp=2604271157&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_519x453_crop_center-center_none/Loekie.jpg?stamp=2604271157&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/Loekie.jpg?stamp=2604271157&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_384x330_crop_center-center_none/Loekie.jpg?stamp=2604271157&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_519x453_crop_center-center_none/Loekie.jpg?stamp=2604271157&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/Loekie.jpg?stamp=2604271157&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_882x1004_crop_center-center_none/banner-beeld-hond-close-885.png?stamp=2504161034&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4594908-loekie'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Noord-Nederland'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4594908-loekie')
limit 1;

