insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Alfie', 'Alfie is onze vrolijke spring-in-’t-veld, een energieke, rood-witte kater van 2 jaar oud die nooit stilzit. Hij werd op straat gevonden en via de dierenambulance bij ons gebracht, en sindsdien zorgt hij voor leven en plezier in huis. Alfie is nieuwsgierig, dapper en altijd klaar voor avontuur. Geen hoekje ontsnapt aan zijn onderzoekende blik, en geen speeltje overleeft zijn speelse jachtinstinct.
Alfie is ontzettend speels… misschien zelfs een tikje té speels. Waarschijnlijk is hij te jong uit het nest gehaald, waardoor hij nog niet helemaal geleerd heeft hoe hij met overprikkeling om moet gaan. Alles wat beweegt, ziet hij als een speeltje, je handen, je haar, je sokken… echt, niks is veilig! Met geduld en begeleiding leert hij langzaam zijn enthousiasme in goede banen te leiden, maar eerlijk gezegd levert het ook hilarische momenten op.
Na een tijdje wennen zou Alfie graag de buitenwereld ontdekken. Klimmen, rennen, graven of blaadjes achterna zitten, alles is voor hem een avontuur. En hopelijk wordt hij daarna binnen een tikkeltje rustiger.
Voor Alfie zoeken wij een rustig huishouden met 1 a max twee personen. Dit betekent een huis zonder kinderen en/of andere huisdieren. Mensen die hem voldoende kunnen uitdagen en zijn lichaamstaal goed kunnen lezen. Een huis met een tuin is voor hem echt een must. 
Bent u op zoek naar een actieve, levenslustige en vrolijke kat met een flinke dosis karakter (en humor)? Dan zou Alfie wel eens uw nieuwe huisgenoot kunnen zijn. Neem gerust contact met ons op!', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Alfie.jpg?stamp=2604081437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Alfie.jpg?stamp=2604081437&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Alfie.jpg?stamp=2604081437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Alfie.jpg?stamp=2604081437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Alfie-1.jpg?stamp=2604081437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Alfie-2.jpg?stamp=2604081437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Alfie.jpg?stamp=2604081437&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Alfie.jpg?stamp=2604081437&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Alfie.jpg?stamp=2604081437&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Alfie-1.jpg?stamp=2604081437&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Alfie-2.jpg?stamp=2604081437&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4593006-alfie'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4593006-alfie')
