insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Lance', 'Maak kennis met Lance, een zachtaardige jongen met een klein hartje 💛 Lance is een cyper-witte kater van ongeveer 5 jaar oud en hoewel hij er misschien uitziet als een stoere kerel, is hij van binnen vooral een gevoelige jongen.
Lance is nog wat onzeker en kijkt in nieuwe situaties eerst even de kat uit de boom. Hij heeft tijd nodig om te wennen en om vertrouwen op te bouwen. Maar geef je hem die kans? Dan ontdek je al snel hoe ontzettend lief en aanhankelijk hij eigenlijk is. Lance komt graag bij je in de buurt en geniet zichtbaar van jouw gezelschap.
Wel is het belangrijk om zijn grenzen te respecteren. Als iets hem te veel wordt, laat hij dat netjes weten. Geen drama, gewoon duidelijke communicatie, daar kunnen we wat van leren 😉
Voor Lance zoeken we een rustig huishouden, zonder al te veel drukte. Hij voelt zich het prettigst op een plek waar hij zichzelf mag zijn en op zijn eigen tempo kan ontdooien. Andere dieren of een hectische omgeving passen niet bij hem.
Daarnaast is Lance dol op naar buiten gaan. Een tuin is daarom echt een must, zodat hij veilig zijn energie kwijt kan en op zijn eigen manier de wereld kan ontdekken.het liefste wel in een autoluwe straat . Hij is namelijk weinig verkeer gewend in zijn vorige omgeving.
Lance heeft een gevoelige maag/darm en krijgt daarom speciale (hypoallergene) voeding. Gelukkig vindt Lance dit voer ontzettend lekker 😋
Ben jij degene die Lance de rust, het geduld en de liefde kan geven die hij nodig heeft? Kom dan snel eens kennismaken met hem!', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Lance-01.jpeg?stamp=2605042333&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Lance-01.jpeg?stamp=2605042333&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Lance-01.jpeg?stamp=2605042333&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Lance-01.jpeg?stamp=2605042333&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Lance-2.jpg?stamp=2604231551&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Lance-1.jpg?stamp=2604231551&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Lance.jpg?stamp=2604231551&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Lance-01.jpeg?stamp=2605042333&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Lance-01.jpeg?stamp=2605042333&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Lance-01.jpeg?stamp=2605042333&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Lance-2.jpg?stamp=2604231551&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Lance-1.jpg?stamp=2604231551&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Lance.jpg?stamp=2604231551&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592602-lance'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592602-lance')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Jor', 'Maak kennis met Jor, een rustige kerel met een prachtig uiterlijk 🤍
Jor is een kater van 4 jaar oud en hij is er eentje die je niet snel vergeet. Met zijn prachtige witte vacht en bijzondere ogen steelt hij moeiteloos de show.
Jor is een rustige, relaxte kat die het leven graag op zijn gemak benadert. Een beetje lui? Absoluut 😉 Hij ligt het liefst lekker te chillen en bekijkt de wereld op zijn eigen tempo. Maar vergis je niet… zodra een andere kat iets té dichtbij komt, laat hij heel duidelijk weten dat dat niet de bedoeling is. Dan deelt hij zonder pardon een tik uit, zijn persoonlijke ruimte is heilig en daar onderhandelt hij niet over.
Jor is geen uitgesproken schootkat, maar wel een echte gezelligheidskat. Hij is graag bij je in de buurt en vindt het fijn om samen te zijn. Aaien waardeert hij enorm, zelfs een aai over zijn buik vindt hij prima. Oppakken daarentegen? Dat hoeft voor hem niet. Dan kiest hij er liever voor om weg te lopen.
Jor houdt van rust, dus een druk huishouden met kinderen past minder goed bij hem. Ook met andere katten heeft hij geen klik, dus we zoeken voor hem een plek waar hij lekker de enige kat in huis mag zijn.
Een tuin is voor Jor wel belangrijk. Hij is gewend om naar buiten te gaan en vindt het heerlijk om af en toe een rondje te maken of gewoon in het zonnetje te liggen.
Ben jij op zoek naar een rustige, lieve huisgenoot met een klein gebruiksaanwijzingetje én een vleugje humor? Dan is Jor misschien wel precies de kat die je zoekt.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Jor.jpg?stamp=2604231547&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Jor.jpg?stamp=2604231547&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Jor.jpg?stamp=2604231547&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Jor.jpg?stamp=2604231547&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Jor.jpg?stamp=2604231547&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Jor.jpg?stamp=2604231547&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Jor.jpg?stamp=2604231547&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592592-jor'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4592592-jor')
limit 1;

