insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Loki', 'Maak kennis met onze Loki, een prachtige kerel die precies weet wat hij wil. Zijn naam klinkt misschien stoer, maar wie Loki echt leert kennen, ziet een karaktervolle kat die simpelweg zijn eigen, duidelijke manier van communiceren heeft. 
Loki is geen ''schootkat'' die je even optilt; hij is een trotse strijder die het liefst met zijn vier pootjes stevig op de grond blijft staan. Hij houdt van aandacht en geniet oprecht van een aai over zijn kopje. Loki is echter heel eerlijk in zijn communicatie: als hij genoeg heeft van de knuffels, geeft hij dat duidelijk aan. In zijn verleden is hij helaas niet altijd goed begrepen en werd hij gecorrigeerd op een manier die erg vervelend voor hem was. Hierdoor moet hij er opnieuw leren vertrouwen dat mensen zijn grenzen wél respecteren.
Daarom zoeken wij voor hem ervaren kattenbaasjes die zijn lichaamstaal goed kunnen aanvoelen en zijn onafhankelijkheid waarderen. We zoeken mensen die bereid zijn om door te zetten, ook op de momenten dat Loki het even lastig heeft en zijn oude wantrouwen opspeelt. 
Voor Loki is een mooie, groene tuin het ultieme geluk. Hij is een echte buitenman die graag via een kattenluikje zijn eigen avonturen beleeft. In een huis zonder andere dieren of kinderen komt Loki het best tot zijn recht. Hij heeft een plekje nodig waar hij de rust en de ruimte krijgt om helemaal zichzelf te zijn.
Ben jij degene die deze bijzondere jongen een liefdevol en geduldig thuis kan bieden? Neem dan contact op, hieronder staat hoe dat werkt. Omdat we heel graag willen dat Loki de juiste baasjes vindt, maakt een stukje begeleiding door onze kattengedragstherapeut mogelijk onderdeel uit van de adoptieprocedure.

KENNISMAKEN EN ADOPTIE:
We verzoeken om de volgende informatie via info.vlaardingen@dierenbescherming.nl te sturen:
naam, adres en telefoonnummerde gezinssamenstelling (indien kinderen, de leeftijden)de woonsituatie (wel/geen tuin/balkon en hoe dat is afgezet, graag foto''s toevoegen)werksituatie/ werktijdende ervaring met katteneventuele andere aanwezige huisdiereneventuele vakantieplannen op korte termijn: We hebben geen mogelijkheid om een dier tot na de vakantie vast te houden en adviseren om pas na de vakantie op zoek te gaan naar een nieuwe huisgenoot.
Het is niet mogelijk om per e-mail of via de telefoon een kat te reserveren. Kennismaken met de asielkatten kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch. Bij meerdere gegadigden maken we een selectie voor de uitnodiging voor het kennismaken op basis van de informatie zoals gegeven in de mail. Let op: katten dienen bij adoptie met een auto opgehaald te worden.
Kenmerken', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_330x285_crop_center-center_none/IMG_9262.jpg?stamp=2604222005&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/IMG_9262.jpg?stamp=2604222005&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/IMG_9262.jpg?stamp=2604222005&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/IMG_9262.jpg?stamp=2604222005&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/IMG_9775.jpg?stamp=2604222005&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/IMG_9263.jpg?stamp=2604222005&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/IMG_9262.jpg?stamp=2604222005&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/IMG_9262.jpg?stamp=2604222005&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/IMG_9262.jpg?stamp=2604222005&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/IMG_9775.jpg?stamp=2604222005&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/IMG_9263.jpg?stamp=2604222005&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301030&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4591911-loki'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4591911-loki')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Gizmo', 'Hoi allemaal, mijn naam is Gizmo en ik ben 7 jaar oud.Mijn baasje kon helaas niet meer voor mij zorgen, en daarom ben ik in de opvang terechtgekomen. In het begin vond ik dat best spannend en een beetje eng. Ik was zo van slag dat ik zelfs niet meer wilde eten. Gelukkig mocht ik al snel naar een gastgezin verhuizen.Ook daar moest ik even wennen, maar al snel kreeg ik door dat het daar veilig was. Ik begon weer zelfstandig te eten en ontdekte hoe fijn het is om onder mijn kin gekriebeld te worden. Volgens mijn gastgezin ben ik een hele lieve kat, en af en toe speel ik ook nog graag met een hengeltje.Na een tijdje merkte mijn gastgezin dat ik moeite had met springen. Soms trilt mijn pootje een beetje, en omdat katten helaas niet kunnen vertellen wat er precies aan de hand is, ben ik naar de dierenarts geweest. Daar zijn foto’s gemaakt van mijn rug en heupen. Hierop was gelukkig niets ernstigs te zien, alleen een klein randje op mijn heupen dat mogelijk verklaart waarom springen voor mij lastig is. Een tweede dierenarts denkt dat dit iets is waar ik al mijn hele leven mee leef.Ik krijg pijnstilling, waardoor bewegen en ergens op klimmen al een stuk beter gaat. Daarnaast heb ik soms wat gevoelige darmen, maar daar krijg ik ook medicatie voor en dat gaat gelukkig goed.Wat betekent dit voor mij? Ik ben misschien geen topspringer, maar ik ben wel een enorme knuffelkont. Ik ben graag bij je in de buurt en geniet van gezelschap. Een rustig huis, zoals een appartement met een katveilig balkon, zou perfect voor mij zijn. Een fijne bank om op te slapen… en misschien zelfs een plekje bij jou op bed? Dat lijkt me heerlijk.Ik ben op zoek naar een speciaal baasje dat mijn medische achtergrond geen probleem vindt en mij gewoon ziet voor wie ik ben: een lieve, gezellige huisgenoot.Hopelijk mag ik snel mijn koffertje pakken en verhuizen naar mijn eigen thuis.Zie ik jouw mailtje binnenkort in onze inbox verschijnen?
KENNISMAKEN EN ADOPTIE:
We verzoeken om de volgende informatie via info.vlaardingen@dierenbescherming.nl te sturen:
naam, adres en telefoonnummerde gezinssamenstelling (indien kinderen, de leeftijden)de woonsituatie (wel/geen tuin/balkon en hoe dat is afgezet, graag foto''s toevoegen)werksituatie/ werktijdende ervaring met katteneventuele andere aanwezige huisdiereneventuele vakantieplannen op korte termijn: We hebben geen mogelijkheid om een dier tot na de vakantie vast te houden en adviseren om pas na de vakantie op zoek te gaan naar een nieuwe huisgenoot.
Het is niet mogelijk om per e-mail of via de telefoon een kat te reserveren. Kennismaken met de asielkatten kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch. Bij meerdere gegadigden maken we een selectie voor de uitnodiging voor het kennismaken op basis van de informatie zoals gegeven in de mail. Let op: katten dienen bij adoptie met een auto opgehaald te worden
Kenmerken', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_330x285_crop_center-center_none/Gizmo2.jpeg?stamp=2604231345&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/Gizmo2.jpeg?stamp=2604231345&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/Gizmo2.jpeg?stamp=2604231345&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Gizmo2.jpeg?stamp=2604231345&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Gizmo.jpeg?stamp=2602271423&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Gizmo3.jpeg?stamp=2602271423&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Gizmo1.jpeg?stamp=2602271423&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/Gizmo2.jpeg?stamp=2604231345&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/Gizmo2.jpeg?stamp=2604231345&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Gizmo2.jpeg?stamp=2604231345&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Gizmo.jpeg?stamp=2602271423&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Gizmo3.jpeg?stamp=2602271423&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Gizmo1.jpeg?stamp=2602271423&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301030&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4532022-gizmo'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4532022-gizmo')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Spijkenisse', 'Rebel', 'Update 1 mei: Sinds vandaag heeft Rebel besloten dat wij toch erg lief voor hem zijn. Er schuild een lieve schootkat in hem. Vanochtend kwam hij voor het eerst aandacht zoeken en kroop hij tevreden op schoot. Daarna heeft hij ook nog een poosje liggen rollebollen. Natuurlijk verwachten we nog weinig van hem en laten we hem zijn eigen tempo aangeven. To be continued....
Rebel is een zwart-witte gecastreerde kater van bijna 2 jaar oud. Deze gevoelige jongeman is met veel verdriet afgestaan omdat hij niet overweg kon met de oude poes in huis.
Sommige katten kunnen niet aarden in een asiel en Rebel is er daar 1 van. Wij doen ons uiterste best om zijn verblijf zo aangenaam mogelijk te maken en hem zo min mogelijk stress te geven maar hij kan er geen vrede mee hebben dat hij in het asiel zit. Daarom zijn wij nu op zoek naar een rustig huisje waar hij alle tijd en ruimte krijgt om zichzelf weer te worden. Bij zijn vorige baasje was rebel namelijk best een gezellig mannetje, wel 1 met grenzen, die graag speelde en goed overweg kon met de kleine hondjes. Helaas is Rebel te vroeg uit het nest gehaald waardoor hij nooit echt heeft geleerd om kat te zijn en om te gaan met frustraties in het leven. Met de juiste begeleiding in een goede omgeving kan Rebel ook een leuk maatje worden! Een huis met tuin of groot katveilig dakterras staat op zijn wensen lijstje want rebel is nieuwsgierig naar zijn omgeving.
Denk jij dat je Rebel die veilige haven kunt bieden waar hij zo naar verlangt? Wonen/komen er bij jou geen kindjes over de vloer? Ben jij geduldig en kun je hem alle tijd en ruimte bieden? Vul dan het interesse formulier in en wie weet kunnen wij een afspraak maken voor een vrijblijvende kennismaking en weet jij Rebel''s hart te veroveren.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_330x285_crop_center-center_none/IMG-20260408-WA0020.jpg?stamp=2604121305&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260408-WA0020.jpg?stamp=2604121305&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260408-WA0020.jpg?stamp=2604121305&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0020.jpg?stamp=2604121305&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0022_2026-04-12-110527_jrys.jpg?stamp=2604121305&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0024_2026-04-12-110526_kodu.jpg?stamp=2604121305&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0021.jpg?stamp=2604121305&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/rebelhond.jpg?stamp=2604211159&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/rebel3.jpg?stamp=2604211201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/Actueel/_800x550_crop_center-center_none/20260501_110419.jpg?stamp=2605011410&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/Actueel/_800x550_crop_center-center_none/20260501_140749.jpg?stamp=2605011411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/Actueel/_800x550_crop_center-center_none/20260501_140729.jpg?stamp=2605021255&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0020.jpg?stamp=2605061356&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0021.jpg?stamp=2605061355&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0022.jpg?stamp=2605061355&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4582071-rebel'
from public.shelters s
where s.name = 'Dierenopvangcentrum Spijkenisse'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4582071-rebel')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Prije', 'Maak kennis met Prijé: een dame die het leven benadert als een goede film — eerst even kijken hoe het afloopt voordat ze zelf in beeld verschijnt. In haar verblijf is ze geen type “hallo hier ben ik!”, maar eerder “ik zie jullie wel hoor… vanachter haar geheime observatiepost.”
Ben jij rustig, geduldig én in het bezit van een smakelijk snackje? Dan heb je haar aandacht. Pas wanneer de sfeer kalm is en er iets lekkers wordt aangeboden, besluit Prijé dat het veilig genoeg is om voorzichtig tevoorschijn te komen. Alsof ze denkt: oké… dit is het moment. Ga je niet te snel, dan kun je haar tijdens het snacken voorzichtig over haar rug aaien. En zie je haar staart fier overeind komen met haar kontje een beetje omhoog? Dan weet je: aandacht vindt ze stiekem toch wel erg prettig. En eerlijk is eerlijk: dat moment is het wachten meer dan waard.
Geef je haar dan zachtjes aandacht, dan zie je hoe ze daar zichtbaar van geniet. Maar… plotselinge bewegingen of drukte? Daar doet mevrouw niet aan mee. Dan is het: exit Prijé, terug naar haar veilige plekje. En eerlijk? Groot gelijk heeft ze.
Prijé is een gevoelige, zachtaardige kat die geen haast heeft. En precies dát maakt haar zo bijzonder. Met geduld, rust en misschien af en toe een culinair omkoopmiddel groeit er een band die misschien wat langer duurt, maar daardoor juist extra waardevol is. Geen snelle vriendschap, maar eentje voor het leven.
Voor deze dame zoeken we een thuis waar:
rust en voorspelbaarheid de norm zijn (chaos is overrated)geen kinderen of andere huisdieren aanwezig zijnze lekker zichzelf mag zijn, ook als dat betekent: eerst verstoppen, dan pas hallo zeggengenoeg knusse schuilplekjes zijn (hoe meer, hoe beter!)haar tempo wordt gevolgd — zij bepaalt het tempo, jij past je aan 😉ze na gewenning lekker naar buiten kan om haar eigen rustige avonturen te beleven
Wat krijg je ervoor terug?Een bijzondere vriendin die langzaam maar zeker haar zachte, lieve karakter laat zien. En geloof ons: als je haar vertrouwen wint, voelt dat als het winnen van de jackpot — maar dan met snorharen en een zacht spinnetje erbij.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/4588659/prije2.jpg?stamp=2604191520&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4588659/prije2.jpg?stamp=2604191520&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4588659/prije2.jpg?stamp=2604191520&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588659/prije2.jpg?stamp=2604191520&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588658/Prije1.jpg?stamp=2604191520&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588661/prije4.jpg?stamp=2604191520&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588660/prije3.jpg?stamp=2604191520&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588662/prije5.jpg?stamp=2604191521&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4588659/prije2.jpg?stamp=2604191520&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4588659/prije2.jpg?stamp=2604191520&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588659/prije2.jpg?stamp=2604191520&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588658/Prije1.jpg?stamp=2604191520&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588661/prije4.jpg?stamp=2604191520&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588660/prije3.jpg?stamp=2604191520&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588662/prije5.jpg?stamp=2604191521&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4588657-prije'
from public.shelters s
where s.name = 'Dierencentrum Achterhoek'
