insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Bendaughter', 'Een zachtaardige dame die het liefst eerst even de kat uit de boom kijkt — en geef haar eens ongelijk. In haar buitenverblijf is Bendaughter geen haantje-de-voorste. Vanuit haar zelfgekozen schuilplekje houdt ze rustig en nieuwsgierig in de gaten wie er binnenkomt.
Benader je haar op een kalme, vriendelijke manier? Dan gebeurt er iets moois.Voorzichtig komt ze tevoorschijn en geniet ze zichtbaar van de aandacht die je haar geeft. Maar onverwachte bewegingen of drukte vindt ze nog spannend — dan kiest ze snel weer voor de veiligheid van haar vertrouwde plekje.
Bendaughter is een poes die vraagt om zachtheid… en diezelfde zachtheid ook volop teruggeeft. Met geduld, rust en wederzijds respect groeit er een band die steeds sterker wordt. Geen snelle vriendschap, maar juist eentje die bijzonder waardevol is.
Voor Bendaughter zoeken we een liefdevol thuis waar:
Rust en voorspelbaarheid centraal staanGeen kinderen of andere huisdieren aanwezig zijnZe helemaal zichzelf mag zijn, ook als ze wat langer nodig heeft om te wennenFijne schuilplekjes aanwezig zijn waar ze zich veilig kan terugtrekkenHaar tempo wordt gevolgd, zonder verwachtingenze na gewenning vrij naar buiten kan – ook om haar eigen avonturen in de buurt te beleven.
Wat je ervoor terugkrijgt?Een bijzondere vriendin die, als je haar vertrouwen eenmaal hebt gewonnen, haar zachte en lieve karakter steeds meer laat zien.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/4588497/bendaughter2.jpg?stamp=2604191328&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4588497/bendaughter2.jpg?stamp=2604191328&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4588497/bendaughter2.jpg?stamp=2604191328&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588497/bendaughter2.jpg?stamp=2604191328&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588498/IMG_2216.jpg?stamp=2604191328&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588496/bendaughter1.jpg?stamp=2604191328&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4588497/bendaughter2.jpg?stamp=2604191328&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4588497/bendaughter2.jpg?stamp=2604191328&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588497/bendaughter2.jpg?stamp=2604191328&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588498/IMG_2216.jpg?stamp=2604191328&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588496/bendaughter1.jpg?stamp=2604191328&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_882x1004_crop_center-center_none/EXTERN-ASIEL-HEADER-KAT-885x1005.png?stamp=2306291600&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4588477-bendaughter'
from public.shelters s
where s.name = 'Dierencentrum Achterhoek'
