insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Miaust Klein', 'Maak kennis met Miaust Klein: een zachte ziel met een talent voor… verstoppen. Serieus, deze dame is een soort kampioen verstoppertje. Het is altijd weer een verrassing waar je haar gaat vinden. Maar meestal heeft ze haar zachte fluffie mandje over haar hoofd ;-)
Maar geef haar even de tijd (en een rustige stem), en er gebeurt iets moois. Als je zachtjes tegen haar praat of haar voorzichtig een kriebeltje geeft, komt ze nieuwsgierig tevoorschijn. En dan zie je het: ze vindt aandacht eigenlijk best heel fijn. Grote kans dat ze zelfs besluit om gezellig samen met jou een hapje te eten—want ja, samen is toch leuker dan alleen.
Miaust is wel een gevoelig dametje. Harde geluiden of drukke bewegingen? Dan denkt ze: “nope” en trekt ze zich weer terug in haar veilige bubbel. Gelukkig herstelt ze ook weer als de rust terugkeert.
Daarom zoeken we voor haar een kalm, stabiel thuis:
Geen kinderen (die zijn haar nét iets te enthousiast)Liefst geen andere dieren (ze tolereert ze wel, maar solo is ze op haar best)Een plek waar ze in haar eigen tempo mag wennen en ontdekkenEn waar ze, als ze daar klaar voor is, veilig vrij naar buiten kan vanuit haar eigen tuin de buurt in.
Miaust heeft geen haast. Ze zoekt iemand die dat begrijpt. Iemand die haar de ruimte geeft, haar respecteert en geniet van de kleine overwinningen—zoals een eerste kopje, een voorzichtig spinnetje, of samen een stil momentje.
Ben jij op zoek naar pure schoonheid en heb je het geduld om haar vertrouwen te winnen?Dan zou Miaust zomaar eens jouw perfecte avontuur kunnen zijn.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/4588473/Tayler1_2026-04-19-112412_uemk.jpg?stamp=2604191324&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4588473/Tayler1_2026-04-19-112412_uemk.jpg?stamp=2604191324&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4588473/Tayler1_2026-04-19-112412_uemk.jpg?stamp=2604191324&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588473/Tayler1_2026-04-19-112412_uemk.jpg?stamp=2604191324&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588474/tayler2_2026-04-19-112413_mylo.jpg?stamp=2604191324&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4588473/Tayler1_2026-04-19-112412_uemk.jpg?stamp=2604191324&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4588473/Tayler1_2026-04-19-112412_uemk.jpg?stamp=2604191324&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588473/Tayler1_2026-04-19-112412_uemk.jpg?stamp=2604191324&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4588474/tayler2_2026-04-19-112413_mylo.jpg?stamp=2604191324&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_882x1004_crop_center-center_none/EXTERN-ASIEL-HEADER-KAT-885x1005.png?stamp=2306291600&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4588472-taylor-sniff'
