insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Spijkenisse', 'Dirk', 'Dirk is een gecastreerde kater van 14 jaar oud. Deze knappe senior is bij ons terecht gekomen nadat hij afscheid moest nemen van zijn beide baasjes.
Wij zoeken voor deze prachtige senior kater een huisje die hij niet hoeft te delen met andere dieren.Dirk kan hun aanwezigheid zeker niet waarderen en durft nog steeds een confrontatie aan te gaan.
Een volledig afgesloten tuin, lees er kan geen kat in of uit komen, is een vereiste want Dirk wil de wind door zijn haren voelen, de zon op zijn snoet hebben en ieder vogeltje/muisje/voorbijganger of blaadje nauwlettend in de gaten houden. Hij verwacht wel 24 uur per dag vrije keus door middel van een kattenluikje!
Uit bloedonderzoek is gebleken dat Dirk''s schildklier wat ondersteuning nodig heeft. Daarom krijgt hij 2 maal daags medicatie.


Ben jij op zoek naar een maatje en is het voor jou geen enkel probleem om Dirk zijn medicatie te geven? Vul dan het interesse formulier in en wie weet kunnen wij een afspraak maken voor een vrijblijvende kennismaking met knappe senior Dirk.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_330x285_crop_center-center_none/IMG-20260420-WA0010.jpg?stamp=2604201213&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260420-WA0010.jpg?stamp=2604201213&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260420-WA0010.jpg?stamp=2604201213&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0010.jpg?stamp=2604201213&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0007.jpg?stamp=2604201212&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/Dirk2.jpeg?stamp=2604171156&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0006.jpg?stamp=2604201212&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/Dirk1.jpeg?stamp=2604171156&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0011.jpg?stamp=2604201213&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0002.jpg?stamp=2604201212&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0008.jpg?stamp=2604201213&tag=xs', 'https://cms.dierenbescherming.nl/assets/diere