insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', 'Ody', 'Ody is een kater met een uitgesproken karakter. Het is een jongen die goed weet wat hij wil en daarbij erg zelfstandig is. Het is geen kat die echt de mensen op zoekt voor aandacht maar hij zoekt wel een huis waar hij ook gezellig binnen mag zijn in de buurt van mensen. Hij houdt van warme, zachte schuilhuisjes.
Daarnaast zoekt hij een plek waar hij lekker buiten mag rondstruinen, hij heeft het liefst een rustige groene omgeving waar hij de ruimte en vrijheid heeft om op ontdekking te gaan.
Ody kan, wanneer iemand zijn duidelijke grenzen respecteert, echt een aanwinst zijn in je huis. Gun jij hem die plek?', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_330x285_crop_center-center_none/4593481/ody-2.jpg?stamp=2604241726&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_384x330_crop_center-center_none/4593481/ody-2.jpg?stamp=2604241726&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_519x453_crop_center-center_none/4593481/ody-2.jpg?stamp=2604241726&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593481/ody-2.jpg?stamp=2604241726&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/ody1.jpg?stamp=2604271454&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/odyyy.jpg?stamp=2604161117&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_384x330_crop_center-center_none/4593481/ody-2.jpg?stamp=2604241726&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_519x453_crop_center-center_none/4593481/ody-2.jpg?stamp=2604241726&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593481/ody-2.jpg?stamp=2604241726&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/ody1.jpg?stamp=2604271454&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/odyyy.jpg?stamp=2604161117&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_882x1004_crop_center-center_none/banner-beeld-hond-close-885.png?stamp=2504161034&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4583452-ody'
from public.shelters s
