insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Spijkenisse', 'X-zie', 'X-zie is een zwart-witte kater van ongeveer 1 jaar oud geschat. Deze knappe kater is bij ons gebracht nadat hij bedacht had een nieuw huisje uitgezocht te hebben. X-zie heeft een chip maar helaas is deze nergens geregistreerd en zijn baasje hebben wij nog niet kunnen achterhalen. Zijn naam heeft hij gekregen van de bewoners waar hij zich steeds melde omdat zij vonden dat hij x- benen heeft.
Wanneer je kennis komt maken met X-zie is de kans groot dat hij rustig vanaf zijn krabpaal bekijkt wie jij bent en of je echt bij hem komt kijken. Eenmaal in zijn verblijf komt X-zie zich graag voorstellen maar wel op zijn gemak en zijn tijd. Eenmaal voorgesteld kijkt hij je met zijn zieligste uitdrukking aan in de hoop dat je zijn voerbakje nog een keer vult. Er schuilt in hem ook een ware voetballer. Pingpong balletjes zijn favoriet bij hem maar wil je hem helemaal euforisch zien; kattenkruid! Hij wrijft het liefst zijn hele lijf er mee in. Luidruchtig is deze jongeman zeker! Wanneer hij iets wil dan wil hij het ook meteen. X-zie is een tikkeltje dramatisch hierin dus zijn nieuwe personeelsleden moeten zijn gezang wel kunnen waarderen. 
Andere katten vindt hij maar niets. Zijn spotlight wil hij niet delen.
Wij zoeken voor deze kleine gespierde drama Queen een huis die hij niet hoeft te delen met andere dieren. Een lekkere groene tuin ( het liefst met kattenkruid plantjes als het aan X-zie ligt) waar hij door middel van een kattenluikje gebruik van kan maken.
Denk jij dat X-zie helemaal bij jou past? Vul dan het interesse formulier in en wie weet kunnen wij binnenkort een afspraak maken voor een vrijblijvende kennismaking.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_330x285_crop_center-center_none/IMG-20260506-WA0047.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260506-WA0047.jpg?stamp=2605061801&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260506-WA0047.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0047.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0056.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0055.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0050.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0048.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0052.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0051.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0049.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0053.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0057.jpg?stamp=2605061801&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260506-WA0047.jpg?stamp=2605061801&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260506-WA0047.jpg?stamp=2605061801&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4583055-x-zie'
from public.shelters s
where s.name = 'Dierenopvangcentrum Spijkenisse'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4583055-x-zie')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Romulus', 'Hé, ik ben Romulus en ik ben 2 jaar oud geschat. Volgens buurtbewoners ben ik achtergelaten samen met nog een andere kat na verhuizing.
Ik ben bang, het asiel vind ik eng. Wie zijn die mensen? Wie ben jij? Wat kom je doen? Als ik je vertrouw ben ik een echte knuffelbeer, dol op aaien en spring zelf om kopjes te geven langs je hand.
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
