insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Fiji', 'Koekoek, ik ben Fiji en ik ben 4 jaar oud geschat! Ik ben gevonden samen met nog andere katjes als zwervertje. Vermoedelijk achtergelaten door ons baasje.
Ik had een wondje aan mijn oor, dit is dus gedeeltelijk weggehaald. Heb ik geen last van hoor!
Ik zoek een geduldig baasje, iemand die me de tijd geeft om te wennen.
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag verzoeken wij je eerst een kennismakingsmail te sturen naar limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Fiji2.png?stamp=2604151034&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Fiji2.png?stamp=2604151034&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Fiji2.png?stamp=2604151034&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Fiji2.png?stamp=2604151034&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Fiji_2026-04-15-083424_jkgo.png?stamp=2604151034&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Fiji2.png?stamp=2604151034&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Fiji2.png?stamp=2604151034&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Fiji2.png?stamp=2604151034&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Fiji_2026-04-15-083424_jkgo.png?stamp=2604151034&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4582488-fiji'
