insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Spijkenisse', 'Flyn', 'Flyn is een cypers-witte gecastreerde kater van ongeveer 3 jaar oud geschat. Deze verlegen kater is bij een dierenarts gebracht omdat hij zich niet lekker leek te voelen. Gelukkig leek dit mee te vallen en is Flyn recent gecastreerd bij ons.
Wanneer je kennis komt maken met Flyn zie je hem waarschijnlijk niet direct maar hij heeft jou zeker al gezien en houdt je in de gaten. Flyn is namelijk nog een tikje verlegen en onzeker maar als je rustig de tijd voor hem neemt durft hij stapje voor stapje meer vertrouwen te krijgen. Eenmaal vertrouwt ontpopt Flyn zich in een lieve kater die geniet van een aai en een lief woord en zelfs speelt met een speelmuisje. Alle geluiden in de opvang vindt hij heel spannend, en trekt zich dan ook terug, maar wij hebben er alle vertrouwen in dat het met Flyn in een stabiele omgeving met de juiste begeleiding helemaal goed komt.
Wij denken dat een gezin met kindjes niet goed bij Flyn past gezien zijn onzekere en angstige kant. Een stads-kat is Flyn niet, nee hij verlangt meer naar een groene landelijke omgeving waar hij door middel van een kattenluikje toegang toe heeft en zelf kan beslissen of hij gezellig op de bank neerploft om samen tv te kijken.
Ben jij nieuwsgierig geworden? Ben je geduldig en is het bij jou thuis heerlijk rustig? Vul dan zijn interesse formulier in en wie weet kunnen wij binnenkort een afspraak maken voor een vrijblijvende kennismaking.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_330x285_crop_center-center_none/IMG-20260420-WA0013.jpg?stamp=2604201400&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260420-WA0013.jpg?stamp=2604201400&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260420-WA0013.jpg?stamp=2604201400&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0013.jpg?stamp=2604201400&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0066.jpg?stamp=2604121302&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0057_2026-05-06-174405_hrhr.jpg?stamp=2605061944&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0060.jpg?stamp=2605061944&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0016.jpg?stamp=2604201400&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0058.jpg?stamp=2605061944&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0015.jpg?stamp=2604201400&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260506-WA0059.jpg?stamp=2605061944&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0014.jpg?stamp=2604201400&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0012.jpg?stamp=2604201400&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260420-WA0017.jpg?stamp=2604201400&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0068.jpg?stamp=2604121302&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4582056-flyn'
from public.shelters s
where s.name = 'Dierenopvangcentrum Spijkenisse'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4582056-flyn')
