insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Tiktik', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.
Er was eens een knappe, zelfstandige kater die zijn intrede deed als zwerfkatje. Hij zag er verrassend goed uit, alsof hij zijn eigen avontuur al half had uitgeschreven… maar één ding viel meteen op, hij zat écht onder de teken. Zóveel zelfs, dat zijn naam al snel geboren was; Tiktik.
En die naam draagt meer met zich mee dan je misschien denkt. In de Filipijnse mythologie is de Tiktik een mysterieuze, vogelachtige metgezel van de Aswang, een soort vampierachtig wezen, die met zijn geluid mensen op het verkeerde been zet. Onze Tiktik? Die heeft daar gelukkig niets duisters van overgenomen… al heeft hij wél een eigen willetje en weet hij precies hoe hij de regie over zijn leven houdt.
Tiktik is een kater die houdt van zijn vrijheid. Hij kan heerlijk op zichzelf zijn, rustig een fijn plekje opzoeken en genieten van zijn eigen gezelschap. Maar als jij zijn vertrouwen wint, komt hij ook graag wat aandacht halen, op zíjn voorwaarden, natuurlijk. Want zoals een echte mythische naamgenoot betaamt, kiest hij zelf wanneer hij in beeld verschijnt.
Eten? Daar is hij ook dol op. Een goed afgemeten maaltijd is voor hem belangrijk (hij houdt namelijk soms iets té veel van lekker eten), en hij leert al snel wanneer het tijd is om weer naar binnen te komen voor zijn hapje. Na een rustige wenperiode zal hij dan ook graag weer naar buiten trekken, op ontdekkingstocht in zijn eigen territorium.
Tiktik spreekt vloeiend kattentaal en verwacht dat jij daar ook een beetje rekening mee houdt. Ga je over zijn grens, dan laat hij dat duidelijk weten met een keer blazen. Eerlijk is eerlijk: hij geeft gewoon netjes aan wat hij wel en niet fijn vindt. Daarom past hij het beste in een huis zonder kleine kinderen, waar zijn signalen goed begrepen worden.
Kortom: Tiktik is een bijzondere kater met een stoer verleden, een mythische naam en een heel eigen karakter. Geef je hem de ruimte en het respect dat hij verdient? Dan krijg je er een unieke huisgenoot voor terug die precies weet wie hij is.
Pas als uw (compleet) ingevulde formulier binnen is wordt uw aanvraag in behandeling genomen. We zullen dan kijken of u een geschikte match bent voor het dier en dan zullen we u hopelijk telefonisch uitnodigen voor een ontmoeting. Ontmoetingen vinden alleen op afspraak plaats. We kunnen dieren maximaal 1 week "reserveren". (datum van inplannen afspraak tot datum kennismaking).', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1191929-Tiktik-3.jpg?stamp=2604031157&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1191929-Tiktik-3.jpg?stamp=2604031157&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1191929-Tiktik-3.jpg?stamp=2604031157&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191929-Tiktik-3.jpg?stamp=2604031157&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191929-Tiktik-4.jpg?stamp=2604031158&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191929-Tiktik.jpg?stamp=2603251536&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191929-Tiktik-2.jpg?stamp=2604031157&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1191929-Tiktik-3.jpg?stamp=2604031157&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1191929-Tiktik-3.jpg?stamp=2604031157&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191929-Tiktik-3.jpg?stamp=2604031157&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191929-Tiktik-4.jpg?stamp=2604031158&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191929-Tiktik.jpg?stamp=2603251536&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191929-Tiktik-2.jpg?stamp=2604031157&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4567641-tiktik'
from public.shelters s
where s.name = 'De Kuipershoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4567641-tiktik')
limit 1;

