insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Dudley', 'Voor Dudley vragen we graag uw extra aandacht. Dudley is een prachtige cyper-witte kater van 5 jaar oud die zich hier in het begin wat meer op de achtergrond hield en daardoor niet meteen opviel bij bezoekers. Maar wie hem beter leert kennen, ontdekt al snel wat een bijzonder katje hij is, en hij laat zich steeds vaker zien.
Zijn start was niet makkelijk, maar Dudley heeft al mooie stappen gezet. Waar hij eerst erg bang en overweldigd was, zien we nu een kat die steeds meer vertrouwen krijgt. Hij is nog steeds een gevoelige en voorzichtige jongen, maar achter zijn stoere uiterlijk zit een zacht karakter dat hij steeds vaker durft te laten zien.
En dat vertrouwen groeit: Dudley begint uit zichzelf naar je toe te komen voor een aai en geeft graag kopjes tegen je been. Ook is hij vocaal behoorlijk aanwezig, hij laat goed van zich horen en zoekt op zijn eigen manier contact. Dat maakt hem juist zo charmant en uniek.
Voor Dudley zoeken we een baasje met ervaring en vooral veel geduld. In een nieuwe omgeving zal hij waarschijnlijk weer even moeten wennen en mogelijk een stapje terug doen. Met rust, begrip en tijd zal hij echter weer openbloeien. Met eten kun je gelukkig veel bij hem bereiken, dat vindt hij vaak nét iets interessanter dan zijn spanning. Dat maakt het voor de nieuwe eigenaar ook een mooie, maar realistische uitdaging. Een rustige woonomgeving met één of twee personen, zonder kinderen, past het beste bij hem.
Dudley geniet zichtbaar van het buiten zijn en ligt graag in het zonnetje. Daarom denken wij dat een huis met een tuin ideaal voor hem zou zijn.
Hij heeft nog een weg te gaan, maar hij laat nu al zien hoeveel vooruitgang hij kan boeken. Wie weet wil hij die weg samen met u bewandelen? Aan het einde wacht misschien geen typische knuffelkat, maar wél een bijzondere, groeiende band die elke stap meer dan waard maakt.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Dudley-01.jpeg?stamp=2605042327&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Dudley-01.jpeg?stamp=2605042327&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Dudley-01.jpeg?stamp=2605042327&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dudley-01.jpeg?stamp=2605042327&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dudley-02.jpeg?stamp=2605042327&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dudley-2.jpg?stamp=2604231550&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dudley-1.jpg?stamp=2604231550&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Dudley-01.jpeg?stamp=2605042327&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Dudley-01.jpeg?stamp=2605042327&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dudley-01.jpeg?stamp=2605042327&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dudley-02.jpeg?stamp=2605042327&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dudley-2.jpg?stamp=2604231550&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Dudley-1.jpg?stamp=2604231550&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4579476-dudley'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4579476-dudley')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Tottie', 'Hoi! Ik ben Tottie — negen jaar jong en altijd klaar voor gezelligheid!
Als jij ergens zit, dan kom ik er graag meteen bij. Niet omdat ik opdringerig ben hoor… nou ja, misschien een béétje. Maar ik ben nu eenmaal dol op aandacht. Praatjes? Ja graag. Ik miauw terug alsof we een echt gesprek voeren. Aaitjes? Nog liever! Hier kan ik geen genoeg van krijgen.
Ik houd van spelen, zeker met een hengel waar ik achteraan kan springen. En als je me kattenkruidspeelgoed geeft… nou, dan zie je mij rare sprongetjes maken waar je vast om moet lachen. Daarna plof ik tevreden neer, liefst heel dicht bij jou.
Mijn droomhuis? Eentje met een tuin! Dan kan ik lekker frisse lucht snuiven, wat rondscharrelen en de buurt inspecteren. Maar aan het einde van de dag kruip ik binnen graag weer tegen je aan.
En nu het serieuze deel van mijn verhaal:Ik heb diabetes. Dat betekent dat ik dagelijks een beetje insuline krijg en speciaal voer eet. Gelukkig voel ik me daar uitstekend bij. Vooral als jij er bent om me een knuffel en wat lekkers te geven. Want met wat liefde en aandacht bereik je een hele hoop! Ik ben dus wel op zoek naar iemand die mij durft te prikken en een relatief gestructureerd leven heeft waar het zorgen voor mij goed bij past. 
Heb jij zin in een lieve uitdaging? Wil jij mij graag een huisje geven waar ik alle liefde en zorg krijg? Neem dan contact op met het Dierentehuis en wie weet tot snel!', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/tottie-nieuw.jpeg?stamp=2604161418&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/tottie-nieuw.jpeg?stamp=2604161418&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/tottie-nieuw.jpeg?stamp=2604161418&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/tottie-nieuw.jpeg?stamp=2604161418&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Tottie.jpg?stamp=2604041522&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Tottie3.jpg?stamp=2604041522&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/tottie-nieuw.jpeg?stamp=2604161418&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/tottie-nieuw.jpeg?stamp=2604161418&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/tottie-nieuw.jpeg?stamp=2604161418&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Tottie.jpg?stamp=2604041522&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Tottie3.jpg?stamp=2604041522&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4576900-tottie'
from public.shelters s
where s.name = 'Dierentehuis Kennemerland'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4576900-tottie')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Hay', 'Hay,... ik ben Hay! Ik ben 3,5 jaar oud geschat en een hele knappe kater. Als zwerver gevonden in een tuin. Ik bewoog niet meer en eerst dacht men dat ik dood was. Uiteindelijk bleek ik vergiftigd te zijn. Ik kon mezelf niet meer bewegen door het gif en mijn organen waren langzaam aan het opgeven. Maar gelukkig kwam daar de dierenambulance. Hop naar de dierenarts en na een nachtje aan het infuus voelde ik me weer stukken beter!
Ik ben wel nieuwsgierig naar mensen maar laat me zeker nog niet aaien. Wat ik dus zoek is iemand met geduld, liefde en kattenervaring waar ik mag opbloeien!
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Walter2.png?stamp=2604031955&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Walter2.png?stamp=2604031955&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Walter2.png?stamp=2604031955&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Walter2.png?stamp=2604031955&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Walter2.png?stamp=2604031955&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Walter2.png?stamp=2604031955&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Walter2.png?stamp=2604031955&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4576319-hay'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4576319-hay')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
