?stamp=2604031159&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1189694-Murtuhunut-Tahti.jpg?stamp=2604031159&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1189694-Murtuhunut-Tahti.jpg?stamp=2604031159&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1189694-Murtunut-Tähti-1.jpg?stamp=2601191636&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1189694-Murtunut-Tähti-6.jpg?stamp=2601191636&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4509229-murtunut-t%C3%A4hti'
from public.shelters s
where s.name = 'De Kuipershoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4509229-murtunut-t%C3%A4hti')
