insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Rinus (FIV)', 'Rinus is een lieve kater met een onweerstaanbare bolle toet die al snel ieders aandacht weet te trekken. Hij kwam bij ons binnen als vondeling en al gauw werd duidelijk dat hij een echte stoere jongen is die een confrontatie met andere katten niet uit de weg gaat. Zijn lijfje vertelde dat verhaal ook: krassen, wondjes en kleine littekens. Het vermoeden dat hij kattenaids (FIV) heeft, werd helaas bevestigd. Daarom zoeken we voor hem een passend en veilig thuis.
Rinus vindt het heel leuk als je hem komt bezoeken. Hij komt meteen naar je toe om je te begroeten en geeft je graag een flinke dosis kopjes. Echt een knuffelaar! Tegelijkertijd is Rinus ook duidelijk in zijn grenzen. Soms kan hij nog wat onzeker zijn en als hij iets spannend vindt of als je hem op een gevoelig plekje aanraakt kan hij dat met een knauw laten weten. Gelukkig duurt dat nooit lang: vaak komt hij daarna alweer “sorry” zeggen met nóg meer kopjes. Naast mensen heeft Rinus nog een grote liefde: eten! Hij is een echte bourgondiër en dol op zijn brokjes en snacks. Let dus goed op, want eten onbeheerd laten staan is met Rinus in de buurt geen goed idee.
Voor Rinus zoeken we een rustig en ervaren thuis. Mensen die katten goed kunnen lezen en aanvoelen wanneer het hem even te veel wordt. Kleine kinderen zijn voor hem te spannend, maar kinderen vanaf 12 jaar met kattenervaring mogen zeker langskomen om te kijken of er een klik is. Rinus geniet enorm van buiten zijn en gezien zijn zwerversverleden denken we dat een balkon niet voldoende voor hem is. Daarom zoeken we een huis met een volledig catproof tuin, waar hij veilig kan genieten zonder dat er andere katten in of uit kunnen. Vanwege de kattenaids heeft Rinus een zwakkere afweer en hierdoor is hij sneller vatbaar voor, in eerste instantie onschuldige, kwaaltjes. Ondanks dat is de kans ook groot dat Rinus gewoon gezond oud kan worden.
Ben jij die rustige, liefdevolle en ervaren kattenliefhebber die Rinus een tweede kans wil geven? Vul dan het aanvraagformulier in bij stap 3.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/4573754/DSC_0107_2026-04-01-092339_mrks.jpg?stamp=2604011200&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/4573754/DSC_0107_2026-04-01-092339_mrks.jpg?stamp=2604011200&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/4573754/DSC_0107_2026-04-01-092339_mrks.jpg?stamp=2604011200&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573754/DSC_0107_2026-04-01-092339_mrks.jpg?stamp=2604011200&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573751/DSC_0101_2026-04-01-092335_tdqy.jpg?stamp=2604011200&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573757/DSC_0130_2026-04-01-092350_slck.jpg?stamp=2604011201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573756/DSC_0121_2026-04-01-092347_xxku.jpg?stamp=2604011202&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573755/DSC_0112_2026-04-01-092343_yvrk.jpg?stamp=2604011201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/4573754/DSC_0107_2026-04-01-092339_mrks.jpg?stamp=2604011200&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/4573754/DSC_0107_2026-04-01-092339_mrks.jpg?stamp=2604011200&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573754/DSC_0107_2026-04-01-092339_mrks.jpg?stamp=2604011200&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573751/DSC_0101_2026-04-01-092335_tdqy.jpg?stamp=2604011200&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573757/DSC_0130_2026-04-01-092350_slck.jpg?stamp=2604011201&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573756/DSC_0121_2026-04-01-092347_xxku.jpg?stamp=2604011202&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4573755/DSC_0112_2026-04-01-092343_yvrk.jpg?stamp=2604011201&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4573749-rinus'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4573749-rinus')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Ollie', 'Ik ben Ollie, vijf jaar oud geschat door de dierenarts en gevonden als zwerver. Ook ik ben een onzichtbaar zieltje in het asiel. Verstopt, laat me nog niet aaien en voel me hier niet fijn. Geduld is wat ik zoek en een baasje met wel kattenervaring. Iemand die rustig een vertrouwensband met me wilt opbouwen en me alle tijd geeft van de wereld.
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Ollie_2026-04-07-164135_dyhf.png?stamp=2604071841&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Ollie_2026-04-07-164135_dyhf.png?stamp=2604071841&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Ollie_2026-04-07-164135_dyhf.png?stamp=2604071841&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Ollie_2026-04-07-164135_dyhf.png?stamp=2604071841&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Ollie_2026-04-07-164135_dyhf.png?stamp=2604071841&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Ollie_2026-04-07-164135_dyhf.png?stamp=2604071841&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Ollie_2026-04-07-164135_dyhf.png?stamp=2604071841&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4572643-ollie'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4572643-ollie')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Walter', 'Walter is mijn naam, vijf jaar oud geschat en als zwerver gevonden. Ik ben onzichtbaar in het asiel. De meeste mensen weten niet eens dat ik er ben. Dat komt ook omdat ik bang ben en eigenlijk altijd verstop zit.
Ik zoek een baasje die me de tijd geeft die ik nodig heb en mij wel ziet zitten.
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Walter.png?stamp=2604031954&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Walter.png?stamp=2604031954&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Walter.png?stamp=2604031954&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Walter.png?stamp=2604031954&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Walter.png?stamp=2604031954&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Walter.png?stamp=2604031954&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Walter.png?stamp=2604031954&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4572612-walter'
