insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Billy en Zwollie', 'Billy & Zwollie: Twee onafscheidelijke harten op zoek naar een rustig pensioen
Maak kennis met Billy en Zwollie, twee prachtige broers op leeftijd die laten zien dat echte vriendschap voor het leven is. Met hun 13,5 jaar zijn ze de jongsten niet meer, maar hun band is sterker dan ooit. Deze twee heren horen bij echt bij elkaar en hebben veel steun aan elkaar; waar de één is, is de ander nooit ver weg.
Voor Billy en Zwollie zijn we op zoek naar een kalm en voorspelbaar huishouden. Een plek zonder andere honden of katten, waar ze in hun eigen tempo de boel kunnen verkennen. Een Katveilig balkon is een grote wens, Zo kunnen ze op hun gemak naar de vogeltjes kijken en een frisse neus halen, zonder de drukte van de straat.
Hoewel ze broers zijn, hebben ze elk hun eigen karakter:
Zwollie is de dapperste van de twee. Als hij zich eenmaal op zijn gemak voelt, komt hij graag bij je voor een flinke portie aandacht. Hij is een echte fijnproever wat betreft aaitjes, zolang hij maar zelf het initiatief mag nemen.
Billy is de meer introverte broer. Hij kijkt de kat uit de boom en heeft wat langer de tijd nodig om uit zijn schulp te kruipen. Hij zoekt een baasje dat hem die ruimte geeft en begrijpt dat zijn liefde groeit met geduld. Wie biedt deze senioren een warm mandje?
Ben jij dat lieve en geduldige baasje dat snapt dat "thuis" voor deze twee een plek is waar niets moet en alles mag? Billy en Zwollie hebben niet veel nodig: een zacht kussen, een rustige omgeving en een mens die begrijpt dat liefde soms wat tijd nodig heeft.
Krijgen deze twee onafscheidelijke broers bij jou hun welverdiende gouden mandje?
KENNISMAKEN EN ADOPTIE:
We verzoeken om de volgende informatie via info.vlaardingen@dierenbescherming.nl te sturen:
naam, adres en telefoonnummerde gezinssamenstelling (indien kinderen, de leeftijden)de woonsituatie (wel/geen tuin/balkon en hoe dat is afgezet, graag foto''s toevoegen)werksituatie/ werktijdende ervaring met katteneventuele andere aanwezige huisdiereneventuele vakantieplannen op korte termijn: We hebben geen mogelijkheid om een dier tot na de vakantie vast te houden en adviseren om pas na de vakantie op zoek te gaan naar een nieuwe huisgenoot.
Het is niet mogelijk om per e-mail of via de telefoon een kat te reserveren. Kennismaken met de asielkatten kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch. Bij meerdere gegadigden maken we een selectie voor de uitnodiging voor het kennismaken op basis van de informatie zoals gegeven in de mail. 
Let op: katten dienen bij adoptie met een auto opgehaald te worden.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_330x285_crop_center-center_none/Billy-en-Zwollie.jpeg?stamp=2603301414&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/Billy-en-Zwollie.jpeg?stamp=2603301414&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/Billy-en-Zwollie.jpeg?stamp=2603301414&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Billy-en-Zwollie.jpeg?stamp=2603301414&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Billy-en-Zwollie2.jpeg?stamp=2603301414&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3563.jpeg?stamp=2604260532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/Billy-en-Zwollie.jpeg?stamp=2603301414&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/Billy-en-Zwollie.jpeg?stamp=2603301414&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Billy-en-Zwollie.jpeg?stamp=2603301414&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Billy-en-Zwollie2.jpeg?stamp=2603301414&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3563.jpeg?stamp=2604260532&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301030&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4571256-billy-en-zwollie'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4571256-billy-en-zwollie')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Katja', 'Ik ben mooi? Ben ik niet? Maar helaas ben ik erg bang in het asiel. Ik vind mensen spannend en als ik in mijn veilige krabpaaltje zit kan ik ook wel fel reageren als je dichtbij komt. Dan voel ik me gewoon onveilig.
Ben sociaal met andere katjes en 4 jaar oud geschat.
Ik hoop snel een lief baasje te vinden die mij de tijd geeft om te wennen.
Een tuin is een must voor deze kat. We plaatsen deze katten niet op appartementen of flats met balkon
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag verzoeken wij je eerst een kennismakingsmail te sturen naar limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Tanja_2026-03-29-173524_tngs.png?stamp=2603291935&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Tanja_2026-03-29-173524_tngs.png?stamp=2603291935&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Tanja_2026-03-29-173524_tngs.png?stamp=2603291935&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Tanja_2026-03-29-173524_tngs.png?stamp=2603291935&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Tanja_2026-03-29-173524_tngs.png?stamp=2603291935&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Tanja_2026-03-29-173524_tngs.png?stamp=2603291935&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Tanja_2026-03-29-173524_tngs.png?stamp=2603291935&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4571325-tanja'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4571325-tanja')
