insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Boerderij katten zoeken erf!', 'Vol op boerderij katten beschikbaar voor een nieuwe boerderij!', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_330x285_crop_center-center_none/1920x1132-img_2096-60ba2caf15f56.jpeg?stamp=2306290836&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_384x330_crop_center-center_none/1920x1132-img_2096-60ba2caf15f56.jpeg?stamp=2306290836&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_519x453_crop_center-center_none/1920x1132-img_2096-60ba2caf15f56.jpeg?stamp=2306290836&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/1920x1132-img_2096-60ba2caf15f56.jpeg?stamp=2306290836&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/1856x1095-img_2083-60ba2cbb44682.jpeg?stamp=2306290836&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/1682x992-img_2093-60ba2ce51b98c.jpeg?stamp=2306290836&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/Buiten-ren-1.jpg?stamp=2306290826&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/1897x1118-img_2080-60ba2cd5e858e.jpeg?stamp=2306290836&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/1918x1131-img_2084-60ba2cc535673.jpeg?stamp=2306290836&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_384x330_crop_center-center_none/1920x1132-img_2096-60ba2caf15f56.jpeg?stamp=2306290836&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_519x453_crop_center-center_none/1920x1132-img_2096-60ba2caf15f56.jpeg?stamp=2306290836&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/1920x1132-img_2096-60ba2caf15f56.jpeg?stamp=2306290836&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/1856x1095-img_2083-60ba2cbb44682.jpeg?stamp=2306290836&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/1682x992-img_2093-60ba2ce51b98c.jpeg?stamp=2306290836&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/Dieren/_800x550_crop_center-center_none/Buiten-ren-1.jpg?stamp=2306290826&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/472059-schuwe-katten-zoeken-erf'
