insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Spijkenisse', 'Mogli', 'Uit de diepte van de “stedelijke jungle” stapte hij binnen… met wilde haren, een stoere blik en een verleden vol avontuur. Maak kennis met Mogli, een nieuwsgierige kater van bijna 8 jaar oud die zijn eigen junglepad heeft bewandeld.
Toen hij bij ons binnenkwam, droeg hij zijn vacht als een echte woudbewoner: ruig, vol klitten en helemaal in safari-stijl. Inmiddels is deze knappe avonturier professioneel getrimd. De klitten zijn verdwenen en onder die wilde boswachterslook kwam een prachtige, zachte vacht tevoorschijn. Onze kleine leeuw ziet er weer uit als de koning van zijn eigen territorium!
Mogli is een echte ontdekkingsreiziger. Met zijn alerte ogen en nieuwsgierige snuit inspecteert hij zijn omgeving alsof het een onontdekt regenwoud is. Nieuwe geluiden? Even checken. Een onbekend hoekje? Zeker verkennen. Maar als hij zijn veilige rustplek heeft gevonden, geniet hij ook zichtbaar van ontspanning, alsof hij hoog in een warme boomtak ligt te soezen.
Bij binnenkomst was Mogli al bekend met blaasproblemen en onzindelijkheid. Na wat onderzoeken bleek hij last te hebben van een blaassteen ( inmiddels volledig opgelost) en is er milde artrose zichtbaar maar hier lijkt hij op dit moment nog geen ongemak van te hebben. Dieetvoer zal voorkomen dat hij opnieuw stenen in zijn blaas zal ontwikkelen en gelukkig vindt hij de brokjes erg lekker!
Voor Mogli zoeken we een rustig en stabiel thuis waar hij in zijn eigen tempo verder mag ontplooien. Een plek waar hij zich veilig voelt, zijn territorium rustig kan verkennen en waar zijn mensen begrijpen dat zelfs een jungleheld soms gewoon een zachte mand nodig heeft waar zijn wilde haren regelmatig worden geborsteld.
 Nog belangrijker is een baasje die begrijpt dat Mogli niet altijd keurig zindelijk zal zijn en het misschien een zoektocht wordt naar de juiste omstandigheden zodat Mogli wel altijd keurig gebruik zal maken van zijn kattenbakken. Mogli is dus zeker niet geschikt voor iedereen.
Ben jij klaar om jouw huis om te toveren tot Mogli’s nieuwe jungle? Ben jij die echte Perzen gek die ook helemaal niet verbaasd is dat Mogli niet 100% zindelijk is? Vul dan snel zijn interesse formulier in en wie weet kunnen wij een afspraak maken voor een vrijblijvende kennismaking en Mogli zien hoe ontzettend lief en speels hij is.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_330x285_crop_center-center_none/IMG-20260422-WA0002.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260422-WA0002.jpg?stamp=2604221412&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260422-WA0002.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0002.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0006.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0003.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0005.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0004.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0007.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0012.jpg?stamp=2604092019&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0011.jpg?stamp=2604092019&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0008.jpg?stamp=2604221412&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0014.jpg?stamp=2604092019&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0018.jpg?stamp=2604092019&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260408-WA0009.jpg?stamp=2604092019&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4567450-mogli'
from public.shelters s
where s.name = 'Dierenopvangcentrum Spijkenisse'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4567450-mogli')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Garfield', 'Deze kat verblijft in het asiel. De kosten van een kat bedragen 154,- euro (dit is inclusief chippen, vaccinatie(s), castratie/sterilisatie). Het asiel werkt alleen op afspraak. Als u belangstelling heeft voor dit dier kunt u uw gegevens (zie onder) doorgeven aan ons. Wij nemen dan contact met u op.Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1191880-Garfield.jpg?stamp=2603251115&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1191880-Garfield.jpg?stamp=2603251115&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1191880-Garfield.jpg?stamp=2603251115&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191880-Garfield.jpg?stamp=2603251115&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191880-Garfield-2.jpg?stamp=2603251115&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191880-Garfield-1.jpg?stamp=2603251115&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1191880-Garfield.jpg?stamp=2603251115&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1191880-Garfield.jpg?stamp=2603251115&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191880-Garfield.jpg?stamp=2603251115&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191880-Garfield-2.jpg?stamp=2603251115&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191880-Garfield-1.jpg?stamp=2603251115&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4567223-garfield'
from public.shelters s
where s.name = 'De Kuipershoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4567223-garfield')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Jemo (FIV +, binnenkat)', 'Prachtig zwart en ook nog eens lange haren? Ja, dat ben ik! Ik ben een prachtkerel, al laat ik dat in het asiel nog niet zo zien. Ik ben als zwerver gevonden en volgens buurtbewoners heeft mijn eigenaar me achtergelaten na een verhuizing.
Het asiel? Dat vindt ik maar niets. Ik ben bang en lig bovenop de plankjes of in mijn veilige krabpaaltje. Wachtend op iemand die geduldig, lief is en mij ziet.
Wat is kattenaids?Kattenaids is een virusziekte die het afweersysteem van een kat aantast. Het is niet besmettelijk voor mensen of andere dieren, alleen voor katten onderling. Er is geen geneesmiddel of medicijn voor kattenaids. Belangrijk is dat de katten een zo stressvrij mogelijk leven lijden en niet meer vrij buiten mogen rondlopen. Indien ze dus goed verzorgd worden hebben ze een goede levensverwachting. De meeste aidskatten overlijden eerder door ouderdom of andere problemen dan door de aids.
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.
Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Jemo2.png?stamp=2603291917&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Jemo2.png?stamp=2603291917&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Jemo2.png?stamp=2603291917&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jemo2.png?stamp=2603291917&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Jemo2.png?stamp=2603291917&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Jemo2.png?stamp=2603291917&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Jemo2.png?stamp=2603291917&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4563395-jemo'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4563395-jemo')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Mork', 'Mork is een kater die het buitenleven serieus neemt. Zonnetje op z’n vacht, zand tussen z’n tenen en sprintjes trekken alsof hij auditie doet voor de Olympische Spelen – dát is zijn ding.
Binnen is hij… tja, laten we zeggen: gezellig op zijn voorwaarden. Aanhankelijk? Zeker. Maar wel tot een duidelijke grens. Een aai over zijn rug? Prima. Een uitgebreide knuffelsessie van 20 minuten? Absoluut niet volgens Mork’s contractvoorwaarden. Hij laat het je overigens keurig weten wanneer je je limiet hebt bereikt.
Andere katten? Mwah. Buiten een beetje buurten is oké, maar binnen hoeft hij geen huisgenoot met snorharen. Mork is meer het type: “ik ben al compleet, dank je.”
Hij zoekt een rustig huishouden zonder kinderen, waar hij op zijn eigen tempo alles kan ontdekken: zijn nieuwe huis, zijn nieuwe mens… en vooral zichzelf (die reis is nog in volle gang).
Wat Mork nodig heeft:
· Een plek waar hij na gewenning lekker vrij naar buiten kan (ja, ook buiten de tuin – hij is een avonturier)
· Rust, ruimte en iemand die zijn grenzen respecteert
· Iemand die hem wil leren kennen zoals hij is (een beetje eigenwijs, maar met karakter!)
Oh, en kleine sidenote: meneer staat momenteel preventief op dieetvoer vanwege een gevoelige blaas. Hij doet dus ook een beetje aan “self-care”.
Kortom: wil jij een kat met persoonlijkheid, humor en een duidelijk eigen mening?Iemand die niet altijd op schoot ligt, maar wél echt jouw maatje wordt?
Dan is Mork helemaal klaar om jou te ontmoeten!', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/4563235/mork7.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4563235/mork7.jpg?stamp=2603191839&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4563235/mork7.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563235/mork7.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563238/mork10.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563237/mork9.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563236/mork8.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563234/mork6.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563233/mork5.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563232/mork4.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563229/mork1.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563239/mork11.jpg?stamp=2603191839&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4563235/mork7.jpg?stamp=2603191839&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4563235/mork7.jpg?stamp=2603191839&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4563235/mork7.jpg?stamp=2603191839&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4563228-mork'
from public.shelters s
where s.name = 'Dierencentrum Achterhoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4563228-mork')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Kaboel (FIV +, binnenkat)', 'Ben Kaboel en ongeveer 6 jaar oud geschat door de dierenarts. Als zwerver gevonden, maar niemand die me mist.
Helaas heb ik kattenaids, maar dit is zeker geen doodvonnis voor me. Wel ben ik een kater die veel tijd nodig heeft, ik ben in het asiel nog niet uit mijn schulp gekropen en vind geaaid worden nog altijd doodeng. Op dit moment vind ik mensen nog niet leuk. Ik blaas naar je en probeer je weg te jagen. 
Ik hoop echter dat er iemand is die mij een kans geeft, iemand die wel ziet hoe leuk ik zal zijn als ik rustig een vertrouwensband met je opgebouwd heb.

Wat is kattenaids?Kattenaids is een virusziekte die het afweersysteem van een kat aantast. Het is niet besmettelijk voor mensen of andere dieren, alleen voor katten onderling. Er is geen geneesmiddel of medicijn voor kattenaids. Belangrijk is dat de katten een zo stressvrij mogelijk leven lijden en niet meer vrij buiten mogen rondlopen. Indien ze dus goed verzorgd worden hebben ze een goede levensverwachting. De meeste aidskatten overlijden eerder door ouderdom of andere problemen dan door de aids.
Let op: Het is niet mogelijk om zonder afspraak naar deze kat te komen kijken.Graag
 verzoeken wij je eerst een kennismakingsmail te sturen naar 
limburg@dierenbescherming.nl. Wij nemen dan snel contact met je op om 
een eventuele afspraak te maken. Bedankt voor je begrip!Het is ook mogelijk om meerdere katten in het asiel te bezoeken tijdens een afspraak.Is er een klik met de kat tijdens de afspraak? Dan mogen de meeste katten direct mee naar hun nieuwe thuis.Ben je woonachtig in Duitsland of België? Dan is het helaas niet mogelijk om een kat of kitten uit ons asiel te adopteren. Op onze website bij info en advies vind je hier meer informatie over.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Kaboel2.png?stamp=2604271936&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Kaboel2.png?stamp=2604271936&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Kaboel2.png?stamp=2604271936&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Kaboel2.png?stamp=2604271936&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Kaboel_2026-04-26-170831_dzfp.png?stamp=2604261908&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Kaboel2.png?stamp=2604271936&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Kaboel2.png?stamp=2604271936&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Kaboel2.png?stamp=2604271936&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Kaboel_2026-04-26-170831_dzfp.png?stamp=2604261908&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&