select s.id, 'Zandvoort', 'Jimmy', 'Ik ben Jimmy-bijna 4 jaar, knap, charmant en... een beetje een dorpsfiguur in wording.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/jimmy.jpeg?stamp=2603061214&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/jimmy.jpeg?stamp=2603061214&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/jimmy.jpeg?stamp=2603061214&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/jimmy.jpeg?stamp=2603061214&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/jimmy1.jpeg?stamp=2603061214&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Jimmy2_2026-03-07-131030_tlfn.jpg?stamp=2603071410&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/jimmy.jpeg?stamp=2603061214&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/jimmy.jpeg?stamp=2603061214&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/jimmy.jpeg?stamp=2603061214&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/jimmy1.jpeg?stamp=2603061214&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/Jimmy2_2026-03-07-131030_tlfn.jpg?stamp=2603071410&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4552102-jimmy'
