insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Utrecht', 'Skip', 'Maak kennis met Skip, een gevoelige jongen met een gouden randje 💛
Skip is een kater van 6 jaar oud die met pijn in het hart is afgestaan door zijn vorige eigenaar. Hij is een onzekere en stressgevoelige jongen, en dat merken we hier nog steeds. De nieuwe omgeving, vreemde mensen en andere katten maken hem soms overweldigd, waardoor hij zich af en toe nog terugtrekt.
Maar… we zien ook een hele mooie ontwikkeling. 💛
Skip begint steeds meer vertrouwen te krijgen en komt inmiddels zelf naar je toe voor een aai. En als hij je eenmaal kent? Dan kan hij zelfs heerlijk bij je op schoot komen liggen en echt genieten van het contact. Dat zachte, lieve karakter zit er dus zeker in – het heeft alleen even tijd nodig om naar boven te komen.
Als klein kitten kwam hij bij zijn vorige baasjes en daar had hij het goed. Door veranderde omstandigheden in huis raakte Skip echter gestrest en onzeker. Uiteindelijk werd de situatie te moeilijk en is hij bij ons terechtgekomen.
Voor Skip zoeken we een rustig en stabiel thuis. Hij is eenkennig en hecht zich het liefst aan één of twee mensen. Kinderen of andere huisdieren zijn voor hem te stressvol. Wat hij nodig heeft, is iemand met ervaring, geduld en inzicht in kattengedrag, die hem de tijd geeft om op zijn eigen tempo te landen.
Een tuin is belangrijk voor Skip. Buiten zijn helpt hem om zijn energie kwijt te kunnen en zijn hoofd leeg te maken. Daarnaast vindt hij het fijn om te spelen, dit helpt ook om zijn zelfvertrouwen te vergroten.
Hoe beter je Skip leert kennen, hoe duidelijker hij wordt in zijn communicatie. En hoe meer vertrouwen er ontstaat, hoe meer je zijn zachte, aanhankelijke kant te zien krijgt. Wij zien nu al dat hij die stapjes maakt, en dat belooft veel moois voor de toekomst.
Skip krijgt dieetvoer om blaasproblemen te helpen voorkomen. Gelukkig vind hij dit erg lekker!
Ben jij iemand die niet terugdeinst voor een kat met een rugzakje, maar juist blij wordt van het opbouwen van een band? Dan is Skip misschien wel precies de kat die bij u past.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_330x285_crop_center-center_none/Skip-5.jpg?stamp=2604231556&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Skip-5.jpg?stamp=2604231556&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Skip-5.jpg?stamp=2604231556&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Skip-5.jpg?stamp=2604231556&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Skip-4.jpg?stamp=2603121008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Skip-3.jpg?stamp=2603121008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Skip-2.jpg?stamp=2603121008&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_384x330_crop_center-center_none/Skip-5.jpg?stamp=2604231556&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_519x453_crop_center-center_none/Skip-5.jpg?stamp=2604231556&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Skip-5.jpg?stamp=2604231556&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Skip-4.jpg?stamp=2603121008&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Skip-3.jpg?stamp=2603121008&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/_800x550_crop_center-center_none/Skip-2.jpg?stamp=2603121008&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenasielUtrecht/Algemeen/_882x1004_crop_center-center_none/DB-KAT-885x1005.png?stamp=2511171446&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4542153-skip'
from public.shelters s
where s.name = 'Dierenasiel Utrecht'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4542153-skip')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', 'Boerderijkatten', 'Wie kan ons helpen? Wij zoeken met regelmaat een buitenplek voor verwilderde katten, dit kan zijn een boerderij, manege of bijvoorbeeld een kassencomplex.
De katten zijn zeer geschikt als muizenvangers en ze zijn geneutraliseerd, gevaccineerd en gechipt. Ze zijn absoluut niet geschikt als huiskat.
U kunt ze na overleg kosteloos bij ons ophalen.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_330x285_crop_center-center_none/what-do-you-call-a-group-of-cats-v0-g1ep2r3f4uv91.webp?stamp=2602171006&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_384x330_crop_center-center_none/what-do-you-call-a-group-of-cats-v0-g1ep2r3f4uv91.webp?stamp=2602171006&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_519x453_crop_center-center_none/what-do-you-call-a-group-of-cats-v0-g1ep2r3f4uv91.webp?stamp=2602171006&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/what-do-you-call-a-group-of-cats-v0-g1ep2r3f4uv91.webp?stamp=2602171006&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_384x330_crop_center-center_none/what-do-you-call-a-group-of-cats-v0-g1ep2r3f4uv91.webp?stamp=2602171006&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_519x453_crop_center-center_none/what-do-you-call-a-group-of-cats-v0-g1ep2r3f4uv91.webp?stamp=2602171006&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/what-do-you-call-a-group-of-cats-v0-g1ep2r3f4uv91.webp?stamp=2602171006&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_882x1004_crop_center-center_none/banner-beeld-hond-close-885.png?stamp=2504161034&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4537750-boerderijkatten'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Noord-Nederland'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4537750-boerderijkatten')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Spijkenisse', 'Jolly (met filmpje)', 'Jolly is een zwart-witte gecastreerde kater van 11 jaar oud. Deze kanjer is bij ons terecht gekomen nadat de eigenaar hem niet de juiste zorg kon geven.
Wanneer je kennis komt maken met Jolly is de kans groot dat hij in zijn boxje aan de catwall ligt en hij nieuwsgierig zijn kopje naar buiten steekt om te kijken wie er is. Een enthousiaste begroeting is nu nog iets teveel gevraagd want Jolly is namelijk een tikje verlegen. Als je hem zachtjes verteld dat het goed is en hij zo''n knappe kater is neemt hij de eerste voorzichtige stapjes naar je toe. Eenmaal vertrouwt blijkt Jolly een enthousiaste kater te zijn die graag op schoot ligt of gewoon lekker tegen je aan. Hij kijkt je dan ook dankbaar aan en het is prachtig om te zien hoe hij van aandacht geniet.
Wij zoeken voor hem een rustig één of twee persoons huisje zonder kinderen of andere dieren. Een volledig afgeschermde tuin (lees: er kan geen kat uit of in komen) of katveilig balkon is gewenst. Jolly mag namelijk geen contact hebben met andere katten. Hij heeft namelijk FiV oftewel katten aids. Dit is NIET besmettelijk voor ons mensen. Uiteraard vertellen wij je hier graag meer over bij interesse. 
Ben jij op zoek naar een maatje en begrijp je dat er eerst vertrouwen moet komen voordat Jolly enthousiast wordt? Vul dan het interesseformulier in en wie weet kunnen wij een afspraak maken voor een vrijblijvende kennismaking met deze lieverd en ligt Jolly straks bij jou op schoot te knorren.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_330x285_crop_center-center_none/IMG-20260422-WA0011.jpg?stamp=2604221411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_384x330_crop_center-center_none/IMG-20260422-WA0011.jpg?stamp=2604221411&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_519x453_crop_center-center_none/IMG-20260422-WA0011.jpg?stamp=2604221411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0011.jpg?stamp=2604221411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0009.jpg?stamp=2604221411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0013.jpg?stamp=2604221411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260202-WA0057_2026-02-04-134543_sfos.jpg?stamp=2602041445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0010.jpg?stamp=2604221411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260209-WA0054.jpg?stamp=2602111956&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0015.jpg?stamp=2604221411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260128-WA0034.jpg?stamp=2601281944&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260422-WA0012.jpg?stamp=2604221411&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260209-WA0049.jpg?stamp=2602111957&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260209-WA0051.jpg?stamp=2602111957&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumSpijkenisse/_800x550_crop_center-center_none/IMG-20260401-WA0020.jpg?stamp=2604012036&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4515627-jolly'
from public.shelters s
where s.name = 'Dierenopvangcentrum Spijkenisse'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4515627-jolly')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Monster en Fluffie', 'Sommige katten komen niet alleen met een reismandje binnen… maar met een heel verhaal.Monster (21-05-2015) en Fluffie (08-05-2013) zijn zo’n bijzonder duo. Samen zijn ze van ver gekomen.
Bij binnenkomst waren ze angstig en onzeker. De wereld voelde groot en onveilig. Maar met tijd, geduld en vooral verwachtingsloos respect begonnen ze langzaam te ontdooien. Eerst een blik. Toen een kleine stap. En weer een stapje verder.
Nu staan ze op een nieuw kruispunt: klaar om op zoek te gaan naar hun eigen, veilige thuis.
Een thuis waar ze mogen zijn wie ze zijn.Waar niets moet.Waar ze hun eigen tempo mogen volgen — zelfs als dat betekent dat ze soms weer een stapje terug doen. Want ja, die stapjes terug zullen er zijn. Maar wij weten inmiddels: met geduld en respect voor hun ruimte ontstaan er telkens weer nieuwe, ontroerende momentjes van groei.
En geloof ons… de beloning is bijzonder.
Elk klein stapje voelt als een persoonlijk cadeautje.Een stille dankjewel.Een teken dat hun vertrouwen groeit — langzaam, maar oprecht.
Monster en Fluffie zoeken een thuis waar ze zich veilig mogen voelen. Waar ze fijne verstopplekjes hebben om zich even onzichtbaar te wanen totdat de wereld weer veilig genoeg voelt om tevoorschijn te komen. Iedere keer opnieuw zal hun vertrouwen groeien.
Om hun stressniveau zo laag mogelijk te houden, staan ze momenteel op speciaal dieetvoer. Het is belangrijk dat dit in hun nieuwe thuis wordt voortgezet, zodat zij zowel lichamelijk als mentaal in balans kunnen blijven.
We zoeken een ervaren kattenliefhebber die bekend is met dit gedrag.Iemand zonder verwachtingen.Iemand die hen niet wil veranderen, maar hen simpelweg laat zijn.
Want wie dat kan, weet: of het nu weken, maanden of misschien zelfs een jaar duurt… de uiteindelijke beloning is groots.
Wanneer ze eenmaal echt gewend zijn, willen Monster en Fluffie graag ook de buitenwereld ontdekken. Niet alleen een tuin, maar uiteindelijk ook vrij naar buiten kunnen.
Heb jij een groot hart?Kun jij dit bijzondere duo samen een plek geven — zonder druk, zonder verwachtingen, maar met alle geduld van de wereld?
Dan wachten Monster en Fluffie misschien wel op jou.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/4534848/mf1.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/4534848/mf1.jpg?stamp=2602122101&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/4534848/mf1.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534848/mf1.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534850/mf3.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534849/mf2.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534853/mf6.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534855/mf8.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534856/mf9.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534859/mf12.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534854/mf7.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534857/mf10.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4534858/mf11.jpg?stamp=2602122101&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-cent