insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Boerderijkatten zoeken baan!', 'We zijn altijd op zoek naar goede plekjes voor boerderijkatten.
Boerderijkatten die té verwilderd zijn voor een leven in huis. Ze worden daar niet gelukkig van maar zijn wel gewend om bijgevoerd te worden door mensen.
Ze zoeken dus een boerderij, manege of andere mooie buitenplek met een vacature voor muizenvanger. Waar ze dus geen overlast kunnen veroorzaken in de buurt. We vragen geen adoptiekosten voor deze katten, een vrijwillige bijdrage is natuurlijk altijd welkom.Ben je dus op zoek naar een boerderijkat (of -katten)? Stuur ons dan een e-mail met het woonadres en wat meer informatie over de plek. 
E-mail: Limburg@dierenbescherming.nlLet op: we hebben niet altijd boerderijkatten in de opvang zitten, mocht je interesse hebben in adoptie dan kunnen we je wel op een wachtlijst plaatsen.', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_330x285_crop_center-center_none/php3GUEhs.png?stamp=2306301433&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_384x330_crop_center-center_none/php3GUEhs.png?stamp=2306301433&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_519x453_crop_center-center_none/php3GUEhs.png?stamp=2306301433&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/php3GUEhs.png?stamp=2306301433&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/phpU4edbb.png?stamp=2306301433&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_384x330_crop_center-center_none/php3GUEhs.png?stamp=2306301433&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_519x453_crop_center-center_none/php3GUEhs.png?stamp=2306301433&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/php3GUEhs.png?stamp=2306301433&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/phpU4edbb.png?stamp=2306301433&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/472293-boerderijkatten-zoeken-baan'
