insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Doetinchem', 'Molly', 'Voor Molly loopt het (l)even niet helemaal volgens het sprookjesboek. Twee keer dacht ze haar gouden mandje gevonden te hebben – een fijn thuis, een eigen mens, rust in de tent – maar het liep nét even anders.Maar hé, wij blijven optimistisch: op elk potje past een dekseltje. Soms moet je alleen wat beter zoeken. En voor Molly zoeken we dat ene, gouden dekseltje dat écht past.
Belangrijk voor een goede start: aaien en oppakken is voorlopig een no-go. Zelfs als Molly denkt: “kom maar door met die knuffels.” Laat haar lekker zelf naar je toe komen. Op schoot liggen? Helemaal prima. Maar handen thuis houden. Dat aaien komt later wel, als jullie elkaar echt goed kennen.
Molly & andere katten? Dat is geen match. Echt niet. Alleen al het zien van een andere kat kan haar in paniek brengen. Op zo’n moment heeft ze vooral rust en ruimte nodig (ook als ze half in de gordijnen hangt alsof ze auditie doet voor een actiefilm). Ga je haar dan helpen, dan kan ze haar stress per ongeluk op jou afreageren.
Verder is Molly:
Sociaal… op haar eigen voorwaarden 😉Graag de regisseur van haar eigen levenSpeels en fan van balletjes en hengelsessiesHet gelukkigst in een rustige, kat-arme (liefst landelijke) omgevingEen buitenliefhebber die graag vrij rondstruint
Ze krijgt momenteel dieetvoer vanwege lichte darmklachten – niets spannends, gewoon een beetje opletten.
Kort samengevat:
Geen andere katten of drukke buurtGeen kinderenWel lekker naar buiten kunnenGeduld en respect voor haar grenzen zijn keyEen rustige, liefdevolle thuisbasis
Denk jij: “Hé, dit klinkt als mijn soort kat”? En kun jij je ego prima parkeren om Molly de ruimte te geven?
Dan maak je niet alleen onze dag… maar vooral Molly’s leven een heel stuk mooier!', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_330x285_crop_center-center_none/Molly4_2026-03-26-100244_bqoj.jpg?stamp=2603261102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_384x330_crop_center-center_none/Molly4_2026-03-26-100244_bqoj.jpg?stamp=2603261102&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_519x453_crop_center-center_none/Molly4_2026-03-26-100244_bqoj.jpg?stamp=2603261102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/Molly4_2026-03-26-100244_bqoj.jpg?stamp=2603261102&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4242991/molly9.jpg?stamp=2505012158&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4242996/molly14.jpg?stamp=2505012158&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4403697/molly21.jpg?stamp=2509301901&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4403696/Molly20.jpg?stamp=2509301901&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4242997/molly15.jpg?stamp=2505012159&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4242987/molly5.jpg?stamp=2505012158&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4242995/molly13.jpg?stamp=2505012158&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4242992/molly10.jpg?stamp=2505012158&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4242986/molly4.jpg?stamp=2505012158&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4242984/molly2.jpg?stamp=2505012158&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierencentrumAchterhoek/_800x550_crop_center-center_none/4403699/molly23.jpg?stamp=2509301901&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/4242981-molly'
