insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Gouda', 'Muizenvangers zoeken buitenplek', 'GEZOCHT: Een fijne en veilige leefplek voor verwilderde katten, als muizenvanger voor op een erf of in een buitengebied. Kun jij hen helpen?Het gaat hier om katten van verschillende leeftijden, zowel jonge katjes als volwassen katten die moeilijk tot niet socialiseerbaar zijn. Deze dieren zullen ontzettend ongelukkig worden als huiskat maar zijn in hun element bij mensen die een boerderij, manege of iets dergelijks hebben of bij mensen die in een buitengebied wonen. In ruil voor een natje, droogje en een veilige slaapplek houden zij je terrein muisvrij. De dieren zijn van alle leeftijden;Zowel katers als poezen zijn op zoek naar een plek;De katten komen in vrijwel alle kleuren en tekeningen;De katten zijn geneutraliseerd, ingeent, gechipt en nagekeken door de dierenarts. Let op: de dieren op de foto zijn voorbeelden, deze katten zijn dus al verhuisd naar een buitenplek. Meer weten? Of interesse? Neem dan contact op met ons door een mail te sturen naar gouda@dierenbescherming.nl', 'cat', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_330x285_crop_center-center_none/1859x1096-dsc_0059-5d1072ac5b515.jpg?stamp=2306301211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_384x330_crop_center-center_none/1859x1096-dsc_0059-5d1072ac5b515.jpg?stamp=2306301211&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_519x453_crop_center-center_none/1859x1096-dsc_0059-5d1072ac5b515.jpg?stamp=2306301211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_800x550_crop_center-center_none/1859x1096-dsc_0059-5d1072ac5b515.jpg?stamp=2306301211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_800x550_crop_center-center_none/1838x1084-dsc_0429-5d107288137ac.jpg?stamp=2306301211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_800x550_crop_center-center_none/1920x1132-dsc_0055-5d107267efffc.jpg?stamp=2306301211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_384x330_crop_center-center_none/1859x1096-dsc_0059-5d1072ac5b515.jpg?stamp=2306301211&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_519x453_crop_center-center_none/1859x1096-dsc_0059-5d1072ac5b515.jpg?stamp=2306301211&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_800x550_crop_center-center_none/1859x1096-dsc_0059-5d1072ac5b515.jpg?stamp=2306301211&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_800x550_crop_center-center_none/1838x1084-dsc_0429-5d107288137ac.jpg?stamp=2306301211&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Dieren/_800x550_crop_center-center_none/1920x1132-dsc_0055-5d107267efffc.jpg?stamp=2306301211&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumGouda/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301136&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/475904-muizenvangers-zoeken-buitenplek'
