where s.name = 'Dierenopvangcentrum Gouda'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/katten/475904-muizenvangers-zoeken-buitenplek')
