insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Witje', 'Hoi ik ben Witje, hoe kan het ook anders een witte gecastreerde hangoor man van ongeveer 2 jaar oud. Ik ben zwervend op straat aangetroffen en niemand heeft mij meer opgehaald...Ik ben een hele nieuwsgierige, ondernemende en actieve man. Ik heb dan ook behoefte aan een ruime plek met voldoende uitdagingen en een vriendin die mij kan temmen. Mensen mogen mij aaien en ik kom ook altijd meteen even kijken als iemand mijn hok opent. Heb jij een plek voor mij vrij?', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/IMG_0647.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0647.jpeg?stamp=2605051249&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0647.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0647.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0651.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0647.jpeg?stamp=2605051249&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0647.jpeg?stamp=2605051249&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0647.jpeg?stamp=2605051249&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0651.jpeg?stamp=2605051249&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dieren