insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Brandi', 'Maak kennis met Brandi! Brandi is samen met zijn broertjes en zusje via uitwisseling met een andere opvang bij ons gekomen, daar waren ze als vondelingen binnengebracht. Hierdoor weten wij niet zijn exacte leeftijd en zijn verleden.
Brandi is een rustig en voorzichtig mannetje. Hij komt wel even bij je kijken maar zodra die je genoeg heeft bekeken loopt hij de andere kant op. Tenzij je lekkere gezonde snack bij je hebt dan durft hij dat heel dapper van je aan te nemen! Oppakken vind hij niet heel tof, het liefst staat hij met al zijn poten op de grond.
Hij is opzoek naar een leuke vriendin die mee kan genieten van de gezonde snacks!

Heeft u de geschikte situatie voor hem? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met hem te maken.
Konijnen zijn sociale dieren en wij zullen ze niet plaatsen als er geen ander konijn aanwezig is. Aanvragen voor 1 konijn zullen dan ook niet in behandeling worden genomen.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Brandi6.jpg?stamp=2601271621&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Brandi6.jpg?stamp=2601271621&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Brandi6.jpg?stamp=2601271621&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi6.jpg?stamp=2601271621&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi3.jpg?stamp=2601271621&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi5.jpg?stamp=2601271621&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi4.jpg?stamp=2601271621&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi2.jpg?stamp=2601271621&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi-1.jpg?stamp=2601271621&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Brandi6.jpg?stamp=2601271621&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Brandi6.jpg?stamp=2601271621&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi6.jpg?stamp=2601271621&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi3.jpg?stamp=2601271621&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi5.jpg?stamp=2601271621&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Brandi4.jpg?stamp=2601271621&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4397682-brandi'
