insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Jaded', 'Maak kennis met Jaded! Jaded is samen met zijn broertjes en zusje via uitwisseling met een andere opvang bij ons gekomen, daar waren ze als vondelingen binnengebracht. Hierdoor weten wij niet zijn exacte leeftijd en zijn verleden.
Jaded moet altijd een beetje opwarmen, hij vind de aandacht erg leuk maar het heeft even tijd nodig voordat hij dapper genoeg is en hoi komt zeggen. 
Hij is opzoek naar een lieve vriendin die hem laat zien dat wij helemaal niet zo spannend zijn!

