insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Pandoravenator & Sellosaurus', 'Maak kennis met Pandoravenator & Sellosaurus! Ze zijn via afstand bij een andere opvang gekomen en via uitwisseling bij ons.
Sello en Pandora zijn nog maar kort bij ons in het asiel, en dat is goed te merken. Alles is nog nieuw, spannend en soms een beetje overweldigend voor dit duo. Ze houden zich voorlopig nog wat op de achtergrond en zoeken vooral steun bij elkaar. We geven ze alle tijd om rustig te wennen, in de hoop dat ze zich snel veilig genoeg voelen om hun echte karakter te laten zien.
Sello, een rustige ram, kan wel een beetje extra zorg gebruiken. Hij mag wat gewicht verliezen en hij heeft blaasproblemen daarom staat hij op een speciaal blaasdieet om hem zo goed mogelijk te ondersteunen. 
Pandora, een lieve voedster, heeft gevoelige hakjes. Daarom is het belangrijk dat ze op een zachte ondergrond zoals gras of zand gaan verblijven. Dit helpt om haar pootjes te ontlasten en verdere klachten te voorkomen.

Heeft u al interesse in dit leuke koppel? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met hen te maken.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Sello-Pandora1.jpg?stamp=2605061232&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Sello-Pandora1.jpg?stamp=2605061232&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Sello-Pandora1.jpg?stamp=2605061232&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Sello-Pandora1.jpg?stamp=2605061232&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Sello-Pandora.jpg?stamp=2605061232&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Pandora.jpg?stamp=2605061232&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Sello.jpg?stamp=2605061232&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Sello-Pandora1.jpg?stamp=2605061232&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Sello-Pandora1.jpg?stamp=2605061232&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Sello-Pandora1.jpg?stamp=2605061232&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Sello-Pandora.jpg?stamp=2605061232&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Pandora.jpg?stamp=2605061232&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Sello.jpg?stamp=2605061232&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4602076-pandoravenator-sellosaurus'
