insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Chelsy', 'Maak kennis met Chelsy!
Chelsy is bij ons gekomen nadat ze helaas haar maatje is verloren. Nu is ze klaar voor een nieuw begin met een lief nieuw vriendje aan haar zijde. Deze dame is erg nieuwsgierig en gaat graag op pad. Ze is actief, ondernemend en altijd in voor een ontdekkingstocht door haar verblijf. Stilzitten is niets voor haar, als de deur van haar verblijf open gaat is ze voor dat je het weet al op de gang aan het rond huppelen
Chelsy heeft een last van een traanoogje. Hiervoor is haar traanbuis doorgespoeld en hopen we dat dit het zal verhelpen. Zo niet heeft een nieuw maatje de schone taak om die voor haar te wassen Mocht dat niet voldoende zijn, dan is het goed te ondersteunen met vitamine A-zalf.
Ben jij op zoek naar een nieuwsgierige en ondernemende konijnendame? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis te maken met haar.
Let op: konijnen zijn sociale dieren. We plaatsen haar alleen bij een gecastreerde ram. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Chelsy1.jpg?stamp=2605061127&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Chelsy1.jpg?stamp=2605061127&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Chelsy1.jpg?stamp=2605061127&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Chelsy1.jpg?stamp=2605061127&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Chelsy2.jpg?stamp=2605061127&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Chelsy1.jpg?stamp=2605061127&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Chelsy1.jpg?stamp=2605061127&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Chelsy1.jpg?stamp=2605061127&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Chelsy2.jpg?stamp=2605061127&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4597962-chelsy'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4597962-chelsy')
limit 1;

