insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Bobby en Lieke', 'Hoi wij zijn Bobby en Lieke, een leuk koppeltje van net 3 jaar oud. Wij zijn helaas op zoek naar een nieuwe plek wegens allergieklachten van onze eigenaar.Wij zijn nieuwsgierige en vriendelijke konijntjes, gewend om lekker buiten te lopen en komen altijd even kijken als je op visite komt. Rond etenstijd konden ze ons altijd even aaien en ook zijn wij kinderen gewend en niet snel bang. Wij zoeken een ruime plek met voldoende aandacht.Heb jij een fijn thuis voor ons?', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/IMG_0641.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0641.jpeg?stamp=2605051249&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0641.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0641.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0638.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0640.jpeg?stamp=2605051249&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0641.jpeg?stamp=2605051249&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0641.jpeg?stamp=2605051249&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0641.jpeg?stamp=2605051249&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0638.jpeg?stamp=2605051249&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0640.jpeg?stamp=2605051249&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4601074-bobby-en-lieke'
from public.shelters s
where s.name = 'Dierentehuis Kennemerland'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4601074-bobby-en-lieke')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Cavia Tequilla', 'Tequilla is een ontzettende lieve en vriendelijke gecastreerde beer die opzoek is naar een fijn thuis. Hij laat zich graag aaien als die je kent, in het begin is die erg schuw.
Adoptiekosten zijn 48,50 euro voor een gecastreerde beer.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Breezer_2026-02-20-184537_iovs.png?stamp=2602201945&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Breezer_2026-02-20-184537_iovs.png?stamp=2602201945&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Breezer_2026-02-20-184537_iovs.png?stamp=2602201945&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Breezer_2026-02-20-184537_iovs.png?stamp=2602201945&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Breezer23.png?stamp=2602201945&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Breezer2.png?stamp=2602201945&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Breezer_2026-02-20-184537_iovs.png?stamp=2602201945&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Breezer_2026-02-20-184537_iovs.png?stamp=2602201945&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Breezer_2026-02-20-184537_iovs.png?stamp=2602201945&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Breezer23.png?stamp=2602201945&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Breezer2.png?stamp=2602201945&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4540049-cavia-breezer'
