  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4540049-cavia-breezer')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', '119255 Salsa', 'Dit kleine dametje is Salsa, ze is bij ons binnengebracht als zwervend konijntje en helaas is er uiteindelijk niemand meer geweest die zich heeft gemeld als haar eigenaar, we zijn voor haar dan nu ook op zoek naar een nieuw fijn huisje waar ze mag samenwonen met een gecastreerd rammetje.
Ondanks haar kleine voorkomen (Salsa is een dwergje), schuilt er in dit konijntje ook een pittig tantetje. Wij hopen dat Salsa met een lief mannetje aan haar zijde weer helemaal in haar nopjes zal zijn.
Hebt u een ruim buitenverblijf met een fijn nachtgedeelte waar beide konijnen tezamen in kunnen schuilen tegen weer en wind, een verblijf waar de konijnen hun pootjes 24 uur per dag goed kunnen strekken? Maak uw interesse dan kenbaar via onderstaande contactmogelijkheid. 
Een verzoek naar foto''s van het potentiële konijnenverblijf en zijn afmetingen behoort tot de aanvraagprocedure.
Wij plaatsen onze konijnen uitsluitend in koppels of bij een andere soortgenoot, dit omdat konijnen groepsdieren zijn en de aanwezigheid van een soortgenootje zeer op prijs stellen.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_330x285_crop_center-center_none/Salsa3.jpg?stamp=2605051437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_384x330_crop_center-center_none/Salsa3.jpg?stamp=2605051437&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_519x453_crop_center-center_none/Salsa3.jpg?stamp=2605051437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Salsa3.jpg?stamp=2605051437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Salsa2.jpg?stamp=2605051437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Salsa1.jpg?stamp=2605051437&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_384x330_crop_center-center_none/Salsa3.jpg?stamp=2605051437&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_519x453_crop_center-center_none/Salsa3.jpg?stamp=2605051437&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Salsa3.jpg?stamp=2605051437&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Salsa2.jpg?stamp=2605051437&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Salsa1.jpg?stamp=2605051437&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_882x1004_crop_center-center_none/banner-beeld-hond-close-885.png?stamp=2504161034&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4600820-119255-salsa'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Noord-Nederland'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4600820-119255-salsa')
