insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Oreo', 'Maak kennis met Oreo!
Oreo is bij ons gekomen nadat ze het niet meer zo goed kon vinden met de andere gerbil dames. Ze is een meester in dutten maar als ze merkt dat er gevoed wordt is ze er als de kippen bij om snel de lekkerste dingen op te eten. Ze is tam en en was bij de vorige eigenaar goed hanteerbaar.
Heeft u een een geschikt verblijf voor haar? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met hen te maken.
Gerbils zijn sociale dieren en wij zullen ze niet plaatsen als er geen andere gerbil van hetzelfde geslacht aanwezig is. Aanvragen voor 1 gerbil zullen dan ook niet in behandeling worden genomen.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Oreo.jpg?stamp=2605051227&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Oreo.jpg?stamp=2605051227&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Oreo.jpg?stamp=2605051227&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Oreo.jpg?stamp=2605051227&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Oreo1.jpg?stamp=2605051227&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Oreo2.jpg?stamp=2605051227&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Oreo.jpg?stamp=2605051227&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Oreo.jpg?stamp=2605051227&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Oreo.jpg?stamp=2605051227&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Oreo1.jpg?stamp=2605051227&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Oreo2.jpg?stamp=2605051227&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4600996-oreo'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4600996-oreo')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Penelope', 'Maak kennis met Penelope!
Penelope is samen met haar zusjes binnen gekomen nadat ze helaas niet meer goed met elkaar overweg konden. Ze had hier een lelijks staartwond aan overgehouden, maar gelukkig is deze mooi genezen. Ze is een hele nieuwsgierige dame die gelijk komt kijken als je bezig bent. Vanaf haar veilige plekje in haar loopwiel houd ze het allemaal goed in de gaten.
Heeft u een een geschikt verblijf voor haar? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met hen te maken.
Gerbils zijn sociale dieren en wij zullen ze niet plaatsen als er geen andere gerbil van hetzelfde geslacht aanwezig is. Aanvragen voor 1 gerbil zullen dan ook niet in behandeling worden genomen.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Penelope1.jpg?stamp=2605051215&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Penelope1.jpg?stamp=2605051215&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Penelope1.jpg?stamp=2605051215&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Penelope1.jpg?stamp=2605051215&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Penelope2.jpg?stamp=2605051215&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Penelope1.jpg?stamp=2605051215&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Penelope1.jpg?stamp=2605051215&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Penelope1.jpg?stamp=2605051215&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Penelope2.jpg?stamp=2605051215&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4600974-penelope'
