insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Cavia Chianti', 'Chianti is een knappe meid die gedumpt is samen met nog een heel aantal andere cavia''s. Het is een leuke dame die ook graag gekriebeld wordt op haar kopje als ze je kent en vertrouwd. Ze is mama geworden van drie knappe baby''s.
Ze is waarschijnlijk nog jong, maar een precieze leeftijd weten we niet.
Ze mag vanaf maandag 11 mei verhuizen.
Heb jij voor Chianti cavia vriendjes? Of wil je haar eventueel met haar dochter adopteren? Stuur dan een e-mail naar limburg@dierenbescherming.nl', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Chianti2.png?stamp=2605061104&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Chianti2.png?stamp=2605061104&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Chianti2.png?stamp=2605061104&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Chianti2.png?stamp=2605061104&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Chianti.png?stamp=2605061104&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Chianti2.png?stamp=2605061104&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Chianti2.png?stamp=2605061104&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Chianti2.png?stamp=2605061104&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Chianti.png?stamp=2605061104&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4600848-cavia-chianti'
