insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Aagje', 'Maak kennis met Aagje! Zij is door afstand bij ons gekomen.
Helaas heeft Aagje geen goede start gehad in het leven, ze stond op marktplaats aangeboden in een hamsterverblijf. Gelukkig is ze snel opgehaald en bij ons gekomen en nu opzoek is naar een geschikt huisje.Deze energieke dame zit boordevol leven en laat dat ook graag zien! Zodra ze je ziet, komt ze nieuwsgierig op je af huppelen, klaar om te ontdekken wat je komt doen… en vooral of het iets met haar te maken heeft. Ze is dol op aandacht en vindt het heerlijk om betrokken te worden bij alles wat er om haar heen gebeurt. Even stilzitten, dat staat niet in haar woordenboek. Ze rent, springt, maakt vrolijke sprintjes en onderzoekt elk hoekje alsof het een nieuw avontuur is. Haar enthousiasme werkt aanstekelijk en zorgt gegarandeerd voor een glimlach.

Heeft u een ram die opgewassen is tegen haar energie? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met haar te maken.
Konijnen zijn sociale dieren en wij zullen ze niet plaatsen als er geen ander konijn aanwezig is. Aanvragen voor 1 konijn zullen dan ook niet in behandeling worden genomen.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Aagje2.jpg?stamp=2605061121&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Aagje2.jpg?stamp=2605061121&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Aagje2.jpg?stamp=2605061121&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aagje2.jpg?stamp=2605061121&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aagje.jpg?stamp=2605061121&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Aagje2.jpg?stamp=2605061121&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Aagje2.jpg?stamp=2605061121&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aagje2.jpg?stamp=2605061121&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aagje.jpg?stamp=2605061121&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4598759-aagje'
