insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Isolde', 'Maak kennis met Isolde! Ze is als vondeling bij ons binnen gekomen, daarom weten we geen leeftijd of verleden van haar
Toen ze bij ons binnen kwam leek ze enorm last te hebben van een gasbuik, na uitgebreide behandeling leek het niet minder te worden maar al snel bleek dat ze vooral een goed gevuld dametje is. Inmiddels weten we dat ze gewoon erg van eten houdt, en dat laat ze merken ook!
Isolde is een nieuwsgierig konijn dat graag haar omgeving verkent en overal even een kijkje wil nemen. Ze is alert, ondernemend en altijd geïnteresseerd in wat er om haar heen gebeurt. Tegelijk kan ze ook genieten van aandacht: een rustige aai over haar koppie waardeert ze zeker, al moet ze hier wel voor in de juiste stemming zijn.
Rond eten kan ze wat fel uit de hoek komen. Ze is enthousiast en duidelijk in wat ze wil, wij strooien het eten ook door haar ren zodat ze wat meer moeite moet doen om het te vinden.

Heeft u een leuk maatje voor haar? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis te maken met haar.
Let op: konijnen zijn sociale dieren. We plaatsen haar alleen bij een gecastreerde ram. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Isolde1.jpeg?stamp=2605021452&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Isolde1.jpeg?stamp=2605021452&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Isolde1.jpeg?stamp=2605021452&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Isolde1.jpeg?stamp=2605021452&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Isolde2.jpeg?stamp=2605021452&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Isolde3.jpeg?stamp=2605021452&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Isolde1.jpeg?stamp=2605021452&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Isolde1.jpeg?stamp=2605021452&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Isolde1.jpeg?stamp=2605021452&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Isolde2.jpeg?stamp=2605021452&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Isolde3.jpeg?stamp=2605021452&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4597952-isolde'
