insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Bentlie', 'Maak kennis met Bentlie! Hij is samen met zijn broer Harley in de opvang gekomen en zijn nu ieder opzoek naar een knappe dame
Bentlie is een afwachtend konijn dat de kat even uit de boom kijkt. In nieuwe situaties heeft hij wat tijd nodig om te wennen, maar met rust en geduld laat hij haar lieve kant steeds meer zien. Hij is zachtaardig van karakter en geen haantje-de-voorste, maar juist een rustig maatje dat op zijn eigen tempo vertrouwen opbouwt. Als hij zich eenmaal op zijn gemak voelt, komt zijn vriendelijke persoonlijkheid mooi naar voren.

Heeft u een geschikt maatje voor hem? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis met hem te maken.
