insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Lotte', 'Lotte is een Groot Lotharinger die in juli 2 jaar oud wordt. Ze heeft tot nu toe altijd alleen gewoond en omdat haar eigenaren haar een maatje gunde maar zelf die mogelijkheid niet hadden hebben ze besloten haar af te staan. Dat is voor Lotte het beste want elk konijn verdient een maatje om mee samen te leven, dat kan je als mens nooit vervangen. Voor deze grote dame van bijna 7 kilo zoeken we een heel groot verblijf in de tuin waar ze natuurlijk samen met een gecastreerde ram mag gaan wonen. Of hij groot is of klein maakt niet uit. Kun jij Lotte een heel fijn leven bieden? Laat het ons weten!
ADOPTIE:
Er wordt bij ons in de opvang gekoppeld zodat er de juiste match ontstaat. We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
