insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Lucas', 'Lieve Lucas is een prachtig rammetje van ongeveer een jaar oud. Hij is gevonden en niet meer door zijn eigenaar opgehaald. 
Het is een verlegen manneke die wel nieuwsgierig is, maar nog vrij snel kan schrikken. Als hij eenmaal ergens gewend is en waar het niet al te druk is bloeit hij vast helemaal op. Lucas is op zoek naar een lieve voedster en een fijn ruim verblijf in de tuin. Uiteraard is hij gevaccineerd en gecastreerd, en daarnaast is hij ook gechipt. Heb jij een voedster die wil komen kijken of het met knappe Lucas klikt? Laat het ons weten!
