insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Konijn Nijntje', 'Dit kleine dametje heet Nijntje. Ze is een klein hangoortje van 3 maanden oud die afgestaan is omdat het kindje er niet naar omkeek. Nijntje is een dametje met pit, we weten niet of dit komt door te kleine huisvesting of omgang, maar ze wil op dit moment niet geaaid worden en wilt dan ook bijten.
Ze is opzoek naar een ervaren eigenaar met genoeg ruimte, zodat Nijntje lekker kan rondhupsen.
Ze krijgt een voucher mee voor haar sterilisatie als ze 6 maanden oud is.
Let op: Het is niet mogelijk om de konijnen te bezoeken zonder afspraak. Een afspraak maak je via limburg@dierenbescherming.nl', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/nijntje_2026-05-01-183540_nfgp.png?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/nijntje_2026-05-01-183540_nfgp.png?stamp=2605012035&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/nijntje_2026-05-01-183540_nfgp.png?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/nijntje_2026-05-01-183540_nfgp.png?stamp=2605012035&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/nijntje_2026-05-01-183540_nfgp.png?stamp=2605012035&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/nijntje_2026-05-01-183540_nfgp.png?stamp=2605012035&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/nijntje_2026-05-01-183540_nfgp.png?stamp=2605012035&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4598525-konijn-nijntje'
