insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Konijn Olijfje', 'Olijfje is een leuke dame van 2 jaar oud die als zwerver is gevonden. Het is een vriendelijke en grappige dame. Ze is in het asiel ook zindelijk en doet alles netjes op de bak (we kunnen natuurlijk niet aangeven hoe dit in een thuissituatie is).
Ze is een wat groter konijn van bijna 4 kilogram en heeft dus wel ook ruimte nodig.
