insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Jonge ratjes', 'Tatty, Alfred, Bomber, Claud, Chub, Hummel, Huub, Felix, Finn, Otis, Sjefke en Ratty zijn via preventie naar ons toegekomen omdat het helemaal uit de hand liep in huis. Wat begon als drie mannetjes uit de dierenwinkel eindigde in meer dan 40 ratten in huis. Want het bleken dus niet alle drie mannen te zijn.
