insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Japie', 'Maak kennis met Japie! Er is afstand van hem gedaan omdat hem een maatje gegund werd die de vorige eigenaren niet konden bieden.
Japie is een aanhankelijk konijn dat dol is op aandacht. Hij geniet zichtbaar van rustige aaitjes en zoekt graag het gezelschap van mensen op.
Tegelijk is Japie ook wat gevoelig: hij kan snel schrikken van onverwachte geluiden of bewegingen. Een rustige benadering en een stabiele omgeving zijn daarom belangrijk voor hem, zodat hij zich veilig kan voelen en echt kan ontspannen. We hopen dat het juiste maatje hem hierin kan helpen.

Heeft u een lieve voedster voor hem? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis te maken met Mr. Black.
Let op: konijnen zijn sociale dieren. We plaatsen Japie alleen bij een voedster. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Japie1.jpg?stamp=2605061124&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Japie1.jpg?stamp=2605061124&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Japie1.jpg?stamp=2605061124&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Japie1.jpg?stamp=2605061124&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Japie.jpg?stamp=2605061124&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Japie1.jpg?stamp=2605061124&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Japie1.jpg?stamp=2605061124&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Japie1.jpg?stamp=2605061124&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Japie.jpg?stamp=2605061124&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4598097-japie'
