insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Jose', 'Maak kennis met Jose!
Jose is voor ons een oude bekende: vorig jaar zat hij ook al in de opvang, en nu is hij helaas teruggekomen nadat zijn maatje is overleden. Hij is dus opnieuw op zoek naar een fijn thuis én een nieuw vriendinnetje.
Jose is ondanks zijn leeftijd een speelse, actieve ram met een flinke dosis eigenwijsheid. Hij weet goed wat hij wil en gaat graag zijn eigen gang. Stilzitten is niets voor hem, hij is het liefst bezig met ontdekken, rondrennen en… graven! Geef hem de kans en hij maakt er met plezier zijn eigen project van.
Jose is een echt buiten konijn, daarom plaatsen wij hem uitsluitend buiten.
Heeft u een geschikt maatje voor hem en een mooi verblijf waar hij tunnels kan graven? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis met hem te maken.
Let op: konijnen zijn sociale dieren. We plaatsen hem alleen bij een voedster. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Jose2.jpg?stamp=2605011351&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Jose2.jpg?stamp=2605011351&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Jose2.jpg?stamp=2605011351&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Jose2.jpg?stamp=2605011351&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Jose1.jpg?stamp=2605011351&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Jose2.jpg?stamp=2605011351&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Jose2.jpg?stamp=2605011351&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Jose2.jpg?stamp=2605011351&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Jose1.jpg?stamp=2605011351&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4598090-jose'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4598090-jose')
