insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Pikachu & Eevee', 'Maak kennis met Pikachu en Evee! Ze zijn via afstand bij ons gekomen wegens privéomstandigheden. 
Dit broer en zus duo is enorm energiek en nieuwsgierig. Ze zijn graag in beweging, gaan samen op ontdekking en hebben echt de ruimte nodig om te rennen, springen en hun omgeving te verkennen. Ze zijn met voeren dan ook haantje de voorste en staat te trappelen om hun brokjes. Evee (zwart) is erg op haar ruimte gesteld en heeft soms moeite om dit te delen, ze kan dan ook nog wel eens fel uit de hoek komen door een snauw te geven, dit doet ze alleen door met haar pootjes op je hand te graven en te knorren.
Voor deze twee zoeken we een fijne plek waar ze zich thuis mogen gaan voelen. Met geduld, respect voor hun grenzen zal Evee hopelijk snel inzien dat we geen slechte bedoelingen hebben.
Kun jij dit levendige duo de ruimte en rust bieden die ze nodig hebben?

Heeft u al interesse in dit leuke koppel? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met hen te maken.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/EeveePikachu1.jpeg?stamp=2605011226&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/EeveePikachu1.jpeg?stamp=2605011226&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/EeveePikachu1.jpeg?stamp=2605011226&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/EeveePikachu1.jpeg?stamp=2605011226&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/EeveePikachu3.jpeg?stamp=2605011226&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/EeveePikachu2.jpeg?stamp=2605011226&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/EeveePikachu1.jpeg?stamp=2605011226&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/EeveePikachu1.jpeg?stamp=2605011226&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/EeveePikachu1.jpeg?stamp=2605011226&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/EeveePikachu3.jpeg?stamp=2605011226&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/EeveePikachu2.jpeg?stamp=2605011226&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4597925-pikachu-eevee'
from public.shelters s
