  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4597925-pikachu-eevee')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Aublysodon', 'Maak kennis met Aublysodon!
Deze nieuwsgierige dame kwam als zwervertje bij ons binnen, waardoor haar exacte leeftijd helaas onbekend is. Wat we wél zeker weten, is dat ze een levendig en ondernemend karakter heeft. Zodra ze zich een beetje op haar gemak voelt, gaat ze op ontdekkingstocht en wil ze alles in haar omgeving zien, ruiken en onderzoeken.

Aublysodon heeft een binnen vacht, om die reden plaatsen we haar uitsluitend binnen.
Heeft u een fijn thuis voor Aubly? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met haar te maken.
Konijnen zijn sociale dieren en wij zullen ze niet plaatsen als er geen ander konijn aanwezig is. Aanvragen voor 1 konijn zullen dan ook niet in behandeling worden genomen.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Aublysodon2.jpeg?stamp=2605011211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Aublysodon2.jpeg?stamp=2605011211&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Aublysodon2.jpeg?stamp=2605011211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aublysodon2.jpeg?stamp=2605011211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aublysodon3.jpeg?stamp=2605011211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aublysodon1.jpeg?stamp=2605011211&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Aublysodon2.jpeg?stamp=2605011211&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Aublysodon2.jpeg?stamp=2605011211&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aublysodon2.jpeg?stamp=2605011211&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aublysodon3.jpeg?stamp=2605011211&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Aublysodon1.jpeg?stamp=2605011211&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4597885-aublysodon'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4597885-aublysodon')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Rex', 'Rex is een prachtig rexkonijn, een gecastreerde ram van bijna 6 jaar oud en het is een vriendelijk en nieuwsgierig konijn. Hij is bij ons afgestaan omdat er sinds de komst van de kinderen minder tijd voor hem is en na het overlijden van zijn maatje werd hem een plekje ergens anders gegund. En daar gaan wij naar op zoek!
Hij heeft tot nu toe 3 partners gehad die hij allemaal verloren heeft, en tijdens al zijn huwelijken was hij een erg gemoedelijke echtgenoot. Hij is natuurlijk weer op zoek naar een nieuwe liefde, want alleen is wel erg eenzaam. Rex heeft geen geschikte vacht om buiten te wonen en daarom zoekt hij een fijn verblijf bij mensen binnen in huis. Hij eet calciumarm (science selective 4+ en Timothyhooi) vanwege blaaszand in het verleden. Heb jij een lieve voedster die een nieuwe liefde zoekt? Laat het ons weten!
ADOPTIE:
Er wordt bij ons in de opvang gekoppeld zodat er de juiste match ontstaat. We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
Naam, adres en telefoonnummerFoto''s en de afmeting van het verblijfInformatie over het eventuele aanwezige konijn waarmee gekoppeld moet worden (geslacht/ leeftijd/ vaccinatiedatum)Zijn er nog andere soorten dieren in huisDe gezinssamenstelling (indien kinderen, de leeftijden)
Kennismaken met de konijnen en knaagdieren kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch of via mail (we bellen met een 088-nr). Let op: dieren dienen bij adoptie met een auto opgehaald te worden.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_330x285_crop_center-center_none/IMG_3837.jpeg?stamp=2604280833&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_3837.jpeg?stamp=2604280833&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_3837.jpeg?stamp=2604280833&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3837.jpeg?stamp=2604280833&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3791.jpeg?stamp=2604280833&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3754.jpeg?stamp=2604280833&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3840.jpeg?stamp=2604280833&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_3837.jpeg?stamp=2604280833&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_3837.jpeg?stamp=2604280833&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3837.jpeg?stamp=2604280833&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3791.jpeg?stamp=2604280833&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3754.jpeg?stamp=2604280833&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3840.jpeg?stamp=2604280833&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301030&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4595295-rex'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4595295-rex')
