insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Maan', 'Hoi ik ben Maan een voedster van 2 jaar oud, ik ben hier afgestaan toen ik drachtig was en mijn jonkies zijn nu groot genoeg.Ik ben een lief, vriendelijk en nieuwsgierig meisje en ben de afgelopen weken in een huis geweest met kinderen en honden. Ik zoek een fijne ruime plek met voldoende aandacht en een lieve gecastreerde man om mee samen te wonen.Heb jij die fijne plek voor mij?', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/IMG_0518.jpeg?stamp=2604281217&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0518.jpeg?stamp=2604281217&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0518.jpeg?stamp=2604281217&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0518.jpeg?stamp=2604281217&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0512.jpeg?stamp=2604281217&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0518.jpeg?stamp=2604281217&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0518.jpeg?stamp=2604281217&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0518.jpeg?stamp=2604281217&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0512.jpeg?stamp=2604281217&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4595881-maan'
from public.shelters s
