limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Hermoine, Ginny & Molly', 'Dit gezellige trio zijn de dames Hermoine (gevlekt), Ginny (enkele lichte vlekjes) en Molly (albino).Een trio dat wij hier in het asiel hebben gekoppeld. Ginny en Hermoine zijn namelijk gedumpt bij een container en op die manier bij ons terecht gekomen. Molly is aan ons afgestaan en was anders maar alleen. De dames vinden het inmiddels heel gezellig samen en klimmen en klauteren het hele verblijf door! Doordat Hermoine en Ginny gedumpt zijn weten we niet precies hoe oud ze zijn, maar we denken niet veel leeftijdsverschil met Molly.Voor dit olijke trio zoeken we een verblijf van minimaal 1 meter bij 50cm, maar groter is natuurlijk altijd leuker!
Heb je interesse in onze 3 dames? Stuur dan een mail naar knaaghof@dierenbescherming.nl met:
Naam, adres en telefoonnummerFoto''s van het verblijfDe afmetingen van het verblijfInformatie over de eventuele aanwezige dieren waarmee gekoppeld moet worden (geslacht/ castratie/ leeftijd)
Kennismaken met de konijnen en knaagdieren kan uitsluitend op afspraak na uitnodiging, dit doen we per mail telefonisch (we bellen met een 088-nr). Let op: dieren dienen bij adoptie met een auto opgehaald te worden.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_330x285_crop_center-center_none/hermoine.jpg?stamp=2604281434&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/hermoine.jpg?stamp=2604281434&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/hermoine.jpg?stamp=2604281434&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine.jpg?stamp=2604281434&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine9.jpg?stamp=2604281435&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine5.jpg?stamp=2604281434&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine2.jpg?stamp=2604281434&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine6.jpg?stamp=2604281434&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine7.jpg?stamp=2604281435&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoin8.jpg?stamp=2604281433&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine4.jpg?stamp=2604281434&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine3.jpg?stamp=2604281434&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/hermoine.jpg?stamp=2604281434&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/hermoine.jpg?stamp=2604281434&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/hermoine.jpg?stamp=2604281434&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4595754-hermoine-ginny-molly'
