limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Odin en Morrigan', 'Deze twee bijzondere konijntjes zijn op zoek naar rustig en begripvol thuis. 
Het gaat om Odin een gecastreerde ram en Morrigan een gesteriliseerde voedster die samen een hecht duo vormen.
Ze zijn nieuwsgierig van aard en komen af en toe gezellig naar het hek om een kijkje te nemen, maar je merkt al snel dat ze een halfwilde achtergrond hebben. Hierdoor zijn ze geen typische konijnen die van heel veel gedoe houden, en willen liever met rust gelaten worden. 
Voor deze twee zoeken we een veilige, ruime leefomgeving waar ze volledig zichzelf kunnen zijn. Een goed afgesloten ren met een dichte bovenkant is noodzakelijk, zodat ze niet kunnen ontsnappen en zich veilig voelen.
Ze passen het beste bij iemand die niet perse "knuffelkonijnen" wil en bereid is hen de tijd te geven te wennen. In ruil daarvoor krijg je twee prachtige eigenzinnige dieren die je met hun nieuwsgierigheid en gedrag je zeker zullen laten glimlachen. 
Geef jij deze twee lieverds een rustige plek die ze verdienen? vul dan het vragenformulier in.

Wij plaatsen konijnen alleen op afspraak.
Odin en Morrigan zijn gechipt en geënt voor RHD1,RHD2 en Myxomatose.
Aangezien wij streven naar een goed welzijn van konijnen hanteren wij de aanbevolen maatstaven van de licg. Graag willen we u eerst doorverwijzen naar onderstaande link om te controleren of uw verblijf aan de juiste afmetingen voldoet; licg.nl - Konijn.
Zie hieronder voor de link naar het verplicht in te vullen vragenformulier.
Pas als uw (compleet) ingevulde formulier binnen is wordt uw aanvraag in behandeling genomen. We zullen dan kijken of u een geschikte match bent voor het dier en dan zullen we u hopelijk telefonisch uitnodigen voor een ontmoeting. Ontmoetingen vinden alleen op afspraak plaats.. We kunnen dieren maximaal 1 week "reserveren". (datum van inplannen afspraak tot datum kennismaking).', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1191673-Odin.jpeg?stamp=2604241335&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1191673-Odin.jpeg?stamp=2604241335&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1191673-Odin.jpeg?stamp=2604241335&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191673-Odin.jpeg?stamp=2604241335&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191673-Odin-2.jpeg?stamp=2604241335&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191083-Morrigan.jpg?stamp=2604241336&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1191673-Odin.jpeg?stamp=2604241335&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1191673-Odin.jpeg?stamp=2604241335&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191673-Odin.jpeg?stamp=2604241335&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191673-Odin-2.jpeg?stamp=2604241335&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1191083-Morrigan.jpg?stamp=2604241336&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4583912-odin'
from public.shelters s
where s.name = 'De Kuipershoek'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4583912-odin')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Flip', 'Flip is een leuk stoer klein manneke die in juli 4 jaar oud wordt. Flippie heeft tot nu toe met een andere ram samengewoond en wij gaan voor hem op zoek naar een leuke voedster die haar buitenverblijf graag wil delen. Flip de bouwer houdt van bouwen en verbouwen, hij verplaatst graag dingen in zijn verblijf en hoopt op speelgoed waar hij mee kan gooien en smijten. 
Toen hij bij ons binnenkwam had hij snot en in plaats van in een buitenverblijf moest hij naar de ziekenboeg. Dat beviel hem voor geen meter en hij was boos op de hele wereld! We geven hem geen ongelijk, het is ook niet leuk om medicijnen toegediend te krijgen en niet naar buiten te kunnen als je dat zo graag wil. Met behulp van bachbloesem werd hij al snel minder boos en zat steeds beter in zijn vel. Inmiddels is hij helemaal hersteld, niet meer boos en zijn we hem weer aan de buitentemperatuur aan het wennen. Vanaf 1 mei mag hij gekoppeld worden aan die ene ware voor hem. Mag Flip bij jou komen wonen?
ADOPTIE:
Er wordt bij ons in de opvang gekoppeld zodat er de juiste match ontstaat. We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
Naam, adres en telefoonnummerFoto''s en de afmeting van het verblijfInformatie over het eventuele aanwezige konijn waarmee gekoppeld moet worden (geslacht/ leeftijd/ vaccinatiedatum)Zijn er nog andere soorten dieren in huisDe gezinssamenstelling (indien kinderen, de leeftijden)
