insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Belle', 'Belle is een prachtig creme met wit ratje van 1 jaar oud en haar maatje is helaas overleden. Omdat haar baasjes haar niet alleen wilde laten is Bel via ons op zoek naar een nieuw huisje. Ze wil natuurlijk samenwonen met een of meerdere soortgenootjes, want in haar uppie wordt ze doodongelukkig. Belle is een beetje angstig en daarom zoekt ze baasjes die al ervaring met ratjes hebben en haar vertrouwen heel geduldig voor zich gaan winnen. 
Kan jij niet wachten om Belle weer gelukkig te maken? Laat het ons weten!
Heb je interesse in Belle? Stuur dan een mail naar knaaghof@dierenbescherming.nl met: 
