insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Sedona', 'Maak kennis met Sedona! Sedona is bij ons gekomen omdat haar maatje helaas was overleden.
