insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Justin', 'Maak kennis met Justin! Justin is bij ons als vondeling binnen gekomen, hierdoor weten wij helaas niet zijn leeftijd.
Justin is een rustig ventje! Hij kijkt graag eerst de situatie even aan voordat hij een keuze maakt. Echt een kat uit de boom kijker! Hij is vaak wel nieuwsgierig genoeg om even bij je te komen kijken. En word hij dan beloont met een klein stukje andijvie, en dat begint hij volgens mij wel door te krijgen. Wanneer wij langs zijn verblijf lopen blijft hij steeds langer zitten om te kijken of hij dan weer iets lekker krijgt. Slim ventje is het dus ook wel!

Heeft u een geschikt maatje voor hem? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis met hem te maken.
Let op: konijnen zijn sociale dieren. We plaatsen Justin alleen bij een voedster. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Justin4.jpeg?stamp=2604221514&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Justin4.jpeg?stamp=2604221514&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Justin4.jpeg?stamp=2604221514&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Justin4.jpeg?stamp=2604221514&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Justin1.jpeg?stamp=2604221514&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Justin2.jpeg?stamp=2604221514&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Justin3.jpeg?stamp=2604221514&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Justin4.jpeg?stamp=2604221514&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Justin4.jpeg?stamp=2604221514&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Justin4.jpeg?stamp=2604221514&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Justin1.jpeg?stamp=2604221514&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Justin2.jpeg?stamp=2604221514&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Justin3.jpeg?stamp=2604221514&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4591590-justin'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4591590-justin')
