insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Dollodon', 'Maak kennis met Dollodon! Dollodon is bij ons als vondeling in de opvang gekomen, hierdoor weten wij helaas niet zijn leeftijd.
Voor Dollodon is niks te gek! Door heel zijn verblijf maakt hij graag binkies en dan word ook echt elk oppervlak aangeraakt. Als je voor zijn verblijf staat komt hij altijd heel nieuwsgierig bij je kijken. En tegen een stuk andijvie zegt hij zeker geen nee!
Oppakken vind hij verder maar niks hij staat het liefst met al zijn vier voetjes op de grond. Soms vind hij nieuwe dingen nog wel spannend en kijkt hij een beetje de kat uit de boom. Maar zodra hij een beetje doorkrijgt wat de situatie is durft hij al wat meer. Heeft u een leuke voedster die met hem mee de omgeving onveilig te maken?

Heeft u een geschikt maatje voor hem? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis met hem te maken.
Let op: konijnen zijn sociale dieren. We plaatsen Dollodon alleen bij een voedster. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Dollodon1.jpeg?stamp=2604221510&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Dollodon1.jpeg?stamp=2604221510&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Dollodon1.jpeg?stamp=2604221510&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Dollodon1.jpeg?stamp=2604221510&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Dollodon2.jpeg?stamp=2604221510&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Dollodon3.jpeg?stamp=2604221510&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Dollodon4.jpeg?stamp=2604221510&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Dollodon1.jpeg?stamp=2604221510&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Dollodon1.jpeg?stamp=2604221510&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Dollodon1.jpeg?stamp=2604221510&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Dollodon2.jpeg?stamp=2604221510&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Dollodon3.jpeg?stamp=2604221510&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Dollodon4.jpeg?stamp=2604221510&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4591564-dollodon'
