insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Moos', 'Mijn naam is Moos een gecastreerd mannetje van net 1 jaar oud. Helaas was mijn laatste vriendin geen match voor altijd...
Ik ben een vriendelijk, lief en zachtaardig mannetje. Ik vind mensen heel leuk en laat mij ook regelmatig aaien. Helaas ben ik alweer een tijdje alleen en zoek ik snel een fijne nieuwe plek met een lieve vriendin om mee samen te wonen. Heb jij die plek voor mij?', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/IMG_0292_2026-04-22-100129_fycs.jpeg?stamp=2604221201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0292_2026-04-22-100129_fycs.jpeg?stamp=2604221201&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0292_2026-04-22-100129_fycs.jpeg?stamp=2604221201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0292_2026-04-22-100129_fycs.jpeg?stamp=2604221201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0298.jpeg?stamp=2604221201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0295.jpeg?stamp=2604221201&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/IMG_0292_2026-04-22-100129_fycs.jpeg?stamp=2604221201&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/IMG_0292_2026-04-22-100129_fycs.jpeg?stamp=2604221201&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0292_2026-04-22-100129_fycs.jpeg?stamp=2604221201&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0298.jpeg?stamp=2604221201&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/IMG_0295.jpeg?stamp=2604221201&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/Banners/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-02.png?stamp=2306300944&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4526618-moos'
from public.shelters s
where s.name = 'Dierentehuis Kennemerland'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4526618-moos')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Mr. Black', 'Maak kennis met Mr. Black! Hij is hier gekomen omdat hij niet meer goed overweg kon met het andere konijn waar hij mee samen woonde.
Dit is de enige man in black die geen aliens jaagt maar wel harten verovert. Mr. Black is een druk en actief mannetje, al is mannetje niet echt van toepassing met zijn formaat ( 4KG). Hij kwam binnen als een erg angstig konijn maar na een week voelde hij zich al helemaal thuis en liet hij zijn lieve iets wat hypere kant zien. We denken dat Mr. Black het erg leuk zal gaan vinden om hersenwerkjes te gaan doen, denk hierbij aan voerpuzzels. Hopelijk zal hij zich hierdoor ook niet snel gaan vervelen.
Mr. Black heeft een binnen vacht, om die reden plaatsen we hem uitsluitend binnen.
Heeft u een voedster die opgewassen is tegen zijn energie? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis te maken met Mr. Black.
Let op: konijnen zijn sociale dieren. We plaatsen Mr. Black alleen bij een voedster. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Mr.-Black-1.jpg?stamp=2603041159&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Mr.-Black-1.jpg?stamp=2603041159&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Mr.-Black-1.jpg?stamp=2603041159&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Mr.-Black-1.jpg?stamp=2603041159&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Mr.-Black1.jpg?stamp=2603041616&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Mr.-Black.jpg?stamp=2603041616&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Mr.-Black-1.jpg?stamp=2603041159&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Mr.-Black-1.jpg?stamp=2603041159&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Mr.-Black-1.jpg?stamp=2603041159&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Mr.-Black1.jpg?stamp=2603041616&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Mr.-Black.jpg?stamp=2603041616&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4549974-mr-black'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4549974-mr-black')
