insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Koppel Juventus en Lupin', 'Juventus (meisje 2 jaar) en Lupin (mannetje, 2 en een half jaar) zoeken samen een thuis. Ze zijn afgestaan wegens verhuizing.
Ze zijn gewend om buiten te wonen, verder hele lieve konijnen. Een mannetje heeft wel ernstig overgewicht en moet afvallen. Dit kan met voeding beperken en voldoende beweging.
Let op: Het is niet mogelijk om de konijnen te bezoeken zonder afspraak. Een afspraak maak je via limburg@dierenbescherming.nl', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Juv.png?stamp=2604211921&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Juv.png?stamp=2604211921&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Juv.png?stamp=2604211921&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Juv.png?stamp=2604211921&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Juv23.png?stamp=2604211921&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Juv2.png?stamp=2604211921&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Juv.png?stamp=2604211921&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Juv.png?stamp=2604211921&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Juv.png?stamp=2604211921&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Juv23.png?stamp=2604211921&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Juv2.png?stamp=2604211921&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4590792-koppel-juventus-en-lupin'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4590792-koppel-juventus-en-lupin')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Diva', 'Diva is een Syrische hamster en ze hoopt via ons een nieuw huisje te vinden. Begin dit jaar werd ze voor de kinderen bij een dierenwinkel aangeschaft maar zoals zoveel hamsters had Diva geen behoefte aan contact met de kinderen. Overdag wilde ze natuurlijk met rust gelaten worden omdat ze dan slaapt en pas ''s avonds en ''s nachts tot leven komt. 
Diva hoopt op baasjes die er vooral heel veel plezier uithalen om ''s avonds te zien hoe Diva op ontdekkingstocht gaat in het door jou ingerichte hamsterscape paradijs. Vrouwtjes hamsters hebben behoefte aan veel ruimte en daarom zoekt ze een terrarium van minstens 1.20 groot. Kan jij niet wachten om elke avond te genieten van live entertainment in je woonkamer? Laat het ons weten!
Heb je interesse in Diva? Stuur dan een mail naar knaaghof@dierenbescherming.nl met:
Naam, adres en telefoonnummerFoto''s van het verblijfDe afmetingen van het verblijf
Kennismaken met de konijnen en knaagdieren kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch (we bellen met een 088-nr). Let op: dieren dienen bij adoptie met een auto opgehaald te worden.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_330x285_crop_center-center_none/IMG_3257.jpeg?stamp=2604191153&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_3257.jpeg?stamp=2604191153&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_3257.jpeg?stamp=2604191153&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3257.jpeg?stamp=2604191153&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3182.jpeg?stamp=2604191153&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3176.jpeg?stamp=2604191153&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3186.jpeg?stamp=2604191153&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3189.jpeg?stamp=2604191153&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3250.jpeg?stamp=2604191153&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_3257.jpeg?stamp=2604191153&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_3257.jpeg?stamp=2604191153&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3257.jpeg?stamp=2604191153&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3182.jpeg?stamp=2604191153&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3176.jpeg?stamp=2604191153&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3186.jpeg?stamp=2604191153&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4588315-diva'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4588315-diva')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Bennie', 'Bennie is een rustig rammetje van bijna 5 jaar oud en hij is bij ons gebracht omdat zijn broertje is overleden en zijn eigenaren wilden stoppen met het houden van konijnen. Nu wil Bennie graag met een lieve voedster samenwonen en weer gelukkig worden, want hij is niet zo blij in zijn uppie. Logisch, want konijnen zijn niet voor niks groepsdieren en alleen is erg eenzaam.
 Bennie heeft een verlegen karakter, is een beetje angstig en houdt zich afzijdig bij veel drukte. Dat maakt hem een ideale kandidaat voor mensen die konijnen vooral hebben om te zien hoe gelukkig ze met elkaar zijn en niet perse een konijn willen die veel van contact met mensen houdt. Bennie is een buitenkonijn en hij hoopt snel zijn intrek te mogen nemen in een konijnenparadijs in iemands tuin, samen met zijn nieuwe liefde. Heb jij een eenzame voedster die goed bij een rustige ram zou passen? Denk dan aan Bennie!
Ps: op de foto lijkt hij misschien groter dan hij is. Hij weegt 1,7 kilo.
ADOPTIE:
