insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Radijs', 'Maak kennis met Radijs! Radijs is bij ons gebracht omdat helaas haar maatje was overleden. In 2023 is ze ook al bij ons binnengekomen als vondeling hierdoor weten wij niet haar leeftijd.
Radijs kijkt graag de kat uit de boom. Ze is van nature wel erg nieuwsgierig en durft al iets vaker bij je te komen kijken. Maar zodra je een beweging richting haar maakt vind ze het al wel spannend en kan ze gaan stampen. We zien met de tijd dat ze al wel steeds meer durft, maar ze wil vooral lekker konijn zijn! Heeft u een leuk plekje voor haar?
Radijs heeft in het verleden haken op haar kiezen gehad. Daarom is dit goed om te benoemen wanneer ze voor haar jaarlijkse dierenarts bezoek moet!
Radijs heeft een buiten vacht, om die reden plaatsen we haar uitsluitend buiten.
Heeft u een fijn thuis waar Radijs lekker konijn kan zijn? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met haar te maken.
Konijnen zijn sociale dieren en wij zullen ze niet plaatsen als er geen ander konijn aanwezig is. Aanvragen voor 1 konijn zullen dan ook niet in behandeling worden genomen.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Radijs3.jpeg?stamp=2604171445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Radijs3.jpeg?stamp=2604171445&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Radijs3.jpeg?stamp=2604171445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Radijs3.jpeg?stamp=2604171445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Radijs2.jpeg?stamp=2604171445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Radijs1.jpeg?stamp=2604171445&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Radijs3.jpeg?stamp=2604171445&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Radijs3.jpeg?stamp=2604171445&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Radijs3.jpeg?stamp=2604171445&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Radijs2.jpeg?stamp=2604171445&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Radijs1.jpeg?stamp=2604171445&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4587086-radijs'
