insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Beertje', 'Beertje is zonder pardon met kooitje en al bij een afvalcontainer gezet. Gelukkig is ze op tijd gevonden en zit ze nu veilig bij ons in de opvang. Beertje zat in een piepklein kooitje die absoluut niet geschikt is voor welk knaagdiertje dan ook en was ook nog eens erg vies en vol met voer wat niet voor hamsters geschikt is. Kortom, ze werd niet goed verzorgd! 
Ook al zijn hamsters zelf klein, ze hebben alsnog veel ruimte nodig en een inrichting volgens het hamsterscape-principe met volop uitdaging en afwisseling, verschillende verstopplekjes en mogelijkheid om tunnels te graven. Beertje zoekt een nieuwe woning (terrarium) van minimaal 1.20m. Haar nieuwe baasjes weten alles van hamsters, of zijn bereid dit te leren en snappen dat ze overdag met rust gelaten moet worden en pas later in de avond en nacht wakker is.
Als je daar rekening mee houd dan zijn het geweldig leuke dieren waarbij je in de avond kan genieten door te kijken haar ontdekkingstochten door het verblijf, het graven van tunnels en natuurlijk het verzamelen van eten. 
Heb je interesse in Beertje? Stuur dan een mail naar knaaghof@dierenbescherming.nl met:
Naam, adres en telefoonnummerFoto''s van het verblijfDe afmetingen van het verblijf
