insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Lio', 'Dit leuke pluizenbolletje met schattig wit neusje is Lio! Hij is nog piepjong en zoekt dus ook een vriendin van rond zijn leeftijd. Zijn vader en moeder werden bij ons afgestaan en hij is vlak daarna in de opvang geboren. Hij heeft een tijdje in een gastgezin gewoond en daar heeft hij heel veel aandacht gehad, wij merken wel dat hij hier alles weer een beetje spannend vindt. Met tijd, liefde en aandacht verwachten we dat het een heel gezellig binnenkonijntje zal worden. Aangezien dit leuke konijntje een teddy dwerg is, heeft hij regelmatig vachtverzorging nodig. Heb je hier nog geen ervaring mee maar sta je wel open om dit te leren? Wij laten je graag zien hoe dit moet wanneer je Lio adopteert.
