insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Lewis', 'Dit leuke pluizenbolletje is Lewis! Hij is nog piepjong en zoekt dus ook een vriendinvan rond zijn leeftijd. Zijn vader en moeder werden bij ons afgestaan en hij is vlak daarna in de opvang geboren. Hij heeft een tijdje in een gastgezin gewoond en daar heeft hij heel veel aandacht gehad, wij merken wel dat hij hier alles weer een beetje spannend vindt. Met tijd, liefde en aandacht verwachten we dat het een heel gezellig binnenkonijntje zal worden.Aangezien dit leuke konijntje een teddy dwerg is, heeft hij regelmatig vachtverzorging nodig. Heb je hier nog geen ervaring mee maar sta je wel open om dit te leren? Wij laten je graag zien hoe dit moet wanneer je Lewis adopteert. Lewis mag vanaf 23 april op date. Hij is uiteraard gecastreerd en is op de plaatsingsdatum ongeveer 16 weken oud.
ADOPTIE:
Er wordt bij ons in de opvang gekoppeld zodat er de juiste match ontstaat. We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
Naam, adres en telefoonnummerFoto''s en de afmeting van het verblijfInformatie over het eventuele aanwezige konijn waarmee gekoppeld moet worden (geslacht/ leeftijd/ vaccinatiedatum)Zijn er nog andere soorten dieren in huisDe gezinssamenstelling (indien kinderen, de leeftijden)
Kennismaken met de konijnen en knaagdieren kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch of via mail (we bellen met een 088-nr). Let op: dieren dienen bij adoptie met een auto opgehaald te worden.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_330x285_crop_center-center_none/IMG_1535.jpeg?stamp=2604141856&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_1535.jpeg?stamp=2604141856&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_1535.jpeg?stamp=2604141856&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1535.jpeg?stamp=2604141856&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1869.jpeg?stamp=2604141856&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3942.jpeg?stamp=2604301844&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3927.jpeg?stamp=2604301844&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_1535.jpeg?stamp=2604141856&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_1535.jpeg?stamp=2604141856&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1535.jpeg?stamp=2604141856&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1869.jpeg?stamp=2604141856&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3942.jpeg?stamp=2604301844&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3927.jpeg?stamp=2604301844&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301030&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4584022-lewis'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4584022-lewis')
