insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Blue', 'We stellen u graag voor aan Blue! Blue is als vondeling bij ons in de opvang gekomen. Hierdoor weten we helaas niet hoe oud ze is of wat ze precies mee heeft gemaakt. 
Kort nadat Blue bij ons binnen is gekomen is zij bevallen van 3 jongen! Omdat zij nu oud genoeg zijn om op eigen pootjes te staan is Blue op zoek naar een nieuw vriendje en een fijn thuis!
Blue is een erg nieuwsgierige en zachtaardige dame. Ze komt altijd even rustig snuffelen om je te begroeten en kijkt vervolgens of ze stiekem even een kijkje buiten haar verblijf kan nemen om dan lekker rond te rennen. 
Blue heeft een binnen vacht, om die reden plaatsen we haar uitsluitend binnen.
In verband met meerdere mislukte koppelingen plaatsen wij Blue uitsluitend via koppelvakantie!
Heeft u de geschikte situatie voor Blue? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met haar te maken.
Konijnen zijn sociale dieren en wij zullen ze niet plaatsen als er geen ander konijn aanwezig is. Aanvragen voor 1 konijn zullen dan ook niet in behandeling worden genomen.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Blue-2.jpg?stamp=2602041444&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Blue-2.jpg?stamp=2602041444&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Blue-2.jpg?stamp=2602041444&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Blue-2.jpg?stamp=2602041444&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Blue-4.jpg?stamp=2602041444&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Blue-1.jpg?stamp=2602041444&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Blue-3.jpg?stamp=2602041444&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Blue-2.jpg?stamp=2602041444&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Blue-2.jpg?stamp=2602041444&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Blue-2.jpg?stamp=2602041444&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Blue-4.jpg?stamp=2602041444&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Blue-1.jpg?stamp=2602041444&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Blue-3.jpg?stamp=2602041444&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4527573-blue'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4527573-blue')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Muffin', 'Kijk eens naar dit gezellige snoetje, dit is Muffin! Hij is 1 jaar en dus nog een jonge blom. Muffin werd afgestaan samen met zijn broertje omdat het onderling niet goed meer ging. Twee rammelaars bij elkaar is dan ook bijna nooit een goede match, dus Muffin zoekt ditkeer een leuk meisje. Zijn doel? Trouwen, samen wonen en heel lang en gelukkig leven!Omdat hij nog een beetje last had van snot heeft hij eerst een behandeling gehad, inmiddels is hij klaar om op koppeldate te gaan. Hij is aan het wennen aan buiten en kan vanaf 17 april buiten gaan leven.Heb jij een leuke vriendin voor onze knappe Muffin? Neem dan contact op.
ADOPTIE:
Er wordt bij ons in de opvang gekoppeld zodat er de juiste match ontstaat. We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
