insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Konijn Dakota', 'Dakota is een dametje van bijna 4 jaar oud. Ze is afgestaan omdat het vriendje is overleden. Het is een dwergkonijntje, vrolijk en lief.
Ze is nu opzoek naar een nieuw vriendje!
Let op: Het is niet mogelijk om de konijnen te bezoeken zonder afspraak. Een afspraak maak je via limburg@dierenbescherming.nlWat betekend gereserveerd?Wij
 koppelen de konijnen altijd aan andere konijnen. Als een konijn 
gereserveerd is wil dit dus zeggen dat er nog een koppeling plaats moet 
vinden. Het kan uiteraard zijn dat het geen match is. Je kan je dus 
altijd als reserve opgeven mocht er geen match zijn, dan benaderen we 
jou direct via de e-mail om een nieuwe koppelafspraak in te plannen', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Dakota_2026-04-11-175001_etmh.png?stamp=2604111950&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Dakota_2026-04-11-175001_etmh.png?stamp=2604111950&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Dakota_2026-04-11-175001_etmh.png?stamp=2604111950&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Dakota_2026-04-11-175001_etmh.png?stamp=2604111950&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Dakota_2026-04-11-175001_etmh.png?stamp=2604111950&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Dakota_2026-04-11-175001_etmh.png?stamp=2604111950&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Dakota_2026-04-11-175001_etmh.png?stamp=2604111950&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4581436-konijn-dakota'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4581436-konijn-dakota')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Marnix', 'Marnix is een lief en knap ventje van 4 jaar oud. Hij is bij ons afgestaan vanwege tijdgebrek en allergie en we gaan voor deze leukerd nu op zoek naar een nieuw huisje. Wij hebben hem natuurlijk laten castreren en vanaf 17 april kan hij aan een leuke voedster gekoppeld worden. 
Marnix is vriendelijk en nieuwsgierig en dat maakt hem een gezellige aanwinst in de tuin. Heb jij een ruim verblijf voor hem en natuurlijk een lief konijnenmeisje? Laat het ons weten!
ADOPTIE:
Er wordt bij ons in de opvang gekoppeld zodat er de juiste match ontstaat. We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
Naam, adres en telefoonnummerFoto''s en de afmeting van het verblijfInformatie over het eventuele aanwezige konijn waarmee gekoppeld moet worden (geslacht/ leeftijd/ vaccinatiedatum)Zijn er nog andere soorten dieren in huisDe gezinssamenstelling (indien kinderen, de leeftijden)
