insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Milo', 'Het is een plaatje: Milo is een chocoladebruin konijn van 1,7 kilo. Omdat hij buiten is gevonden weten we niet hoe oud hij is. Milo is een vriendelijk konijn die nieuwsgierig komt kijken wanneer je bij hem in de buurt komt. Aandacht? Heel graag voor deze meneer! 
We hebben naar zijn wensenlijstje geluisterd voor zijn nieuwe thuis en hij wil graag een konijnenvriendin die lekker ruikt en lief is. Ook zou hij het liefste heel veel ruimte hebben om lekker te kunnen sprinten en konijn zijn. Kan jij hem dit bieden? Reageer dan en wie weet kunnen we hem koppelen met jouw voedster.
Milo mag vanaf 17 april op date, dan is hij lang genoeg gecastreerd.
