insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Rachel', 'Rachel is een knappe hangoor dame die helaas een ander plekje moest zoeken omdat ze teveel stress kreeg van de hond die haar steeds wilde opjagen.We merken dat Rachel hierdoor nog wat schrikkerig is af en toe. Wel zien we steeds meer haar nieuwsgierige en lieve kant naar boven komen. Als ze eenmaal gewend is kan ze een aaitje op haar koppie ook zeker waarderen! Rachel is gek op het knagen van wilgentakken dus lekker knaagmateriaal in haar nieuwe verblijf zou ze heel fijn vinden. Ook een ruim verblijf om lekker een sprintje te kunnen trekken vindt ze wel wat! 5 jaar betekent nog lang niet achter de geraniums zitten voor Rachel!Heb jij een leuke man die een lieve dame zoekt? Lees dan hieronder hoe je kan reageren.
