insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Zandvoort', 'Kleine konijntjes', 'Hoi, wij zijn 6 broers en zussen van bijna 7 weken oud. Wij zijn geboren in het asiel en mogen bijna verhuizen.
Op dit moment verblijven wij in een pleeggezin dus we zijn gewend aan veel aandacht. Ook zijn wij gewend aan honden en kinderen en komen we graag bij je voor aandacht. Wij zoeken een fijne nieuwe plek, of samen met een broer of zus, of een plekje waar we later gekoppeld worden aan een ander maatje.
Wij zoeken een huisje voor het leven en niet voor even!', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_330x285_crop_center-center_none/20260318_131621.jpg?stamp=2604061148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/20260318_131621.jpg?stamp=2604061148&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/20260318_131621.jpg?stamp=2604061148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/20260318_131621.jpg?stamp=2604061148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/20260405_190135.jpg?stamp=2604061149&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/20260405_190207.jpg?stamp=2604061148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/20260405_190411.jpg?stamp=2604061148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/20260405_190243.jpg?stamp=2604061148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/20260405_190309.jpg?stamp=2604061148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/20260405_190312.jpg?stamp=2604061148&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_800x550_crop_center-center_none/20260405_190446.jpg?stamp=2604061147&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_384x330_crop_center-center_none/20260318_131621.jpg?stamp=2604061148&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierentehuisKennemerland/_519x453_crop_center-center_none/20260318_131621.jpg?stamp=2604061148&amp;tag=xs', 'https://cms.d