insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', 'Peter', 'Dit is Peter.
Peter is een mooie blauwgrijze gecastreerde ram van bijna 3 kg. Hij is een vriendelijk en rustig konijn. Peter heeft een buitenvacht en we zijn op zoek naar een ruim buitenverblijf voor hem met een voedster als maatje.
Heeft u een voedster die op zoek is naar een maatje, dan kunt u contact met ons opnemen voor een koppeling bij het asiel.
Bij interesse in Peter ontvangen we graag een e-mail met foto''s en de maten van het verblijf. De beste match is een gecastreerde ram met een voedster.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_330x285_crop_center-center_none/petertjee.png?stamp=2604271502&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_384x330_crop_center-center_none/petertjee.png?stamp=2604271502&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_519x453_crop_center-center_none/petertjee.png?stamp=2604271502&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/petertjee.png?stamp=2604271502&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/peet.jpg?stamp=2604271457&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Peter.jpg?stamp=2604021155&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Peter-1.jpg?stamp=2604021155&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_384x330_crop_center-center_none/petertjee.png?stamp=2604271502&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_519x453_crop_center-center_none/petertjee.png?stamp=2604271502&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/petertjee.png?stamp=2604271502&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Actueel/_800x550_crop_center-center_none/peet.jpg?stamp=2604271457&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Peter.jpg?stamp=2604021155&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Peter-1.jpg?stamp=2604021155&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_882x1004_crop_center-center_none/banner-beeld-hond-close-885.png?stamp=2504161034&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4574971-peter'
