insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Grover en Nijn', 'Nijn is een hangoordame van 5 jaar oud. Samen met haar kleine harige vriendje Grover van 5 vormen ze een leuk duo! Het gezin waar ze woonden kon hen helaas niet meenemen met de verhuizing naar een andere woning. Beide konijntjes zijn vriendelijk en na een wenperiode best nieuwsgierig. Ze zijn gewend om binnen in huis te wonen en dat is wat ze weer zoeken een ruim verblijf waar ze lekker kunnen rennen, chillen en knagen. 
Grover heeft geen geschikte vacht om buiten te verblijven. Zijn vacht moet goed bijgehouden worden om nare klitten te voorkomen. Op dit moment heeft hij een korte coupe. Uiteraard kunnen we de toekomstige baasjes leren hoe de vacht verzorgd moet worden, daarnaast is het natuurlijk ook een optie dat hij regelmatig door een konijnentrimmer onder handen genomen wordt. 
Val jij voor dit leuke duo en kun je niet wachten om kennis met ze te maken? Laat het ons weten!
ADOPTIE:
Heb je interesse in dit leuke duo? We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
Naam, adres en telefoonnummerFoto''s en de afmeting van het verblijfZijn er nog andere soorten dieren in huisDe gezinssamenstelling (indien kinderen, de leeftijden)
Kennismaken met de konijnen en knaagdieren kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch of via mail (we bellen met een 088-nr). Let op: dieren dienen bij adoptie met een auto opgehaald te worden.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_330x285_crop_center-center_none/IMG_2357.jpeg?stamp=2604051110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_2357.jpeg?stamp=2604051110&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_2357.jpeg?stamp=2604051110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2357.jpeg?stamp=2604051110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2376.jpeg?stamp=2604051110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2377.jpeg?stamp=2604051110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2330.jpeg?stamp=2604051111&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2368.jpeg?stamp=2604051111&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2329.jpeg?stamp=2604051111&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2363.jpeg?stamp=2604051111&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2352.jpeg?stamp=2604051110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_2354.jpeg?stamp=2604051110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_3811.jpeg?stamp=2604272003&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_2357.jpeg?stamp=2604051110&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_2357.jpeg?stamp=2604051110&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4577415-grover-en-nijn'
