insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Milky en Smartie', 'Milky (Peruvian mix) en Smartie (borstel) zijn 2 gecastreerde heren die helaas vanwege allergie in het gezin herplaatst moesten worden. Smartie is de stoerste van de twee. Hij hobbelt lekker door het hok op zoek naar wat te knabbelen of een lekker plekje om te dutten. Milky vindt het duidelijk allemaal nog erg spannend hier en blijft liever lekker veilig in een huisje zitten als wij er zijn. We zien wel dat ook hij steeds meer los komt. Hopelijk durven ze in hun nieuwe huisje zichzelf nog meer te laten zien!Doordat Milky een kruising met een Peruvian is heeft hij hier en daar wat lange plukken. Deze moeten dan ook af en toe geknipt worden. Als je dat geen enkel probleem vindt dan kan je hieronder lezen hoe je kunt reageren!
ADOPTIE:
We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
Naam, adres en telefoonnummerFoto''s en de afmeting van het verblijfZijn er nog andere soorten dieren in huisDe gezinssamenstelling (indien kinderen, de leeftijden)
Kennismaken met de konijnen en knaagdieren kan uitsluitend op afspraak na uitnodiging, dit doen we per mail of telefonisch (we bellen met een 088-nr). Let op: dieren dienen bij adoptie met een auto opgehaald te worden.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_330x285_crop_center-center_none/Milky2.jpg?stamp=2604071343&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_384x330_crop_center-center_none/Milky2.jpg?stamp=2604071343&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_519x453_crop_center-center_none/Milky2.jpg?stamp=2604071343&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Milky2.jpg?stamp=2604071343&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/4593606/Smartie-Milky-2.jpg?stamp=2604242051&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/4593605/Smartie-Milky-1.jpg?stamp=2604242051&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1961.jpeg?stamp=2604031454&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/_800x550_crop_center-center_none/Milky.jpg?stamp=2604071343&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1947.jpeg?stamp=2604031454&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1944.jpeg?stamp=2604031454&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_1964_2026-04-03-125518_vppq.jpeg?stamp=2604031455&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x55