insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', 'Joep', 'Dit is Joep.
Joep is een vriendelijk en voorzichtig konijn. Met zijn 1,3 kg is hij niet zo groot. Hij is nieuwsgierig, maar vindt het soms een beetje spannend als je een snelle beweging maakt. Joep heeft een buitenvacht en we zijn op zoek naar een ruim buitenverblijf voor hem met een voedster als maatje.
Heeft u een voedster die op zoek is naar een maatje, dan kunt u contact met ons opnemen voor een koppeling bij het asiel.
Bij interesse in Joep ontvangen we graag een e-mail met foto''s en de maten van het verblijf. De beste match is een gecastreerde ram met een voedster.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_330x285_crop_center-center_none/Joep.jpg?stamp=2604021150&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_384x330_crop_center-center_none/Joep.jpg?stamp=2604021150&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_519x453_crop_center-center_none/Joep.jpg?stamp=2604021150&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Joep.jpg?stamp=2604021150&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Joep-1.jpg?stamp=2604021150&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_384x330_crop_center-center_none/Joep.jpg?stamp=2604021150&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_519x453_crop_center-center_none/Joep.jpg?stamp=2604021150&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Joep.jpg?stamp=2604021150&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/Joep-1.jpg?stamp=2604021150&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_882x1004_crop_center-center_none/banner-beeld-hond-close-885.png?stamp=2504161034&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4574945-joep'
