insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Konijn Marie', 'Marie is een meisje van 2,5 jaar oud die afgestaan is wegens verhuizing naar een woning waar geen huisdieren waren toegestaan.
Het is een vrolijke meid die opzoek is naar een thuis bij iemand met een leuk gecastreerd vriendje voor haar.
Let op: Het is niet mogelijk om de konijnen te bezoeken zonder afspraak. Een afspraak maak je via limburg@dierenbescherming.nlWat betekend gereserveerd?Wij
 koppelen de konijnen altijd aan andere konijnen. Als een konijn 
gereserveerd is wil dit dus zeggen dat er nog een koppeling plaats moet 
vinden. Het kan uiteraard zijn dat het geen match is. Je kan je dus 
altijd als reserve opgeven mocht er geen match zijn, dan benaderen we 
jou direct via de e-mail om een nieuwe koppelafspraak in te plannen', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Marie2_2026-04-01-091825_ybsb.png?stamp=2604011118&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Marie2_2026-04-01-091825_ybsb.png?stamp=2604011118&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Marie2_2026-04-01-091825_ybsb.png?stamp=2604011118&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Marie2_2026-04-01-091825_ybsb.png?stamp=2604011118&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Marie2_2026-04-01-091825_ybsb.png?stamp=2604011118&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Marie2_2026-04-01-091825_ybsb.png?stamp=2604011118&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Marie2_2026-04-01-091825_ybsb.png?stamp=2604011118&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4573712-konijn-marie'
