insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Ties', 'Maak kennis met Ties! Hij is bij ons gekomen nadat zijn maatje is overleden.
Ties is een oude bekende en is heeft hier in 2023 ook al verbleven. Helaas is hij zijn maatje dus verloren. Ties heeft even de tijd nodig om mensen te leren kennen voordat hij wat meer uit zijn schulp durft te kruipen en kijkt graag even de kat uit de boom. Hij zou baat hebben met een maatje die graag het voortouw neemt en samen met hem op pad gaat.

Heeft u een avontuurlijke dame voor hem? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis te maken met hem.
