insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Delwin', 'Maak kennis met Delwin! Deze lieve dame is bij ons in de opvang gekomen omdat haar vorige eigenaar helaas afstand van haar moest doen. Nu is ze op zoek naar een rustig en begripvol huisje waar ze opnieuw kan wennen en opbloeien.
Delwin is een hangoor van bijna twee jaar oud. Ze is in eerste instantie wat schuw en heeft echt even de tijd nodig om nieuwe mensen en haar omgeving te leren kennen. Het is belangrijk dat haar nieuwe eigenaar haar die rust en ruimte kan bieden.
Wanneer Delwin zich op haar gemak voelt, laat ze steeds meer van haar persoonlijkheid zien. Dan komt haar nieuwsgierige en ondeugende kant naar boven en zie je wat voor leuk konijntje ze eigenlijk is. Bij haar vorige baasje mocht ze los rondlopen. 
Voor Delwin zoeken we een rustig thuis waar ze in haar eigen tempo mag wennen. Een lieve, stabiele ram die haar wat vertrouwen kan geven en haar een beetje op sleeptouw neemt, zal haar zeker goed doen. Met geduld en liefde zal Delwin uitgroeien tot een fijn en bijzonder maatje.
Delwin heeft een binnen vacht, om die reden plaatsen we haar uitsluitend binnen.
Heeft u een geschikt maatje voor haar? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis met haar te maken.
Let op: konijnen zijn sociale dieren. We plaatsen Delwin alleen bij een gecastreerde ram. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Delwin-2_2026-03-30-101751_mklx.jpg?stamp=2603301217&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Delwin-2_2026-03-30-101751_mklx.jpg?stamp=2603301217&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Delwin-2_2026-03-30-101751_mklx.jpg?stamp=2603301217&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Delwin-2_2026-03-30-101751_mklx.jpg?stamp=2603301217&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Delwin-1_2026-03-30-101750_ocvp.jpg?stamp=2603301217&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Delwin-2_2026-03-30-101751_mklx.jpg?stamp=2603301217&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Delwin-2_2026-03-30-101751_mklx.jpg?stamp=2603301217&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Delwin-2_2026-03-30-101751_mklx.jpg?stamp=2603301217&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Delwin-1_2026-03-30-101750_ocvp.jpg?stamp=2603301217&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4571854-delwin'
from public.shelters s
