insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Konijn Nio', 'Nio is een konijntje van ongeveer 2 jaar oud die afgestaan is omdat de hond van de eigenaar het konijn niet met rust liet.
Hij is vriendelijk en lief, sociaal naar mensen toe. En mag al op date!
