insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Lars', 'Lars is een heel knap blauw kleurdwergje die samen met zijn broer is gevonden. Broertjelief heeft een fijn huisje gevonden, nu Lars nog! Natuurlijk is hij gecastreerd, ingeent en gechipt. 
Hij is op zoek naar een vrouwelijke liefde in zijn leven en een leuk verblijf in de tuin waar hij sprintjes kan trekken. Lars is heel nieuwsgierig en houdt alles graag in de gaten vanaf zijn huisje. Val jij voor dit kleine leuke ventje? Hieronder lees je hoe je kunt reageren.
