insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Groningen', 'Robin', 'Dit is Robin.
Robin is een leuk en nieuwsgierig konijn. Bij binnenkomst in het asiel had hij olifantstanden. Inmiddels zijn zijn snijtanden getrokken en heeft hij hier geen last meer van. Robin kan er prima om eten, al gaat het eten van groenvoer wat makkelijker als dat in kleine stukjes wordt aangeboden.
Robin is gecastreerd en helemaal klaar voor een nieuw thuis. Robin heeft een binnenvacht, dus we zoeken een huis voor hem waar hij binnen wordt gehouden. Heeft u een voedster die op zoek is naar een maatje, dan kunt u contact met ons opnemen voor een koppeling bij het asiel.
Bij interesse in Robin ontvangen we graag een e-mail met foto''s en de maten van het verblijf. De beste match is een gecastreerde ram met een voedster.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_330x285_crop_center-center_none/4593466/robin-15.jpg?stamp=2604241728&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_384x330_crop_center-center_none/4593466/robin-15.jpg?stamp=2604241728&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_519x453_crop_center-center_none/4593466/robin-15.jpg?stamp=2604241728&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593466/robin-15.jpg?stamp=2604241728&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593465/robin-14.jpg?stamp=2604241721&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593469/robin-5.jpg?stamp=2604241722&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593464/robin-2.jpg?stamp=2604241721&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593463/robin-1.jpg?stamp=2604241721&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/_800x550_crop_center-center_none/1190669-Robin.jpg?stamp=2604211553&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_384x330_crop_center-center_none/4593466/robin-15.jpg?stamp=2604241728&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_519x453_crop_center-center_none/4593466/robin-15.jpg?stamp=2604241728&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593466/robin-15.jpg?stamp=2604241728&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593465/robin-14.jpg?stamp=2604241721&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593469/robin-5.jpg?stamp=2604241722&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumNoordNederland/Algemeen/_800x550_crop_center-center_none/4593464/robin-2.jpg?stamp=2604241721&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4563929-robin'
