insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Mochi & Marley', 'Dit vrolijke duo zijn Mochi en Marley. Mochi is een Sheltie wit california choco en Marley is een Tessel rood bont. De dames zijn bij ons afgestaan omdat de vachtverzorging toch wel veel tijd in beslag nam. Het is dus goed om te weten dat beide dames regelmatig geknipt moeten worden om te zorgen dat er geen urine en ontlasting in hun haar blijft hangen. Maar ook om te voorkomen dat ze klitten krijgen!Mochi is de stoerste van de twee. Ze is erg nieuwsgierig en komt altijd even kijken als je aan het voeren bent. Marley vindt het hier allemaal maar spannend. Ze durft zeker wel in het zicht te blijven als je er bent, ze zal zich dan niet gaan verstoppen. Maar aandacht vindt ze nog spannend. We verwachten dat als zij eenmaal op haar gemak is dit wel goed komt.Heb jij een heerlijk ruim hok voor deze dames met lekker veel zachte mandjes en vindt je de wekelijkse vachtverzorging niet erg? Lees dan hieronder hoe je kan reageren.
ADOPTIE:
