insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Sterre', 'Deze dame van het goede leven heet Sterre. Ze is bijna 3,5 jaar en afgestaan wegens allergie. Zoals je kan zien is ze best wel aan de maat, we geven dus graag tips mee hoe ze op een gezonde manier naar een goed gewicht kan gaan voor haar grootte.
Sterre is een leuk ondernemend konijntje en wij merken dat ze het erg gezellig vindt in onze aanwezigheid, ze wil soms geaaid worden en soms loopt ze weg om op haar gemak haar eigen ding te gaan doen.
Ze mag op zoek naar een vriendje en een plekje om te wonen.

