insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Adam & Miena', 'Maak kennis met Adam & Miena! Er is afstand van hen gedaan omdat de vorige eigenaar de zorg niet meer kon dragen.
Adam en Miena zijn elkaars steun en toeverlaat, beide vinden mensen maar erg spannend en leunen veel op elkaar tijdens deze stressvolle periode. Adam heeft wat wilde lokken rondom zijn hoofdje en deze kunnen makkelijk gaan klitten als ze niet gekamd worden. Hopelijk zullen ze als ze weer een fijn thuis hebben weer ontdooien en kunnen ze hun ware aard weer laten zien.
Heeft u al interesse in dit leuke koppel? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met hen te maken.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Adam-en-Miena.jpg?stamp=2603041614&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Adam-en-Miena.jpg?stamp=2603041614&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Adam-en-Miena.jpg?stamp=2603041614&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Adam-en-Miena.jpg?stamp=2603041614&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Miena.jpg?stamp=2603041614&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Adam.jpg?stamp=2603041614&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Adam-en-Miena.jpg?stamp=2603041614&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Adam-en-Miena.jpg?stamp=2603041614&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Adam-en-Miena.jpg?stamp=2603041614&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Miena.jpg?stamp=2603041614&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Adam.jpg?stamp=2603041614&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4550249-adam-miena'
