insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Ficus', 'Maak kennis met Ficus! Ficus is bij ons in de opvang gekomen omdat haar maatje helaas is overleden. Daarom is ze nu weer opzoek naar een nieuwe vriend en een liefdevol thuis.
Ficus is een rexkonijn van 4 jaar oud, ze is erg nieuwsgierig en laat niet zomaar over zich heenlopen. In het verleden heeft zij namelijk een keer een aanvaring gehad met een marter, het enige wat zij hier aan over heeft gehouden is een litteken op haar neus. Verder onderzoekt ze alles graag, alleen een aai kan ze soms nog wat spannend vinden.
Ficus heeft een binnen vacht, om die reden plaatsen we haar uitsluitend binnen.
In verband met meerdere mislukte koppelingen plaatsen wij Ficus uitsluitend via koppelvakantie!
Ben jij op zoek naar een nieuwsgierige en ondernemende konijnendame? Vul dan snel het aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis te maken met Ficus.
Let op: konijnen zijn sociale dieren. We plaatsen Ficus alleen bij een gecastreerde ram. Aanvragen voor één konijn nemen we niet in behandeling.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Ficus-1.jpg?stamp=2603031644&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Ficus-1.jpg?stamp=2603031644&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Ficus-1.jpg?stamp=2603031644&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Ficus-1.jpg?stamp=2603031644&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Ficus-2.jpg?stamp=2603031644&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Ficus-3.jpg?stamp=2603031644&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Ficus-1.jpg?stamp=2603031644&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Ficus-1.jpg?stamp=2603031644&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Ficus-1.jpg?stamp=2603031644&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Ficus-2.jpg?stamp=2603031644&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Ficus-3.jpg?stamp=2603031644&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4549557-ficus'
