insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Vlaardingen', 'Bundy', 'Dit knappe kereltje is Bundy. Een leuk mannetje van 5 en een half jaar oud die helemaal klaar is voor een nieuw hoofdstuk in zijn leven. Door allergie in het gezin is er helaas afstand van hem gedaan. Bundy heeft nog nooit een vriendinnetje gehad en kan niet wachten om zijn single leven achter zich te laten. Bundy is een actief en nieuwsgierig konijntje met een heerlijk eigen willetje. Hij houdt van ontdekken, rondhuppelen en zijn omgeving inspecteren. Een ruim buitenverblijf waar hij lekker zijn energie kwijt kan, is daarom echt een must voor hem. Bundy kan ook een eigen willetje hebben en daarom denken wij dat een gezin met jonge kinderen niet bij hem passen. Oudere kinderen die begrijpen dat een konijn ook zijn eigen grenzen heeft, zullen waarschijnlijk geen enkel probleem zijn.Heb jij een lieve voedster die nog een charmante heer mist aan haar zijde? En kun jij Bundy een fijne, veilige plek bieden waar hij helemaal zichzelf mag zijn? Mail ons dan snel!
ADOPTIE:
Er wordt bij ons in de opvang gekoppeld zodat er de juiste match ontstaat. We verzoeken om de volgende informatie via knaaghof@dierenbescherming.nl te sturen:
Naam, adres en telefoonnummerFoto''s en de afmeting van het verblijfInformatie over het eventuele aanwezige konijn waarmee gekoppeld moet worden (geslacht/ leeftijd/ vaccinatiedatum)Zijn er nog andere soorten dieren in huisDe gezinssamenstelling (indien kinderen, de leeftijden)
Kennismaken met de konijnen en knaagdieren kan uitsluitend op afspraak na uitnodiging, dit doen we telefonisch of via mail (we bellen met een 088-nr). Let op: dieren dienen bij adoptie met een auto opgehaald te worden.', 'rodent', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_330x285_crop_center-center_none/IMG_0382.jpeg?stamp=2602281346&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_0382.jpeg?stamp=2602281346&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_0382.jpeg?stamp=2602281346&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_0382.jpeg?stamp=2602281346&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_0367.jpeg?stamp=2602281346&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_0373.jpeg?stamp=2602281346&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_0379.jpeg?stamp=2602281346&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_384x330_crop_center-center_none/IMG_0382.jpeg?stamp=2602281346&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_519x453_crop_center-center_none/IMG_0382.jpeg?stamp=2602281346&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_0382.jpeg?stamp=2602281346&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_0367.jpeg?stamp=2602281346&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_0373.jpeg?stamp=2602281346&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Dieren/_800x550_crop_center-center_none/IMG_0379.jpeg?stamp=2602281346&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumVlaardingen/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301030&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4546923-bundy'
from public.shelters s
where s.name = 'Dierenopvangcentrum Vlaardingen'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4546923-bundy')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Hessel', 'Zoofff… hoor ik daar nou een vliegtuig? Nee hoor, dat is Hessel!
Met zijn brede, zijwaarts hangende oren lijkt hij klaar om op te stijgen, maar Hessel blijft het liefst met al zijn pootjes stevig op de grond.
Deze relaxte heer is bij ons terechtgekomen via een uitwisseling met een andere opvang, waar hij als vondeling binnenkwam. Daardoor weten we helaas niet precies hoe oud hij is of wat hij allemaal heeft meegemaakt. Omdat hij in de opvang nog flink gegroeid is hebben we een leeftijd in kunnen schatten
Hessel is een echte levensgenieter: languit in zijn verblijf, lekker soezen in de zon, en een aaitje op zijn kop vindt hij heerlijk. Optillen? Nee, dat hoeft van hem niet, dat past niet bij zo’n rustig type dat graag met zijn pootjes op de grond blijft.
Hessel is in de opvang uitgebreid behandeld tegen snot en dit lijkt nu goed onder controle te zijn. Wel plaatsen wij hem uitsluitend met een koppelvakantie om de koppeling hopelijk wat minder stressvol voor hem te maken om te voorkomen dat zijn snot weer terug komt
Let op! Hessel heeft een binnenvacht en wordt uitsluitend binnen geplaatst!
Heb je de juiste plek voor deze charmante piloot van het zonnetje?
Vul dan snel het onderstaand aanvraagformulier hieronder in (met een duidelijke foto van het verblijf bij stap 3). Dan nemen wij contact met je op om kennis te komen maken met Hessel.
