insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Nosey en Zaza', 'Maak kennis met Nosey en Zaza! Zij hebben elkaar hier in de opvang leren kennen.
Nosey (de kleine van de twee) is een gecastreerde ram van ongeveer 6 maanden oud. Hij is erg nieuwsgierig, maar wel een beetje verlegen.
Zaza (de grote van de twee) is een voedster. Omdat zij als vondeling binnen is gekomen weten we helaas niet hoe oud ze is. Ze is net als Nosey heel nieuwsgierig, maar ook wat stoerder. We merken dat Nosey hier veel baat bij heeft, omdat hij heel graag in de buurt van Zaza is. Hij hupst haar namelijk overal achterna!
Zaza heeft een halflange vacht, dit zal regelmatig op klitten gecontroleerd moeten worden. Ze zal niet geknipt hoeven worden.
Let op! Nosey en Zaza hebben een binnenvacht, daarom worden zij uitsluitend binnen geplaatst.
Heeft u al interesse in dit leuke koppel? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met hen te maken.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Zaza-en-Nosey8.jpg?stamp=2601271532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Zaza-en-Nosey8.jpg?stamp=2601271532&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Zaza-en-Nosey8.jpg?stamp=2601271532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Zaza-en-Nosey8.jpg?stamp=2601271532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Zaza-en-Nosey-2.jpg?stamp=2601271533&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Zaza-en-Nosey7.jpg?stamp=2601271533&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Zaza-en-Nosey4.jpg?stamp=2601271534&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Zaza-en-Nosey6.jpg?stamp=2601271534&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Zaza-en-Nosey3.jpg?stamp=2601271532&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Zaza-en-Nosey5.jpg?stamp=2601271534&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Zaza-en-Nosey1.jpg?stamp=2601271532&tag=xs', 'https://cms.die