insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Anthony Green', 'Dit is Anthony Green! Hij is samen met vermoedelijk zijn broertje bij ons in de opvang gekomen als vondeling. Hierdoor weten wij niet zijn exacte leeftijd en zijn verleden.
Anthony Green is een enorm nieuwsgierig konijn en komt graag naar je toe rennen als je zijn verblijf in komt. Wel zien we dat hij eerst even de kat uit de boom kijkt, hij heeft dus even de tijd nodig om aan een nieuwe situatie te wennen. Voor een lekkere gezonde snack komt hij graag bij je kijken en neemt dit dan trots van je aan. Een aai over zijn kopje kan hij soms waarderen, maar stilzitten is nog niet zijn sterkste kant. 
Anthony Green kan redelijk hoog springen en daarom zoekt hij een hoge of goed afgesloten ren.

Heeft u de geschikte situatie voor hem? Vul dan snel het onderstaand aanvraagformulier in, bij stap 3, met een duidelijke foto van het verblijf. Wij nemen dan zo snel mogelijk contact met u op voor een afspraak om kennis met hem te maken.
Konijnen zijn sociale dieren en wij zullen ze niet plaatsen als er geen ander konijn aanwezig is. Aanvragen voor 1 konijn zullen dan ook niet in behandeling worden genomen.', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Anthony.jpeg?stamp=2601261516&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Anthony.jpeg?stamp=2601261516&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Anthony.jpeg?stamp=2601261516&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Anthony.jpeg?stamp=2601261516&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Anthony-4.jpeg?stamp=2601261516&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Anthony-2.jpeg?stamp=2601261516&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Anthony-3.jpeg?stamp=2601261516&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Anthony.jpeg?stamp=2601261516&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Anthony.jpeg?stamp=2601261516&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Anthony.jpeg?stamp=2601261516&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Anthony-4.jpeg?stamp=2601261516&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Anthony-2.jpeg?st