insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Konijn Bounty', 'Bounty is een dametje van 1,5 jaar oud. Ze is afgestaan omdat haar konijnenmaatje is overleden en de kinderen geen interesse meer hadden in de konijnen. Kort geplaatst geweest maar helaas teruggekomen wegens dat het geen match was met het dominante mannetje. Het is een pittige meid tijdens koppelingen.
Deze dame is opzoek naar een leuk gecastreerd vriendje om mee samen te wonen! Ze is groter dan een dwergje.
Let op: Het is niet mogelijk om de konijnen te bezoeken zonder afspraak. Een afspraak maak je via limburg@dierenbescherming.nlWat betekend gereserveerd?Wij koppelen de konijnen altijd aan andere konijnen. Als een konijn gereserveerd is wil dit dus zeggen dat er nog een koppeling plaats moet vinden. Het kan uiteraard zijn dat het geen match is. Je kan je dus altijd als reserve opgeven mocht er geen match zijn, dan benaderen we jou direct via de e-mail om een nieuwe koppelafspraak in te plannen', 'rabbit', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Konijnbounty.png?stamp=2604011110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Konijnbounty.png?stamp=2604011110&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Konijnbounty.png?stamp=2604011110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Konijnbounty.png?stamp=2604011110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Konijnbounty23.png?stamp=2604011110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/Bounty2.png?stamp=2601181728&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Konijnbounty2.png?stamp=2604011110&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/Bounty.png?stamp=2601181728&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Konijnbounty.png?stamp=2604011110&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Konijnbounty.png?stamp=2604011110&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Konijnbounty.png?stamp=2604011110&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Konijnbounty23.png?stamp=2604011110&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/Bounty2.png?stamp=2601181728&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Konijnbounty2.png?stamp=2604011110&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Dieren/_800x550_crop_center-center_none/Bounty.png?stamp=2601181728&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/konijnen-en-knagers/4512997-konijn-bounty'
