insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Kanarie Amaterasu', 'Kanarie Amaterasu zoekt een volière met soort genootjes!
Bij ons in het asiel heeft hij Iverdrops (ontworming) gekregen.
Mocht u interesse hebben, dan ontvangen wij graag een reactie per mail met uw ervaring met kanaries, of u al andere kanaries heeft en foto''s van het verblijf.
Let wel, vogels willen graag hun vleugels strekken. We plaatsen onze vogels dan ook enkel bij mensen met een ruim genoeg verblijf of volière.', 'wildlife', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1193598-Kanarie.jpeg?stamp=2605081413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1193598-Kanarie.jpeg?stamp=2605081413&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1193598-Kanarie.jpeg?stamp=2605081413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193598-Kanarie.jpeg?stamp=2605081413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193598-Kanarie-2.jpeg?stamp=2605081413&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1193598-Kanarie.jpeg?stamp=2605081413&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1193598-Kanarie.jpeg?stamp=2605081413&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193598-Kanarie.jpeg?stamp=2605081413&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1193598-Kanarie-2.jpeg?stamp=2605081413&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306290837&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/vogels/4604348-kanarie-amaterasu'
