insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Rotterdam', 'Fiffie', 'Maak kennis met Fiffie, een nieuwsgierige en gezellige valkparkiet met een eigen willetje! 🐦✨
Het geslacht van Fiffie is onbekend, maar één ding is zeker: deze leuke vogel heeft volop karakter 💛 Fiffie is niet tam, maar ook zeker niet bang. Nieuwsgierig kijkt die graag mee naar alles wat er gebeurt en ontdekt enthousiast de omgeving. Met dat grappige koppie en al die nieuwsgierigheid zorgt Fiffie regelmatig voor vrolijke momenten 🥰
Hoewel Fiffie geen echte knuffelvogel is, geniet die wel van gezelligheid en aanwezigheid om zich heen. Fiffie zoekt een baasje dat begrijpt dat niet elke vogel tam hoeft te zijn om ontzettend leuk gezelschap te bieden. Gewoon lekker vogel mogen zijn, dat past perfect bij Fiffie 🌿
Voor Fiffie zoeken we een rustig en liefdevol thuis waar voldoende ruimte is om te klimmen, spelen en op onderzoek uit te gaan. Een ruime kooi of volière en een veilige omgeving zijn belangrijk zodat Fiffie zich helemaal op het gemak kan voelen ✨
Ben jij op zoek naar een leuke, nieuwsgierige valkparkiet met een eigen karaktertje? Dan is Fiffie misschien wel precies het maatje dat jij zoekt! 🐦💛
Stuur ons dan:
✨ Waarom je interesse hebt in Fiffie
📸 Foto’s van het verblijf waar Fiffie komt te wonen
Hopelijk tot snel! 🐦✨', 'wildlife', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_330x285_crop_center-center_none/fiffie.jpg?stamp=2605071104&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_384x330_crop_center-center_none/fiffie.jpg?stamp=2605071104&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_519x453_crop_center-center_none/fiffie.jpg?stamp=2605071104&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/fiffie.jpg?stamp=2605071104&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/fiffie-1.jpg?stamp=2605071104&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_384x330_crop_center-center_none/fiffie.jpg?stamp=2605071104&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_519x453_crop_center-center_none/fiffie.jpg?stamp=2605071104&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/fiffie.jpg?stamp=2605071104&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/fiffie-1.jpg?stamp=2605071104&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301131&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/vogels/4603211-fiffie'
from public.shelters s
where s.name = 'Dierenopvangcentrum Rotterdam'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/vogels/4603211-fiffie')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Rotterdam', 'Nacho & Witje', 'Maak kennis met Nacho & Witje, twee gezellige agapornissen met ieder hun eigen charme! 🐦💛🐦
Deze twee zijn altijd samen te vinden en vormen echt een hecht duo. Of ze nu samen zitten te kletsen, elkaar verzorgen of druk bezig zijn met spelen en ontdekken — ze doen alles zij aan zij. Daarom worden Nacho & Witje alleen samen geplaatst 💕
Het geslacht van Nacho & Witje is onbekend en ze zijn niet tam. Ze vinden mensen nog spannend en zijn geen vogels die graag vastgehouden worden. Wel zijn het ontzettend leuke vogeltjes om naar te kijken. Hun vrolijke gekwetter, nieuwsgierigheid en onderlinge interactie zorgen voor leven en gezelligheid in huis 🥰
Voor Nacho & Witje zoeken we een rustig en liefdevol plekje waar ze gewoon lekker vogel mogen zijn. Een ruime kooi of volière met genoeg mogelijkheden om te klimmen, spelen en ontdekken is belangrijk voor dit duo. Ervaring met vogels is fijn, maar vooral geduld en begrip voor hun karakter zijn heel belangrijk 💛
Ben jij op zoek naar twee schattige, levendige agapornissen die samen jouw huis opfleuren? Dan zijn Nacho & Witje misschien wel precies wat je zoekt! 🐦✨
Stuur ons dan:
✨ Waarom je interesse hebt in Nacho & Witje
📸 Foto’s van het verblijf waar ze komen te wonen
Hopelijk tot snel! 🐦💛🐦', 'wildlife', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_330x285_crop_center-center_none/with-en-nacho.jpg?stamp=2605071100&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_384x330_crop_center-center_none/with-en-nacho.jpg?stamp=2605071100&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_519x453_crop_center-center_none/with-en-nacho.jpg?stamp=2605071100&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/with-en-nacho.jpg?stamp=2605071100&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/n-en-w.jpg?stamp=2605071100&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_384x330_crop_center-center_none/with-en-nacho.jpg?stamp=2605071100&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_519x453_crop_center-center_none/with-en-nacho.jpg?stamp=2605071100&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/with-en-nacho.jpg?stamp=2605071100&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/_800x550_crop_center-center_none/n-en-w.jpg?stamp=2605071100&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenopvangcentrumRotterdam/Algemeen/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.png?stamp=2306301131&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/vogels/4603193-nacho-witje'
from public.shelters s
where s.name = 'Dierenopvangcentrum Rotterdam'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/vogels/4603193-nacho-witje')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Bronsvleugelmagrietje', 'Deze prachtige bronsvleugelmargrietje is geboren in 2024. Voor deze schoonheid zoeken wij een buitenvoliere waar hij ruimte heeft om zichzelf te kunnen zijn. Het liefst natuurlijk met soortgenootjes. Hij vindt mensen behoorlijk spannend.
Deze vogel is getest op alle ziektes en is negatief, volgens DNA onderzoek is het een man. Hij krijgt CITES papieren mee.
