insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Edelpapegaai Edel', 'Maak kennis met onze Edel, een prachtige man van geboorte jaar 2025. Hij is een vrij rustige vogel die een huisje zoekt waar hij binnen kan vertoeven en alle aandacht krijgt. Gaat graag in bad en vliegt graag rond. Edel komt graag op je schouder zitten en vind aandacht helemaal leuk.
Hij is getest op ziektes en negatief bevonden. Krijgt ook cites-papieren mee.
Adoptieprijs: 500 euro', 'wildlife', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Edelpapegaai.png?stamp=2605070937&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Edelpapegaai.png?stamp=2605070937&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Edelpapegaai.png?stamp=2605070937&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Edelpapegaai.png?stamp=2605070937&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Edelpapegaai2.png?stamp=2605070937&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Edelpapegaai.png?stamp=2605070937&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Edelpapegaai.png?stamp=2605070937&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Edelpapegaai.png?stamp=2605070937&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Edelpapegaai2.png?stamp=2605070937&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/vogels/4603042-edelpapegaai-edel'
