insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Halsbandparkiet Pino', 'Pino is een ontzettende leuke vrolijke Halsbandparkiet die gevonden is. Hij was erg kaalgeplukt, de dierenarts vermoed dat dit door de stress komt of ongezonde voeding.
Pino is vrij tam, al durft hij ook wel te bijten. Hij is duidelijk gewend om in huis te wonen en maakt allerlei vrolijke geluiden. Zo praat hij en zegt die regelmatig het woord ''Pino'', dus vermoeden wij dat die Pino heet. Ook doet hij ''kiekeboe'' met je.
We zoeken iemand met voldoende tijd, ervaring en een ruimte kooi voor Pino waar die ook regelmatig los mag vliegen.
Adoptiekosten 40 euro.', 'wildlife', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_330x285_crop_center-center_none/Pino_2026-05-06-091519_neei.png?stamp=2605061115&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Pino_2026-05-06-091519_neei.png?stamp=2605061115&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Pino_2026-05-06-091519_neei.png?stamp=2605061115&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Pino_2026-05-06-091519_neei.png?stamp=2605061115&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_384x330_crop_center-center_none/Pino_2026-05-06-091519_neei.png?stamp=2605061115&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_519x453_crop_center-center_none/Pino_2026-05-06-091519_neei.png?stamp=2605061115&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/_800x550_crop_center-center_none/Pino_2026-05-06-091519_neei.png?stamp=2605061115&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumLimburg/Algemeen/_882x1004_crop_center-center_none/DB-kat-zwart-885x1005.png?stamp=2306301351&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/vogels/4601246-halsbandparkiet-pino'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Limburg'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/vogels/4601246-halsbandparkiet-pino')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Born', 'Japanse kwartels', 'Knappe Japanse kwartel mannetjes zoeken thuis. We hebben er momenteel 2 in de opvang.
Ze scharrelen op de grond en ruimen de gemorste zaadjes op van de vogels in de volière.
