insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Klarenbeek', 'Zijdehoen haan Leizu', 'Maak kennis met onze Zijdehoen haan Leizu!
Leizu is een grijze Zijdehoen haan met een zachte uitstraling. Met zijn pluizige verenkleed en rustige voorkomen is hij een echte blikvanger in het hok.
Hij zoekt een fijne plek waar hij mag rond scharrelen met wat hennetjes om zich heen. Bent u degene die deze haan een warm en veilig plekje kan bieden? Hij zal u belonen met zijn charme!
Heeft u interesse? Stuur ons dan een mailtje met:• Uw ervaring met hanen of kippen• Een paar foto’s van het verblijf waar deze trotse kerel mag wonen
We kijken uit naar uw reactie en hopen samen het perfecte plekje voor onze hanen te vinden!', 'wildlife', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/deKuipershoek/_330x285_crop_center-center_none/1192906-Zijdehoen-Leizu_2026-04-29-143706_uvsl.jpeg?stamp=2604291637&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1192906-Zijdehoen-Leizu_2026-04-29-143706_uvsl.jpeg?stamp=2604291637&tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1192906-Zijdehoen-Leizu_2026-04-29-143706_uvsl.jpeg?stamp=2604291637&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192906-Zijdehoen-Leizu_2026-04-29-143706_uvsl.jpeg?stamp=2604291637&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192906-Zijdehoen-Leizu.jpeg?stamp=2604241457&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192906-Zijdehoen-Leizu-2.jpeg?stamp=2604241457&tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_384x330_crop_center-center_none/1192906-Zijdehoen-Leizu_2026-04-29-143706_uvsl.jpeg?stamp=2604291637&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_519x453_crop_center-center_none/1192906-Zijdehoen-Leizu_2026-04-29-143706_uvsl.jpeg?stamp=2604291637&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192906-Zijdehoen-Leizu_2026-04-29-143706_uvsl.jpeg?stamp=2604291637&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192906-Zijdehoen-Leizu.jpeg?stamp=2604241457&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_800x550_crop_center-center_none/1192906-Zijdehoen-Leizu-2.jpeg?stamp=2604241457&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/deKuipershoek/_882x1004_crop_center-center_none/DB-KITTEN-885x1005-03.