insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Pablo', 'Maak kennis met Pablo! Pablo is geen onbekende van ons. Helaas is hij na plaatsing terug gekomen vanwege allergie. 
Pablo is samen met Joya bij ons in de gekomen, helaas kan Pablo iets te vel doen waardoor het niet meer klikte tussen de fretjes. Om deze reden hebben wij besloten om voor Pablo een huisje alleen te zoeken waar geen andere fretten aanwezig zijn. Pablo in de opvang gekomen via uitwisseling met een andere opvang waar zij als vondeling zijn binnengekomen. We weten daarom helaas niks over zijn verleden. Hun geboortedatum is dan ook een schatting. 

Pablo is nieuwsgierig en een kleine drukte maker. Hij versleept graag zijn speeltjes dagelijks naar zijn vaste verstopplek, namelijk onder de kooi. Pablo komt ook graag bij je op schoot klimmen om te kijken wat je aan het doen bent. Lekker in de weg lopen tijdens de schoonmaak doet hij ook graag in de hoop dat je hem zachtjes aan de kant schuift. Dit is voor hem de perfecte mogelijkheid om je uit te dagen tot spel. Lekker buitenspelen in de ballenbak vindt hij ook erg leuk.
Pablo is meerdere keren door onze dierenarts nagekeken en daaruit is gebleken dat hij vermoedelijk een implantaat heeft waardoor hij momenteel niet vruchtbaar is. Helaas is dit bij fretten niet te controleren. Om deze reden adviseren we zijn toekomstige eigenaar om dit goed in de gaten te houden, dit om te voorkomen dat hij weer vruchtbaar en hormonaal zal worden. Dan is een definitieve castratie noodzakelijk.
Pablo kan soms zijn tandjes gebruiken uit nieuwsgierigheid zoals meeste fretten doen.


Verliefd geworden op dit leuke stel? Vul dan snel een aanvraagformulier in onder aan het verhaaltje. We nemen dan zo snel mogelijk contact op je op!', 'wildlife', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/Pablo-3_2026-05-07-073900_bdqd.jpg?stamp=2605070939&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Pablo-3_2026-05-07-073900_bdqd.jpg?stamp=2605070939&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Pablo-3_2026-05-07-073900_bdqd.jpg?stamp=2605070939&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Pablo-3_2026-05-07-073900_bdqd.jpg?stamp=2605070939&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Pablo-2_2026-05-07-073858_balb.jpg?stamp=2605070938&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Pablo-1_2026-05-07-073856_kfno.jpg?stamp=2605070938&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/Pablo-3_2026-05-07-073900_bdqd.jpg?stamp=2605070939&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/Pablo-3_2026-05-07-073900_bdqd.jpg?stamp=2605070939&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Pablo-3_2026-05-07-073900_bdqd.jpg?stamp=2605070939&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Pablo-2_2026-05-07-073858_balb.jpg?stamp=2605070938&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Pablo-1_2026-05-07-073856_kfno.jpg?stamp=2605070938&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/Algemeen/_882x1004_crop_center-center_none/DB-hond-ouder-885x1005.png?stamp=2306301437&tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/overige/4603038-pablo'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/overige/4603038-pablo')
limit 1;

insert into public.animals (shelter_id, city, name, description, species, status, published, image_urls, external_url)
select s.id, 'Amersfoort', 'Antonio en Joya', 'Maak kennis met Antonio en Joya! Deze lieve fretten hebben elkaar bij ons in de opvang leren kennen en waren gelijk de dikste maatjes! De fretjes zijn geen onbekende van ons. Helaas zijn ze na plaatsing terug gekomen vanwege allergie.

Antonio verblijft al langere tijd bij ons in de opvang en na lang wachten kwamen er andere fretjes binnen waar hij eindelijk vriendjes mee kon worden. Beide fretten zijn in de opvang gekomen via uitwisseling met een andere opvang waar zij als vondeling zijn binnengekomen. We weten daarom helaas niks over hun verleden. Hun geboortedatum is dan ook een schatting. 
Antonio (foto 1,3,5) is een nieuwsgierige jongen is die graag uit zijn slaapholletje komt kruipen om te kijken wat je komt doen in zijn kamertje. Het heeft eventjes geduurd voordat Antonio zijn speelse kant laat zien, maar nu weten we wel zeker dat hij deze heeft. Lekker gek doen in de ballenbak of onder een kleedje spelen vindt hij heel erg leuk. Maar niks is beter dan een langdurig dutje in de hangmat met zijn vriendinnetje. 

Joya (foto 2,4,6) is in het begin wat verlegen. Ze verstopt zich onder de kooi en achtervolgd je stiekem. Ze vindt nieuwe mensen vaak nog wat spannend, maar als je wat tijd voor haar neemt komt ze toch eventjes bij je kijken en klimt ze al snel bij je op schoot. Onder een kleedje ravotten vindt ze erg leuk! Zo kan ze makkelijk de Antonio uit dagen zonder dat hij zomaar bij haar kan. 
De fretjes kunnen soms hun tandjes gebruiken uit nieuwsgierigheid zoals meeste fretten doen. 
We zijn voor dit leuke stel op zoek naar een huisje waar zij samen terecht kunnen en ook de enige drie fretten in huis zijn. Aanvragen voor één van de fretten of een thuis waar al fretten aanwezig zijn worden dan ook niet in behandeling genomen! 
Verliefd geworden op dit leuke stel? Vul dan snel een aanvraagformulier in onder aan het verhaaltje. We nemen dan zo snel mogelijk contact op je op!', 'wildlife', 'available', true, ARRAY['https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_330x285_crop_center-center_none/4511129/Antonio-7.jpg?stamp=2601151500&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/4511129/Antonio-7.jpg?stamp=2601151500&tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/4511129/Antonio-7.jpg?stamp=2601151500&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4511129/Antonio-7.jpg?stamp=2601151500&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4563123/Joya-2.jpg?stamp=2603191540&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Antonio-4.jpg?stamp=2512191432&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4563124/Joya-3.jpg?stamp=2603191540&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Antonio-6.jpg?stamp=2512191432&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4563122/Joya-1.jpg?stamp=2603191540&tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_384x330_crop_center-center_none/4511129/Antonio-7.jpg?stamp=2601151500&amp;tag=sm', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_519x453_crop_center-center_none/4511129/Antonio-7.jpg?stamp=2601151500&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4511129/Antonio-7.jpg?stamp=2601151500&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4563123/Joya-2.jpg?stamp=2603191540&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/Antonio-4.jpg?stamp=2512191432&amp;tag=xs', 'https://cms.dierenbescherming.nl/assets/dierenbeschermingscentrumAmersfoort/_800x550_crop_center-center_none/4563124/Joya-3.jpg?stamp=2603191540&amp;tag=xs']::text[], 'https://ikzoekbaas.dierenbescherming.nl/asieldier/overige/4488211-antonio'
from public.shelters s
where s.name = 'Dierenbeschermingscentrum Amersfoort'
  and not exists (select 1 from public.animals a where a.external_url = 'https://ikzoekbaas.dierenbescherming.nl/asieldier/overige/4488211-antonio')
limit 1;
